{
  "name": "Chronos AI Editor",
  "description": "An ultramodern, AI-driven video editing interface where you act as the Director and the AI handles the technical execution. Features a futuristic UI, timeline visualization, and natural language command processing."
}

export interface TextOverlay {
  id: string;
  text: string;
  startTime: number; // percentage 0-100 or seconds
  duration: number;
  position: 'top' | 'center' | 'bottom';
}

export interface VideoState {
  isPlaying: boolean;
  currentTime: number; // in seconds
  duration: number; // in seconds
  filter: string; // css filter string or class name
  overlays: TextOverlay[];
  volume: number;
  zoom: number;
  rotation: number;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model' | 'system';
  content: string;
  isFunctionCall?: boolean;
}

export enum ToolNames {
  SET_FILTER = 'set_filter',
  ADD_OVERLAY = 'add_overlay',
  SET_PLAYBACK = 'set_playback',
  TRANSFORM_VIDEO = 'transform_video',
}

// Helper type for function args
export type ToolArgs = Record<string, any>;

import { VideoState } from './types';

export const INITIAL_VIDEO_STATE: VideoState = {
  isPlaying: false,
  currentTime: 0,
  duration: 60, // Mock duration of 60 seconds
  filter: 'none',
  overlays: [],
  volume: 0.8,
  zoom: 1,
  rotation: 0,
};

export const SAMPLE_VIDEO_URL = "https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/TearsOfSteel.mp4";

export const AVAILABLE_FILTERS = {
  none: '',
  cyberpunk: 'contrast(1.2) saturate(1.5) hue-rotate(180deg) drop-shadow(0 0 5px cyan)',
  noir: 'grayscale(100%) contrast(1.2) brightness(0.9)',
  retro: 'sepia(0.8) contrast(0.9) brightness(1.1)',
  matrix: 'hue-rotate(90deg) contrast(1.5) brightness(0.9) saturate(0.5)',
  dream: 'blur(1px) brightness(1.2) saturate(0.8)',
};

export const INITIAL_CHAT_MESSAGE = "Systems Online. I am Chronos, your AI production assistant. How would you like to direct this scene?";

import { GoogleGenAI, FunctionDeclaration, Type, Tool } from "@google/genai";
import { ToolNames } from "../types";

// 1. Define Tool Schemas
const setFilterTool: FunctionDeclaration = {
  name: ToolNames.SET_FILTER,
  description: "Apply a visual filter to the video (e.g., cyberpunk, noir, retro, matrix, dream, or none).",
  parameters: {
    type: Type.OBJECT,
    properties: {
      filterName: {
        type: Type.STRING,
        description: "The name of the filter to apply. Options: cyberpunk, noir, retro, matrix, dream, none.",
      },
    },
    required: ["filterName"],
  },
};

const addOverlayTool: FunctionDeclaration = {
  name: ToolNames.ADD_OVERLAY,
  description: "Add a text overlay to the video at a specific time.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      text: { type: Type.STRING, description: "The content of the text overlay." },
      position: { 
        type: Type.STRING, 
        description: "Position on screen: 'top', 'center', 'bottom'." 
      },
      startTime: {
        type: Type.NUMBER,
        description: "Start time in seconds (0-60).",
      }
    },
    required: ["text", "position"],
  },
};

const setPlaybackTool: FunctionDeclaration = {
  name: ToolNames.SET_PLAYBACK,
  description: "Control video playback state (play, pause, seek).",
  parameters: {
    type: Type.OBJECT,
    properties: {
      action: { type: Type.STRING, description: "'play', 'pause', or 'seek'." },
      time: { type: Type.NUMBER, description: "Time to seek to in seconds (optional)." },
    },
    required: ["action"],
  },
};

const transformVideoTool: FunctionDeclaration = {
  name: ToolNames.TRANSFORM_VIDEO,
  description: "Apply geometric transformations like zoom or rotation.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      zoom: { type: Type.NUMBER, description: "Zoom level (1.0 to 3.0)." },
      rotation: { type: Type.NUMBER, description: "Rotation in degrees." },
    },
  },
};

const tools: Tool[] = [{
  functionDeclarations: [setFilterTool, addOverlayTool, setPlaybackTool, transformVideoTool],
}];

const SYSTEM_INSTRUCTION = `
You are Chronos, a highly advanced AI video editor interface from the year 2077.
Your goal is to assist the "Director" (user) in editing their video footage.
You have direct control over the editing software via tools.
Adopt a concise, efficient, slightly robotic but helpful persona.
When a user asks to change the look, use the 'set_filter' tool.
When a user wants to add text/titles, use 'add_overlay'.
When a user wants to play/pause/jump time, use 'set_playback'.
When a user mentions zooming in or rotating, use 'transform_video'.
Always confirm your actions briefly.
`;

export const createGeminiSession = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("API_KEY not found in environment variables");
    return null;
  }

  const ai = new GoogleGenAI({ apiKey });

  return ai.chats.create({
    model: 'gemini-2.5-flash',
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      tools: tools,
    }
  });
};

import React, { useRef, useEffect } from 'react';
import { VideoState, TextOverlay } from '../types';
import { SAMPLE_VIDEO_URL, AVAILABLE_FILTERS } from '../constants';
import { Play, Pause, Maximize, RotateCcw } from 'lucide-react';

interface VideoPlayerProps {
  state: VideoState;
  onTimeUpdate: (time: number) => void;
  onDurationChange: (duration: number) => void;
  onTogglePlay: () => void;
}

const VideoPlayer: React.FC<VideoPlayerProps> = ({ state, onTimeUpdate, onDurationChange, onTogglePlay }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  // Sync state.isPlaying with video element
  useEffect(() => {
    if (videoRef.current) {
      if (state.isPlaying && videoRef.current.paused) {
        videoRef.current.play().catch(e => console.log("Autoplay prevented", e));
      } else if (!state.isPlaying && !videoRef.current.paused) {
        videoRef.current.pause();
      }
    }
  }, [state.isPlaying]);

  // Sync volume
  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.volume = state.volume;
    }
  }, [state.volume]);

  // Handle Seek (if large jump)
  useEffect(() => {
    if (videoRef.current && Math.abs(videoRef.current.currentTime - state.currentTime) > 1) {
      videoRef.current.currentTime = state.currentTime;
    }
  }, [state.currentTime]);

  const activeFilterStyle = AVAILABLE_FILTERS[state.filter as keyof typeof AVAILABLE_FILTERS] || '';

  return (
    <div className="relative w-full h-full bg-black rounded-lg overflow-hidden border border-slate-700 shadow-[0_0_30px_rgba(0,0,0,0.5)] group">

      {/* Video Element */}
      <video
        ref={videoRef}
        className="w-full h-full object-cover transition-all duration-500 ease-out"
        src={SAMPLE_VIDEO_URL}
        loop
        playsInline
        muted={false}
        onTimeUpdate={(e) => onTimeUpdate(e.currentTarget.currentTime)}
        onLoadedMetadata={(e) => onDurationChange(e.currentTarget.duration)}
        style={{
          filter: activeFilterStyle,
          transform: `scale(${state.zoom}) rotate(${state.rotation}deg)`,
        }}
      />

      {/* Overlays */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        {state.overlays.map((overlay) => {
          // Simple visibility check based on mocked duration logic or just always show for demo if within range
          // For this demo, let's just show them if current time is within a 5s window of start time
          const isVisible = state.currentTime >= overlay.startTime && state.currentTime <= overlay.startTime + overlay.duration;

          if (!isVisible) return null;

          let posClass = 'top-10 left-0 right-0 text-center';
          if (overlay.position === 'center') posClass = 'top-1/2 left-0 right-0 -translate-y-1/2 text-center';
          if (overlay.position === 'bottom') posClass = 'bottom-10 left-0 right-0 text-center';

          return (
            <div key={overlay.id} className={`absolute ${posClass} transition-opacity duration-300 animate-in fade-in zoom-in`}>
              <h2 className="text-4xl md:text-6xl font-display font-bold text-white uppercase tracking-widest drop-shadow-[0_0_10px_rgba(0,0,0,0.8)]">
                <span className="bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
                  {overlay.text}
                </span>
              </h2>
            </div>
          );
        })}
      </div>

      {/* Holographic Grid Overlay (Visual candy) */}
      <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(18,18,18,0)_1px,transparent_1px),linear-gradient(90deg,rgba(18,18,18,0)_1px,transparent_1px)] bg-[size:40px_40px] [mask-image:radial-gradient(ellipse_60%_60%_at_50%_50%,#000_70%,transparent_100%)] opacity-20"></div>

      {/* Minimal Playback Controls Overlay on Hover */}
      <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300 bg-black/20 pointer-events-none">
        <div className="pointer-events-auto p-4 rounded-full bg-black/50 backdrop-blur-md border border-white/10 hover:scale-110 transition-transform cursor-pointer" onClick={onTogglePlay}>
          {state.isPlaying ? <Pause className="w-8 h-8 text-white" /> : <Play className="w-8 h-8 text-white ml-1" />}
        </div>
      </div>

      {/* HUD Info */}
      <div className="absolute top-4 left-4 font-mono text-xs text-cyan-500/80 pointer-events-none">
        <div className="flex flex-col gap-1">
          <span>MODE: DIRECTOR</span>
          <span>FILTER: {state.filter.toUpperCase()}</span>
          <span>ZOOM: {state.zoom.toFixed(2)}x</span>
        </div>
      </div>

    </div>
  );
};

export default VideoPlayer;

import React from 'react';
import { VideoState } from '../types';

interface TimelineProps {
  state: VideoState;
  onSeek: (time: number) => void;
}

const Timeline: React.FC<TimelineProps> = ({ state, onSeek }) => {
  const percentage = (state.currentTime / state.duration) * 100;

  const handleTimelineClick = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const clickPercentage = x / rect.width;
    const newTime = clickPercentage * state.duration;
    onSeek(newTime);
  };

  return (
    <div className="w-full h-full flex flex-col gap-1 p-2 bg-slate-900/50 backdrop-blur-lg border-t border-slate-700 select-none">

      {/* Time Markers */}
      <div className="flex justify-between text-[10px] font-mono text-slate-500 px-1">
        <span>00:00</span>
        <span>{new Date(state.duration * 1000).toISOString().substr(14, 5)}</span>
      </div>

      {/* Track Area */}
      <div 
        className="relative w-full h-24 bg-slate-950/80 rounded-md overflow-hidden cursor-pointer border border-slate-800 group"
        onClick={handleTimelineClick}
      >
        {/* Background Grid */}
        <div className="absolute inset-0 opacity-10 pointer-events-none" 
             style={{ backgroundImage: 'linear-gradient(90deg, #334155 1px, transparent 1px)', backgroundSize: '20px 100%' }}>
        </div>

        {/* Video Track */}
        <div className="absolute top-2 left-0 right-0 h-10 bg-cyan-900/20 mx-1 rounded border border-cyan-500/30 overflow-hidden">
             {/* Waveform simulation */}
             <div className="w-full h-full flex items-center opacity-30 gap-[2px]">
                {Array.from({ length: 100 }).map((_, i) => (
                    <div key={i} className="flex-1 bg-cyan-400" style={{ height: `${Math.random() * 80 + 20}%` }}></div>
                ))}
             </div>
        </div>

        {/* Overlay Tracks */}
        {state.overlays.map((overlay, idx) => {
            const left = (overlay.startTime / state.duration) * 100;
            const width = (overlay.duration / state.duration) * 100;
            return (
                <div 
                    key={overlay.id}
                    className="absolute top-14 h-6 bg-purple-500/40 border border-purple-400/50 rounded flex items-center justify-center text-[9px] text-purple-200 overflow-hidden px-1 whitespace-nowrap"
                    style={{ left: `${left}%`, width: `${width}%` }}
                >
                    {overlay.text}
                </div>
            )
        })}

        {/* Playhead */}
        <div 
            className="absolute top-0 bottom-0 w-[2px] bg-red-500 z-10 transition-all duration-75 shadow-[0_0_10px_rgba(239,68,68,0.6)]"
            style={{ left: `${percentage}%` }}
        >
            <div className="absolute -top-1 -left-[4px] w-0 h-0 border-l-[5px] border-l-transparent border-r-[5px] border-r-transparent border-t-[6px] border-t-red-500"></div>
        </div>

      </div>

      {/* Controls Container (could be more extensive) */}
      <div className="flex items-center gap-4 mt-1 font-mono text-xs text-slate-400">
        <div className="px-2 py-1 bg-slate-800 rounded">
            TC: <span className="text-white">{new Date(state.currentTime * 1000).toISOString().substr(11, 8)}</span>
        </div>
      </div>
    </div>
  );
};

export default Timeline;

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { Send, Bot, User, Mic, Sparkles } from 'lucide-react';

interface AIChatProps {
  messages: ChatMessage[];
  onSendMessage: (message: string) => void;
  isProcessing: boolean;
}

const AIChat: React.FC<AIChatProps> = ({ messages, onSendMessage, isProcessing }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !isProcessing) {
      onSendMessage(input);
      setInput('');
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-900/90 backdrop-blur-xl border-l border-slate-700 shadow-2xl">
      {/* Header */}
      <div className="p-4 border-b border-slate-700 bg-slate-950/50 flex items-center gap-3">
        <div className="p-2 bg-cyan-500/10 rounded-lg border border-cyan-500/20 relative">
             <Bot className="w-5 h-5 text-cyan-400" />
             <div className="absolute -top-1 -right-1 w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
        </div>
        <div>
            <h3 className="font-display font-bold text-slate-100 tracking-wider">CHRONOS</h3>
            <p className="text-[10px] font-mono text-cyan-600/80">AI DIRECTOR ASSISTANT</p>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] p-3 rounded-2xl text-sm ${
                msg.role === 'user'
                  ? 'bg-cyan-600/20 text-cyan-100 border border-cyan-500/30 rounded-tr-sm'
                  : 'bg-slate-800 text-slate-300 border border-slate-700 rounded-tl-sm shadow-md'
              }`}
            >
                {msg.isFunctionCall ? (
                    <div className="flex items-center gap-2 text-xs font-mono text-purple-400">
                        <Sparkles className="w-3 h-3" />
                        <span>Executing command...</span>
                    </div>
                ) : (
                    msg.content
                )}
            </div>
          </div>
        ))}
        {isProcessing && (
          <div className="flex justify-start">
            <div className="bg-slate-800 p-3 rounded-2xl rounded-tl-sm border border-slate-700">
              <div className="flex gap-1">
                <span className="w-2 h-2 bg-cyan-500 rounded-full animate-bounce"></span>
                <span className="w-2 h-2 bg-cyan-500 rounded-full animate-bounce delay-75"></span>
                <span className="w-2 h-2 bg-cyan-500 rounded-full animate-bounce delay-150"></span>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Input */}
      <form onSubmit={handleSubmit} className="p-4 bg-slate-950/50 border-t border-slate-700">
        <div className="relative flex items-center gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Command the AI..."
            className="w-full bg-slate-900 border border-slate-700 text-slate-200 rounded-full px-4 py-3 pr-12 text-sm focus:outline-none focus:border-cyan-500/50 focus:ring-1 focus:ring-cyan-500/20 placeholder-slate-600 transition-all font-mono"
            disabled={isProcessing}
          />
          <button
            type="submit"
            disabled={!input.trim() || isProcessing}
            className="absolute right-1 p-2 bg-cyan-600 hover:bg-cyan-500 text-white rounded-full transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <Send className="w-4 h-4" />
          </button>
        </div>
        <div className="flex justify-center mt-2 gap-4">
            <button type="button" className="text-[10px] text-slate-500 hover:text-cyan-400 transition-colors font-mono">"Make it cyberpunk"</button>
            <button type="button" className="text-[10px] text-slate-500 hover:text-cyan-400 transition-colors font-mono">"Add title 'INTRO' at 5s"</button>
        </div>
      </form>
    </div>
  );
};

export default AIChat;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useRef } from 'react';
import { INITIAL_VIDEO_STATE, INITIAL_CHAT_MESSAGE } from './constants';
import { VideoState, ChatMessage, ToolNames, ToolArgs } from './types';
import VideoPlayer from './components/VideoPlayer';
import Timeline from './components/Timeline';
import AIChat from './components/AIChat';
import { createGeminiSession } from './services/geminiService';
import { Activity, Radio, Layers, Scissors, Settings, Menu } from 'lucide-react';
import { Chat } from '@google/genai';

const App: React.FC = () => {
  const [videoState, setVideoState] = useState<VideoState>(INITIAL_VIDEO_STATE);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'init', role: 'model', content: INITIAL_CHAT_MESSAGE }
  ]);
  const [isProcessing, setIsProcessing] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);

  // Initialize Chat Session
  useEffect(() => {
    chatSessionRef.current = createGeminiSession();
  }, []);

  const handleSendMessage = async (userMessage: string) => {
    if (!chatSessionRef.current) return;

    setIsProcessing(true);
    // Add user message to UI
    const userMsgId = Date.now().toString();
    setMessages(prev => [...prev, { id: userMsgId, role: 'user', content: userMessage }]);

    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMessage });

      const functionCalls = result.functionCalls;

      // If the model wants to call a function (tool)
      if (functionCalls && functionCalls.length > 0) {
        // Let user know actions are happening
        setMessages(prev => [...prev, { id: Date.now().toString() + '-fc', role: 'model', content: 'Processing...', isFunctionCall: true }]);

        const responses: any[] = [];

        for (const call of functionCalls) {
            const toolName = call.name;
            const args = call.args as ToolArgs;
            let responseResult = { result: "Success" };

            // Execute local state updates based on tool
            switch (toolName) {
                case ToolNames.SET_FILTER:
                    setVideoState(prev => ({ ...prev, filter: args.filterName }));
                    responseResult = { result: `Filter set to ${args.filterName}` };
                    break;

                case ToolNames.ADD_OVERLAY:
                    const newOverlay = {
                        id: Math.random().toString(36).substr(2, 9),
                        text: args.text,
                        position: args.position,
                        startTime: args.startTime || videoState.currentTime,
                        duration: 5 // default duration
                    };
                    setVideoState(prev => ({ ...prev, overlays: [...prev.overlays, newOverlay] }));
                    responseResult = { result: `Added overlay '${args.text}' at ${args.startTime}s` };
                    break;

                case ToolNames.SET_PLAYBACK:
                    if (args.action === 'play') setVideoState(prev => ({ ...prev, isPlaying: true }));
                    if (args.action === 'pause') setVideoState(prev => ({ ...prev, isPlaying: false }));
                    if (args.action === 'seek' && typeof args.time === 'number') setVideoState(prev => ({ ...prev, currentTime: args.time }));
                    responseResult = { result: `Playback set to ${args.action}` };
                    break;

                case ToolNames.TRANSFORM_VIDEO:
                     if(args.zoom) setVideoState(prev => ({...prev, zoom: args.zoom}));
                     if(args.rotation) setVideoState(prev => ({...prev, rotation: args.rotation}));
                     responseResult = { result: `Video transformed` };
                     break;
            }

            responses.push({
                name: toolName,
                response: responseResult,
                id: call.id
            });
        }

        // Send tool execution results back to Gemini
        const finalResponse = await chatSessionRef.current.sendToolResponse({
            functionResponses: responses
        });

        // Add Gemini's final verbal response after executing tools
        if (finalResponse.text) {
             setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: finalResponse.text }]);
        }

      } else if (result.text) {
        // Normal conversational response
        setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: result.text }]);
      }

    } catch (error) {
      console.error("Chat Error:", error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: "I encountered a system error processing that directive." }]);
    } finally {
      setIsProcessing(false);
    }
  };

  // UI Handlers
  const handleTogglePlay = () => setVideoState(prev => ({ ...prev, isPlaying: !prev.isPlaying }));
  const handleSeek = (time: number) => setVideoState(prev => ({ ...prev, currentTime: time }));
  const handleTimeUpdate = (time: number) => setVideoState(prev => ({ ...prev, currentTime: time }));
  const handleDurationChange = (duration: number) => setVideoState(prev => ({ ...prev, duration: duration }));

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-slate-950 text-slate-200 selection:bg-cyan-500/30">

      {/* Left Toolbar (Futuristic Vertical Nav) */}
      <div className="w-16 border-r border-slate-800 flex flex-col items-center py-6 gap-8 bg-slate-900/50 z-20">
        <div className="p-2 bg-cyan-500 rounded-lg shadow-[0_0_15px_rgba(6,182,212,0.6)]">
            <Activity className="text-white w-6 h-6" />
        </div>
        <div className="flex flex-col gap-6 w-full items-center">
            <button className="p-3 rounded-xl hover:bg-slate-800 text-slate-400 hover:text-cyan-400 transition-all group relative">
                <Scissors className="w-5 h-5" />
                <span className="absolute left-14 bg-slate-800 text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap border border-slate-700">Trim Tool</span>
            </button>
            <button className="p-3 rounded-xl hover:bg-slate-800 text-slate-400 hover:text-cyan-400 transition-all group relative">
                <Layers className="w-5 h-5" />
                <span className="absolute left-14 bg-slate-800 text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap border border-slate-700">Layers</span>
            </button>
            <button className="p-3 rounded-xl hover:bg-slate-800 text-slate-400 hover:text-cyan-400 transition-all group relative">
                <Radio className="w-5 h-5" />
                <span className="absolute left-14 bg-slate-800 text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap border border-slate-700">Effects</span>
            </button>
        </div>
        <div className="mt-auto">
            <button className="p-3 rounded-xl hover:bg-slate-800 text-slate-400 transition-all">
                <Settings className="w-5 h-5" />
            </button>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0 relative">

        {/* Top Header / Status Bar */}
        <div className="h-14 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-900/30">
