    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      tools: tools,
    }
  });
};

import React, { useRef, useEffect } from 'react';
import { VideoState, Sentiment } from '../types';
import { SAMPLE_VIDEO_URL } from '../constants';
import { Play, Pause, AlertTriangle, Sparkles, Quote } from 'lucide-react';

interface VideoPlayerProps {
  state: VideoState;
  onTimeUpdate: (time: number) => void;
  onDurationChange: (duration: number) => void;
  onTogglePlay: () => void;
}

const getSentimentStyles = (sentiment: Sentiment) => {
  switch (sentiment) {
    case 'anger':
      return 'font-display font-bold text-red-500 tracking-tighter uppercase animate-pulse drop-shadow-[0_0_10px_rgba(239,68,68,0.8)]';
    case 'urgency':
      return 'font-mono font-bold text-amber-500 italic tracking-widest bg-black/50 px-4 py-2 border-l-4 border-amber-500';
    case 'proverb':
      return 'font-serif italic text-yellow-200 text-2xl drop-shadow-[0_2px_4px_rgba(0,0,0,0.8)] border-b border-yellow-500/50 pb-2';
    case 'sarcasm':
      return 'font-mono text-pink-400 -skew-x-12 decoration-wavy underline decoration-pink-500/50';
    case 'joy':
      return 'font-display text-cyan-300 drop-shadow-[0_0_15px_rgba(34,211,238,0.6)] scale-110';
    default:
      return 'font-sans font-medium text-white drop-shadow-md bg-black/40 px-3 py-1 rounded';
  }
};

const getSentimentIcon = (sentiment: Sentiment) => {
    switch (sentiment) {
        case 'proverb': return <Quote className="w-4 h-4 text-yellow-500 inline mr-2 mb-2" />;
        case 'urgency': return <AlertTriangle className="w-4 h-4 text-amber-500 inline mr-2" />;
        case 'joy': return <Sparkles className="w-4 h-4 text-cyan-500 inline mr-2" />;
        default: return null;
    }
}

const VideoPlayer: React.FC<VideoPlayerProps> = ({ state, onTimeUpdate, onDurationChange, onTogglePlay }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if (videoRef.current) {
      if (state.isPlaying && videoRef.current.paused) {
        videoRef.current.play().catch(e => console.log("Autoplay prevented", e));
      } else if (!state.isPlaying && !videoRef.current.paused) {
        videoRef.current.pause();
      }
    }
  }, [state.isPlaying]);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.volume = state.volume;
    }
  }, [state.volume]);

  useEffect(() => {
    if (videoRef.current && Math.abs(videoRef.current.currentTime - state.currentTime) > 1) {
      videoRef.current.currentTime = state.currentTime;
    }
  }, [state.currentTime]);

  // Find active subtitle
  const activeLayer = state.languageLayers.find(l => l.id === state.activeLanguageId);
  const activeBlock = activeLayer?.blocks.find(b => {
    const meaning = state.meaningTrack.find(m => m.id === b.parentId);
    return meaning && state.currentTime >= meaning.startTime && state.currentTime <= meaning.startTime + meaning.duration;
  });

  const activeMeaning = activeBlock ? state.meaningTrack.find(m => m.id === activeBlock.parentId) : null;

  return (
    <div className="relative w-full h-full bg-slate-950 rounded-lg overflow-hidden border border-slate-800 shadow-[0_0_50px_rgba(0,0,0,0.7)] group">

      {/* Video */}
      <video
        ref={videoRef}
        className={`w-full h-full object-cover transition-all duration-300 ${state.crowdMode ? 'brightness-110 contrast-125 saturate-150' : ''}`}
        src={SAMPLE_VIDEO_URL}
        loop
        playsInline
        onTimeUpdate={(e) => onTimeUpdate(e.currentTarget.currentTime)}
        onLoadedMetadata={(e) => onDurationChange(e.currentTarget.duration)}
      />

      {/* Dynamic Subtitle Layer */}
      <div className="absolute inset-0 pointer-events-none flex flex-col justify-end items-center pb-16 px-12 text-center">
        {activeBlock && activeMeaning && (
            <div className={`transition-all duration-300 animate-in slide-in-from-bottom-5 fade-in ${getSentimentStyles(activeMeaning.sentiment)}`}>
                {getSentimentIcon(activeMeaning.sentiment)}
                {activeBlock.text}

                {/* Cultural Note Tooltip (Simulated) */}
                {activeMeaning.culturalNote && (
                    <div className="absolute -top-12 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-opacity bg-slate-900/90 text-slate-300 text-[10px] p-2 rounded border border-yellow-500/30 w-64 font-sans font-normal tracking-normal pointer-events-auto cursor-help backdrop-blur-md">
                        <span className="text-yellow-500 font-bold block mb-1">CULTURAL CONTEXT</span>
                        {activeMeaning.culturalNote}
                    </div>
                )}
            </div>
        )}
      </div>

      {/* Scanner/HUD Effects for Crowd Mode */}
      {state.crowdMode && (
         <div className="absolute inset-0 pointer-events-none bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 mix-blend-overlay"></div>
      )}

      {/* Playback Controls Overlay */}
      <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300 bg-black/20 pointer-events-none">
        <div className="pointer-events-auto p-4 rounded-full bg-slate-900/80 backdrop-blur-md border border-cyan-500/30 hover:scale-110 transition-transform cursor-pointer shadow-[0_0_20px_rgba(6,182,212,0.3)]" onClick={onTogglePlay}>
          {state.isPlaying ? <Pause className="w-8 h-8 text-cyan-400" /> : <Play className="w-8 h-8 text-cyan-400 ml-1" />}
        </div>
      </div>

      {/* HUD Info */}
      <div className="absolute top-4 left-4 font-mono text-[10px] text-cyan-900 bg-cyan-400/10 border border-cyan-500/20 px-2 py-1 rounded backdrop-blur pointer-events-none">
          <span className="text-cyan-400 mr-2">● REC</span>
          <span className="text-slate-400">LANG:</span> <span className="text-white">{activeLayer?.name.toUpperCase()}</span>
      </div>

    </div>
  );
};

export default VideoPlayer;

import React from 'react';
import { VideoState, MeaningBlock, LanguageLayer, Sentiment } from '../types';
import { AlertCircle, Star, Quote, Zap, MessageSquare } from 'lucide-react';

interface TimelineProps {
  state: VideoState;
  onSeek: (time: number) => void;
}

const SentimentColorMap: Record<Sentiment, string> = {
  neutral: 'bg-slate-600 border-slate-500',
  anger: 'bg-red-900/80 border-red-500',
  joy: 'bg-cyan-900/80 border-cyan-500',
  urgency: 'bg-amber-900/80 border-amber-500',
  proverb: 'bg-yellow-900/80 border-yellow-500',
  sarcasm: 'bg-pink-900/80 border-pink-500',
};

const Timeline: React.FC<TimelineProps> = ({ state, onSeek }) => {
  const percentage = (state.currentTime / state.duration) * 100;

  const handleTimelineClick = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const clickPercentage = x / rect.width;
    const newTime = clickPercentage * state.duration;
    onSeek(newTime);
  };

  return (
    <div className="w-full h-full flex flex-col bg-slate-950 border-t border-slate-800 select-none">

      {/* Time Markers */}
      <div className="h-6 flex items-center justify-between text-[10px] font-mono text-slate-500 px-4 border-b border-slate-800/50 bg-slate-900/30">
        <span>00:00</span>
        <span>{new Date(state.duration * 1000).toISOString().substr(14, 5)}</span>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar relative">
        <div className="relative min-h-[150px] p-2" onClick={handleTimelineClick}>

            {/* Playhead Line - Spans entire height */}
            <div 
                className="absolute top-0 bottom-0 w-[1px] bg-cyan-500 z-50 pointer-events-none shadow-[0_0_10px_rgba(6,182,212,0.8)]"
                style={{ left: `${percentage}%` }}
            >
                <div className="absolute -top-1 -left-[3px] w-0 h-0 border-l-[4px] border-l-transparent border-r-[4px] border-r-transparent border-t-[4px] border-t-cyan-500"></div>
            </div>

            {/* Meaning Track (The "Spine") */}
            <div className="mb-6 relative h-14 w-full bg-slate-900/50 rounded-lg border border-slate-800 overflow-hidden">
                <div className="absolute left-2 top-2 text-[10px] font-bold text-slate-500 uppercase tracking-wider z-10 bg-slate-900/80 px-1 rounded">Meaning Graph</div>
                {state.meaningTrack.map((block) => {
                     const left = (block.startTime / state.duration) * 100;
                     const width = (block.duration / state.duration) * 100;
                     return (
                         <div 
                            key={block.id}
                            className={`absolute top-2 bottom-2 rounded-md border ${SentimentColorMap[block.sentiment]} flex items-center justify-center cursor-pointer hover:brightness-125 transition-all group`}
                            style={{ left: `${left}%`, width: `${width}%` }}
                            title={block.meaning}
                         >
                            <span className="text-[10px] text-white/90 truncate px-1 font-medium">{block.meaning}</span>
                            {/* Hover info */}
                            <div className="absolute bottom-full mb-2 hidden group-hover:block bg-slate-900 text-xs p-2 rounded border border-slate-700 whitespace-nowrap z-20 shadow-xl">
                                <div className="font-bold text-white mb-1">{block.sentiment.toUpperCase()}</div>
                                <div className="text-slate-400 italic">"{block.originalText}"</div>
                            </div>
                         </div>
                     )
                })}
            </div>

            {/* Language Layers */}
            <div className="space-y-2">
                {state.languageLayers.filter(l => l.isVisible).map(layer => (
                    <div key={layer.id} className="relative h-8 w-full bg-slate-900/30 rounded border border-slate-800/50 hover:border-slate-700 transition-colors">
                         {/* Layer Label */}
                         <div className="absolute -left-0 top-0 bottom-0 w-1 rounded-l bg-slate-700"></div>
                         <div className="absolute left-2 top-1/2 -translate-y-1/2 text-[9px] font-mono text-slate-500 z-10 pointer-events-none opacity-50">{layer.code.toUpperCase()}</div>

                         {layer.blocks.map(block => {
                            const meaning = state.meaningTrack.find(m => m.id === block.parentId);
                            if(!meaning) return null;

                            const left = (meaning.startTime / state.duration) * 100;
                            const width = (meaning.duration / state.duration) * 100;

                            return (
                                <div 
                                    key={block.id}
                                    className={`absolute top-1 bottom-1 rounded-sm bg-slate-700/50 border border-slate-600/30 text-[8px] flex items-center px-1 text-slate-300 overflow-hidden ${block.isLiteral ? 'opacity-70' : ''}`}
                                    style={{ left: `${left}%`, width: `${width}%` }}
                                >
                                    <span className="truncate">{block.text}</span>
                                </div>
                            )
                         })}
                    </div>
                ))}
            </div>

        </div>
      </div>
    </div>
  );
};

export default Timeline;

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { Send, Bot, Sparkles, Globe, BrainCircuit } from 'lucide-react';

interface AIChatProps {
  messages: ChatMessage[];
  onSendMessage: (message: string) => void;
  isProcessing: boolean;
}

const AIChat: React.FC<AIChatProps> = ({ messages, onSendMessage, isProcessing }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !isProcessing) {
      onSendMessage(input);
      setInput('');
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-950 border-l border-slate-800">
      {/* Header */}
      <div className="p-4 border-b border-slate-800 flex items-center gap-3 bg-slate-900/50">
        <div className="p-2 bg-amber-500/10 rounded border border-amber-500/20 relative">
             <BrainCircuit className="w-5 h-5 text-amber-500" />
             <div className="absolute -top-1 -right-1 w-2 h-2 bg-cyan-500 rounded-full animate-pulse shadow-[0_0_10px_cyan]"></div>
        </div>
        <div>
            <h3 className="font-display font-bold text-slate-100 tracking-wider">ORÍ</h3>
            <p className="text-[10px] font-mono text-slate-500">CULTURAL INTELLIGENCE</p>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6" ref={scrollRef}>
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[90%] p-4 rounded-xl text-sm leading-relaxed ${
                msg.role === 'user'
                  ? 'bg-slate-800 text-slate-200 border border-slate-700'
                  : 'bg-gradient-to-br from-slate-900 to-slate-950 text-slate-300 border border-slate-800 shadow-lg'
              }`}
            >
                {msg.isFunctionCall ? (
                    <div className="flex items-center gap-2 text-xs font-mono text-amber-500">
                        <Globe className="w-3 h-3 animate-spin-slow" />
                        <span>PROCESSING MEANING GRAPH...</span>
                    </div>
                ) : (
                    msg.content.split('\n').map((line, i) => <p key={i} className="mb-2 last:mb-0">{line}</p>)
                )}
            </div>
          </div>
        ))}
        {isProcessing && (
          <div className="flex justify-start">
             <div className="flex gap-1 p-3">
                <span className="w-1.5 h-1.5 bg-amber-500 rounded-full animate-bounce"></span>
                <span className="w-1.5 h-1.5 bg-amber-500 rounded-full animate-bounce delay-75"></span>
                <span className="w-1.5 h-1.5 bg-amber-500 rounded-full animate-bounce delay-150"></span>
              </div>
          </div>
        )}
      </div>

      {/* Input */}
      <form onSubmit={handleSubmit} className="p-4 bg-slate-900/30 border-t border-slate-800">
        <div className="relative flex items-center gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask ORÍ to translate or analyze..."
            className="w-full bg-slate-950 border border-slate-700 text-slate-200 rounded-lg px-4 py-3 pr-12 text-sm focus:outline-none focus:border-amber-500/50 focus:ring-1 focus:ring-amber-500/20 placeholder-slate-600 transition-all font-sans"
            disabled={isProcessing}
          />
          <button
            type="submit"
            disabled={!input.trim() || isProcessing}
