import React, { useState, useEffect, useRef } from 'react';
import { INITIAL_VIDEO_STATE, INITIAL_CHAT_MESSAGE } from './constants';
import { VideoState, ChatMessage, ToolNames, ToolArgs, LanguageLayer } from './types';
import VideoPlayer from './components/VideoPlayer';
import Timeline from './components/Timeline';
import AIChat from './components/AIChat';
import { createGeminiSession } from './services/geminiService';
import { Globe, Users, Mic2, Layers, Plus, Eye, EyeOff } from 'lucide-react';
import { Chat } from '@google/genai';

const App: React.FC = () => {
  const [videoState, setVideoState] = useState<VideoState>(INITIAL_VIDEO_STATE);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'init', role: 'model', content: INITIAL_CHAT_MESSAGE }
  ]);
  const [isProcessing, setIsProcessing] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);

  // Initialize Chat Session
  useEffect(() => {
    chatSessionRef.current = createGeminiSession();
  }, []);

  const handleSendMessage = async (userMessage: string) => {
    if (!chatSessionRef.current) return;

    setIsProcessing(true);
    const userMsgId = Date.now().toString();
    setMessages(prev => [...prev, { id: userMsgId, role: 'user', content: userMessage }]);

    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMessage });
      const functionCalls = result.functionCalls;

      if (functionCalls && functionCalls.length > 0) {
        setMessages(prev => [...prev, { id: Date.now().toString() + '-fc', role: 'model', content: 'Consulting cultural database...', isFunctionCall: true }]);

        const responses: any[] = [];

        for (const call of functionCalls) {
            const toolName = call.name;
            const args = call.args as ToolArgs;
            let responseResult = { result: "Success" };

            switch (toolName) {
                case ToolNames.ADD_LANGUAGE:
                    // Simulated logic to add a language
                    const newLayer: LanguageLayer = {
                        id: `target-${args.language.toLowerCase()}`,
                        name: `${args.language} (${args.style || 'Standard'})`,
                        code: args.language.substr(0,2).toLowerCase(),
                        type: 'target',
                        isVisible: true,
                        blocks: videoState.meaningTrack.map(m => ({
                            id: Math.random().toString(36),
                            parentId: m.id,
                            text: `[Translated ${m.meaning} to ${args.language}]`,
                            language: args.language,
                            isLiteral: false
                        }))
                    };
                    setVideoState(prev => ({
                        ...prev,
                        languageLayers: [...prev.languageLayers, newLayer],
                        activeLanguageId: newLayer.id
                    }));
                    responseResult = { result: `Added ${args.language} layer.` };
                    break;

                case ToolNames.SET_TONE:
                     setVideoState(prev => {
                         const newMeaningTrack = prev.meaningTrack.map(block => {
                             if(block.id === args.blockId) {
                                 return { ...block, sentiment: args.sentiment };
                             }
                             return block;
                         });
                         return { ...prev, meaningTrack: newMeaningTrack };
                     });
                     responseResult = { result: `Tone set to ${args.sentiment}` };
                     break;

                case ToolNames.ANALYZE_MEANING:
                    // In a real app, this would query a deeper model.
                    responseResult = { result: "The segment contains a proverb 'Àgbà kì í wà lọ́jà' implying leadership responsibility. Tone implies disappointment." };
                    break;
            }

            responses.push({
                name: toolName,
                response: responseResult,
                id: call.id
            });
        }

        const finalResponse = await chatSessionRef.current.sendToolResponse({
            functionResponses: responses
        });

        if (finalResponse.text) {
             setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: finalResponse.text }]);
        }

      } else if (result.text) {
        setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: result.text }]);
      }

    } catch (error) {
      console.error("Chat Error:", error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: "Connection to cultural node lost." }]);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleTogglePlay = () => setVideoState(prev => ({ ...prev, isPlaying: !prev.isPlaying }));
  const handleSeek = (time: number) => setVideoState(prev => ({ ...prev, currentTime: time }));
  const handleTimeUpdate = (time: number) => setVideoState(prev => ({ ...prev, currentTime: time }));
  const handleDurationChange = (duration: number) => setVideoState(prev => ({ ...prev, duration: duration }));

  const toggleLayerVisibility = (id: string) => {
      setVideoState(prev => ({
          ...prev,
          languageLayers: prev.languageLayers.map(l => l.id === id ? { ...l, isVisible: !l.isVisible } : l)
      }));
  };

  const setActiveLayer = (id: string) => {
      setVideoState(prev => ({ ...prev, activeLanguageId: id }));
  };

  const toggleCrowdMode = () => {
      setVideoState(prev => ({ ...prev, crowdMode: !prev.crowdMode }));
  }

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-slate-950 text-slate-200 selection:bg-amber-500/30">

      {/* Left Panel: Language Stack */}
      <div className="w-64 border-r border-slate-800 bg-slate-950 flex flex-col z-20">
        <div className="p-4 border-b border-slate-800">
            <h2 className="font-display font-bold text-white tracking-widest flex items-center gap-2">
                <Globe className="w-4 h-4 text-cyan-500" /> STACK
            </h2>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {/* Source Layer */}
            <div>
                <div className="text-[10px] font-mono text-slate-500 mb-2 uppercase tracking-wider">Source Reality</div>
                {videoState.languageLayers.filter(l => l.type === 'source').map(layer => (
                    <div key={layer.id} className="bg-slate-900 border border-slate-700 rounded-lg p-3 flex items-center justify-between group hover:border-amber-500/50 transition-colors cursor-pointer" onClick={() => setActiveLayer(layer.id)}>
                        <div className="flex items-center gap-2">
                            <Mic2 className="w-4 h-4 text-amber-500" />
                            <span className={`text-sm font-medium ${videoState.activeLanguageId === layer.id ? 'text-amber-400' : 'text-slate-300'}`}>{layer.name}</span>
                        </div>
                    </div>
                ))}
            </div>

            {/* Target Layers */}
            <div>
                 <div className="flex items-center justify-between mb-2">
                    <div className="text-[10px] font-mono text-slate-500 uppercase tracking-wider">Target Worlds</div>
                    <button className="text-cyan-500 hover:text-cyan-400"><Plus className="w-3 h-3" /></button>
                 </div>
                 <div className="space-y-2">
                    {videoState.languageLayers.filter(l => l.type === 'target').map(layer => (
                        <div key={layer.id} 
                             className={`rounded-lg p-3 flex items-center justify-between border transition-all cursor-pointer ${videoState.activeLanguageId === layer.id ? 'bg-cyan-950/30 border-cyan-500/50 shadow-[0_0_15px_rgba(6,182,212,0.1)]' : 'bg-slate-900 border-slate-800 hover:border-slate-700'}`}
                             onClick={() => setActiveLayer(layer.id)}
                        >
                            <div className="flex items-center gap-2">
                                <div className={`w-1.5 h-1.5 rounded-full ${videoState.activeLanguageId === layer.id ? 'bg-cyan-500' : 'bg-slate-600'}`}></div>
                                <span className="text-sm text-slate-300">{layer.name}</span>
                            </div>
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleLayerVisibility(layer.id); }}
                                className="text-slate-600 hover:text-slate-400"
                            >
                                {layer.isVisible ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
                            </button>
                        </div>
                    ))}
                 </div>
            </div>
        </div>

        {/* Global Controls */}
        <div className="p-4 border-t border-slate-800 bg-slate-900/50">
             <button 
                onClick={toggleCrowdMode}
                className={`w-full py-2 px-3 rounded border flex items-center justify-center gap-2 text-xs font-mono transition-all ${videoState.crowdMode ? 'bg-red-900/20 border-red-500 text-red-400 animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-slate-200'}`}
             >
                 <Users className="w-4 h-4" />
                 {videoState.crowdMode ? 'CROWD REALITY: ON' : 'CROWD REALITY: OFF'}
             </button>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0 relative">

        {/* Top Header */}
        <div className="h-14 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-950">
            <div className="flex items-center gap-4">
                <h1 className="font-display font-bold text-xl tracking-widest text-white">ORÍ <span className="text-amber-500">STUDIO</span></h1>
                <div className="h-4 w-[1px] bg-slate-800"></div>
                <div className="text-xs font-mono text-slate-500">PROJECT: YORUBA_WISDOM_01</div>
            </div>
            <div className="flex items-center gap-4">
                <div className="px-3 py-1 rounded bg-slate-900 border border-slate-800 text-[10px] text-slate-400 font-mono">
                    AI CONFIDENCE: 98.4%
                </div>
                <button className="px-5 py-1.5 bg-amber-600 hover:bg-amber-500 text-white text-xs font-bold tracking-wider rounded transition-all shadow-[0_0_15px_rgba(217,119,6,0.4)]">
                    EXPORT ALL LANGUAGES
                </button>
            </div>
        </div>

        {/* Video Stage */}
        <div className="flex-1 p-6 flex justify-center items-center bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-slate-900 to-slate-950">
            <div className="w-full max-w-4xl aspect-video relative z-10 shadow-2xl">
                <VideoPlayer 
                    state={videoState}
                    onTimeUpdate={handleTimeUpdate}
                    onDurationChange={handleDurationChange}
                    onTogglePlay={handleTogglePlay}
                />
            </div>
        </div>

        {/* Bottom Timeline */}
        <div className="h-64 border-t border-slate-800 bg-slate-950 z-20">
            <Timeline state={videoState} onSeek={handleSeek} />
        </div>
      </div>

      {/* Right Sidebar (AI Chat) */}
      <div className="w-80 border-l border-slate-800 z-30 shadow-2xl">
        <AIChat 
            messages={messages} 
            onSendMessage={handleSendMessage}
            isProcessing={isProcessing}
        />
      </div>

    </div>
  );
};

export default App;

export type Sentiment = 'neutral' | 'anger' | 'joy' | 'urgency' | 'proverb' | 'sarcasm';

export interface MeaningBlock {
  id: string;
  startTime: number;
  duration: number;
  originalText: string; // e.g., Yoruba text
  meaning: string; // The core intent/meaning
  sentiment: Sentiment;
  culturalNote?: string; // Context for the creator
}

export interface TranslationBlock {
  id: string;
  parentId: string; // Links to MeaningBlock
  text: string;
  language: string;
  isLiteral: boolean; // Did we lose meaning?
  confidence: number; // 0.0 to 1.0 - Cultural Guard Score
}

export interface LanguageLayer {
  id: string;
  name: string;
  code: string;
  type: 'source' | 'target';
  isVisible: boolean;
  blocks: TranslationBlock[];
}

export type SimulationMode = 'native' | 'global' | 'learner';

export interface VideoState {
  isPlaying: boolean;
  currentTime: number;
  duration: number;
  volume: number;
  activeLanguageId: string; // Which language to display on video
  meaningTrack: MeaningBlock[];
  languageLayers: LanguageLayer[];
  crowdMode: boolean; // "Crowded Reality" mode
  simulationMode: SimulationMode; // Audience Simulator
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model' | 'system';
  content: string;
  isFunctionCall?: boolean;
}

export enum ToolNames {
  ANALYZE_MEANING = 'analyze_meaning',
  ADD_LANGUAGE = 'add_language',
  SET_TONE = 'set_tone',
  TRANSLATE_LAYER = 'translate_layer',
  ANALYZE_CULTURAL_LOSS = 'analyze_cultural_loss',
}

export type ToolArgs = Record<string, any>;

