  },
};

const setToneTool: FunctionDeclaration = {
  name: ToolNames.SET_TONE,
  description: "Manually override the sentiment/tone of a block.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      blockId: { type: Type.STRING, description: "ID of the block." },
      sentiment: { type: Type.STRING, description: "Sentiment: 'neutral', 'anger', 'joy', 'urgency', 'proverb', 'sarcasm'." }
    },
    required: ["blockId", "sentiment"],
  },
};

const analyzeCulturalLossTool: FunctionDeclaration = {
  name: ToolNames.ANALYZE_CULTURAL_LOSS,
  description: "Analyze how much meaning was lost in a specific translation layer.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      layerId: { type: Type.STRING, description: "ID of the language layer." },
    },
    required: ["layerId"],
  },
};

