import React, { useRef, useEffect } from 'react';
import { VideoState, Sentiment } from '../types';
import { SAMPLE_VIDEO_URL } from '../constants';
import { Play, Pause, AlertTriangle, Sparkles, Quote, Info, Ear, Eye, Maximize2 } from 'lucide-react';

interface VideoPlayerProps {
  state: VideoState;
  onTimeUpdate: (time: number) => void;
  onDurationChange: (duration: number) => void;
  onTogglePlay: () => void;
}

const getSentimentStyles = (sentiment: Sentiment) => {
  switch (sentiment) {
    case 'anger':
      return 'font-display font-bold text-red-500 tracking-tighter uppercase animate-pulse drop-shadow-[0_0_10px_rgba(239,68,68,0.8)]';
    case 'urgency':
      return 'font-mono font-bold text-amber-500 italic tracking-widest bg-black/50 px-4 py-2 border-l-4 border-amber-500';
    case 'proverb':
      return 'font-serif italic text-yellow-200 text-2xl drop-shadow-[0_2px_4px_rgba(0,0,0,0.8)] border-b border-yellow-500/50 pb-2';
    case 'sarcasm':
      return 'font-mono text-pink-400 -skew-x-12 decoration-wavy underline decoration-pink-500/50';
    case 'joy':
      return 'font-display text-cyan-300 drop-shadow-[0_0_15px_rgba(34,211,238,0.6)] scale-110';
    default:
      return 'font-sans font-medium text-white drop-shadow-md bg-black/40 px-3 py-1 rounded';
  }
};

const getSentimentIcon = (sentiment: Sentiment) => {
    switch (sentiment) {
        case 'proverb': return <Quote className="w-4 h-4 text-yellow-500 inline mr-2 mb-2" />;
        case 'urgency': return <AlertTriangle className="w-4 h-4 text-amber-500 inline mr-2" />;
        case 'joy': return <Sparkles className="w-4 h-4 text-cyan-500 inline mr-2" />;
        default: return null;
    }
}

const VideoPlayer: React.FC<VideoPlayerProps> = ({ state, onTimeUpdate, onDurationChange, onTogglePlay }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if (videoRef.current) {
      if (state.isPlaying && videoRef.current.paused) {
        videoRef.current.play().catch(e => console.log("Autoplay prevented", e));
      } else if (!state.isPlaying && !videoRef.current.paused) {
        videoRef.current.pause();
      }
    }
  }, [state.isPlaying]);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.volume = state.volume;
      videoRef.current.playbackRate = state.playbackSpeed;
    }
  }, [state.volume, state.playbackSpeed]);

  useEffect(() => {
    if (videoRef.current && Math.abs(videoRef.current.currentTime - state.currentTime) > 1) {
      videoRef.current.currentTime = state.currentTime;
    }
  }, [state.currentTime]);

  // CSS Filters Calculation
  const getFilterString = () => {
    let filters = [
      `brightness(${state.adjustment.brightness}%)`,
      `contrast(${state.adjustment.contrast}%)`,
      `saturate(${state.adjustment.saturation}%)`,
      `blur(${state.adjustment.blur}px)`,
      `hue-rotate(${state.adjustment.hue}deg)`
    ];

    // Add effect filters
    if (state.activeEffect === 'vhs') filters.push('sepia(0.3) contrast(1.2)');
    if (state.activeEffect === 'cyberpunk') filters.push('hue-rotate(180deg) saturate(1.5)');
    if (state.activeEffect === 'noir') filters.push('grayscale(100%) contrast(1.1)');

    if (state.simulationMode === 'learner') filters.push('blur(2px)');

    return filters.join(' ');
  };

  // Transform Calculation
  const getTransformStyle = () => {
    return {
      transform: `scale(${state.transform.scale}) translate(${state.transform.positionX}px, ${state.transform.positionY}px) rotate(${state.transform.rotation}deg)`,
      opacity: state.transform.opacity / 100
    };
  };

  // Active items
  const activeLayer = state.languageLayers.find(l => l.id === state.activeLanguageId);
  const activeBlock = activeLayer?.blocks.find(b => {
    const meaning = state.meaningTrack.find(m => m.id === b.parentId);
    return meaning && state.currentTime >= meaning.startTime && state.currentTime <= meaning.startTime + meaning.duration;
  });
  const activeMeaning = activeBlock ? state.meaningTrack.find(m => m.id === activeBlock.parentId) : null;

  // Active Text Overlays
  const activeTextOverlays = state.textTrack.filter(t => state.currentTime >= t.startTime && state.currentTime <= t.startTime + t.duration);

  return (
    <div className="relative w-full h-full bg-slate-950 rounded-lg overflow-hidden border border-slate-800 shadow-[0_0_50px_rgba(0,0,0,0.7)] group flex items-center justify-center">

      {/* Video Canvas Container */}
      <div className="relative overflow-hidden w-full h-full">
         <video
            ref={videoRef}
            className={`w-full h-full object-cover transition-all duration-75 ease-linear
                ${state.crowdMode ? 'brightness-110 contrast-125 saturate-150' : ''}
            `}
            style={{
               filter: getFilterString(),
               ...getTransformStyle()
            }}
            src={SAMPLE_VIDEO_URL}
            loop
            playsInline
            onTimeUpdate={(e) => onTimeUpdate(e.currentTarget.currentTime)}
            onLoadedMetadata={(e) => onDurationChange(e.currentTarget.duration)}
         />

         {/* Custom Text Overlays Layer */}
         <div className="absolute inset-0 pointer-events-none overflow-hidden">
             {activeTextOverlays.map(text => (
                 <div 
                    key={text.id}
                    className="absolute whitespace-pre-wrap text-center transform -translate-x-1/2 -translate-y-1/2"
                    style={{
                        left: `${text.style.x}%`,
                        top: `${text.style.y}%`,
                        fontFamily: text.style.fontFamily,
                        fontSize: `${text.style.fontSize}px`,
                        color: text.style.color,
                        opacity: text.style.opacity,
                        textShadow: text.style.shadow,
                        fontWeight: 'bold',
                        width: '100%',
                        pointerEvents: 'auto' // Could allow dragging later
                    }}
                 >
                     {text.text}
                 </div>
             ))}
         </div>

         {/* VHS Overlay FX */}
         {state.activeEffect === 'vhs' && (
            <div className="absolute inset-0 pointer-events-none bg-[repeating-linear-gradient(0deg,transparent,transparent_2px,#000_3px)] opacity-10 mix-blend-overlay"></div>
         )}
      </div>

      {/* Simulator Overlay */}
      {state.simulationMode !== 'native' && (
          <div className="absolute top-4 right-4 bg-black/60 backdrop-blur-md text-xs font-mono px-3 py-1 rounded-full border border-white/20 text-white flex items-center gap-2 pointer-events-none z-20">
              <Eye className="w-3 h-3 text-cyan-400" />
              SIM: {state.simulationMode.toUpperCase()}
          </div>
      )}

      {/* Dynamic Subtitle Layer (Fixed on top of transformations) */}
      <div className="absolute inset-0 pointer-events-none flex flex-col justify-end items-center pb-16 px-12 text-center z-10">
        {activeBlock && activeMeaning && (
            <div className="flex flex-col items-center gap-2">
                {state.simulationMode !== 'native' && activeMeaning.culturalNote && (
                    <div className="animate-in fade-in slide-in-from-bottom-2 bg-slate-900/90 text-slate-300 text-[11px] px-3 py-2 rounded-lg border border-yellow-500/40 max-w-md shadow-lg backdrop-blur-md mb-2">
                        <div className="flex items-center gap-1.5 text-yellow-500 font-bold mb-1 uppercase tracking-wider text-[9px]">
                            <Info className="w-3 h-3" /> Cultural Context
                        </div>
                        {activeMeaning.culturalNote}
                    </div>
                )}
                <div className={`transition-all duration-300 animate-in slide-in-from-bottom-5 fade-in ${getSentimentStyles(activeMeaning.sentiment)}`}>
                    {getSentimentIcon(activeMeaning.sentiment)}
                    {activeBlock.text}
                </div>
            </div>
        )}
      </div>

      {/* Playback Controls Overlay */}
      <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300 bg-black/20 pointer-events-none z-30">
        <div className="pointer-events-auto p-4 rounded-full bg-slate-900/80 backdrop-blur-md border border-cyan-500/30 hover:scale-110 transition-transform cursor-pointer shadow-[0_0_20px_rgba(6,182,212,0.3)]" onClick={onTogglePlay}>
          {state.isPlaying ? <Pause className="w-8 h-8 text-cyan-400" /> : <Play className="w-8 h-8 text-cyan-400 ml-1" />}
        </div>
      </div>

    </div>
  );
};

export default VideoPlayer;

import React from 'react';
import { VideoState, MeaningBlock, LanguageLayer, Sentiment } from '../types';
import { AlertCircle, Star, Quote, Zap, MessageSquare, Scissors, Trash2, Magnet, Undo2, Redo2, ZoomIn, ZoomOut, Type, Music } from 'lucide-react';

interface TimelineProps {
  state: VideoState;
  onSeek: (time: number) => void;
}

const SentimentColorMap: Record<Sentiment, string> = {
  neutral: 'bg-slate-600 border-slate-500',
  anger: 'bg-red-900/80 border-red-500',
  joy: 'bg-cyan-900/80 border-cyan-500',
  urgency: 'bg-amber-900/80 border-amber-500',
  proverb: 'bg-yellow-900/80 border-yellow-500',
  sarcasm: 'bg-pink-900/80 border-pink-500',
};

const Timeline: React.FC<TimelineProps> = ({ state, onSeek }) => {
  const percentage = (state.currentTime / state.duration) * 100;

  const handleTimelineClick = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const clickPercentage = x / rect.width;
    const newTime = clickPercentage * state.duration;
    onSeek(newTime);
  };

  return (
    <div className="w-full h-full flex flex-col bg-slate-950 border-t border-slate-800 select-none">

      {/* Timeline Toolbar */}
      <div className="h-10 border-b border-slate-800 bg-slate-900 flex items-center justify-between px-4">
         <div className="flex items-center gap-2">
            <button className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-white transition-colors" title="Split (Ctrl+B)">
                <Scissors className="w-4 h-4" />
            </button>
            <button className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-white transition-colors" title="Delete">
                <Trash2 className="w-4 h-4" />
            </button>
            <div className="w-[1px] h-4 bg-slate-700 mx-1"></div>
            <button className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-cyan-500 transition-colors" title="Magnet Mode">
                <Magnet className="w-4 h-4" />
            </button>
         </div>
         <div className="flex items-center gap-2">
            <button className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-white" title="Undo"><Undo2 className="w-4 h-4" /></button>
            <button className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-white" title="Redo"><Redo2 className="w-4 h-4" /></button>
            <div className="w-[1px] h-4 bg-slate-700 mx-1"></div>
            <ZoomOut className="w-3 h-3 text-slate-500" />
            <div className="w-20 h-1 bg-slate-800 rounded-full">
                <div className="w-1/3 h-full bg-slate-600 rounded-full"></div>
            </div>
            <ZoomIn className="w-3 h-3 text-slate-500" />
         </div>
      </div>

      {/* Time Markers */}
      <div className="h-6 flex items-center justify-between text-[10px] font-mono text-slate-500 px-4 border-b border-slate-800/50 bg-slate-900/30">
        <span>00:00</span>
        <span>{new Date(state.duration * 1000).toISOString().substr(14, 5)}</span>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar relative bg-slate-950/50">
        <div className="relative min-h-[300px] p-2" onClick={handleTimelineClick}>

            {/* Playhead Line */}
            <div 
                className="absolute top-0 bottom-0 w-[1px] bg-cyan-500 z-50 pointer-events-none shadow-[0_0_10px_rgba(6,182,212,0.8)]"
                style={{ left: `${percentage}%` }}
            >
                <div className="absolute -top-1 -left-[5px] w-0 h-0 border-l-[6px] border-l-transparent border-r-[6px] border-r-transparent border-t-[8px] border-t-cyan-500"></div>
            </div>

            {/* Video Track (Simulated) */}
            <div className="mb-2 relative h-12 w-full bg-slate-900/50 rounded-lg border border-slate-800 overflow-hidden group hover:border-slate-700">
                 <div className="absolute inset-0 flex items-center justify-center opacity-20">
                    <div className="w-full h-full bg-[repeating-linear-gradient(90deg,transparent,transparent_50px,rgba(255,255,255,0.05)_50px,rgba(255,255,255,0.05)_51px)]"></div>
                 </div>
                 <div className="absolute left-2 top-2 text-[10px] font-bold text-slate-500 z-10">VIDEO 1</div>
            </div>

            {/* Meaning Track (The "Spine") */}
            <div className="mb-2 relative h-10 w-full bg-slate-900/50 rounded-lg border border-slate-800 overflow-hidden">
                <div className="absolute left-0 top-0 bottom-0 w-1 bg-amber-500/50"></div>
                {state.meaningTrack.map((block) => {
                     const left = (block.startTime / state.duration) * 100;
                     const width = (block.duration / state.duration) * 100;
                     return (
                         <div 
                            key={block.id}
                            className={`absolute top-1 bottom-1 rounded border ${SentimentColorMap[block.sentiment]} flex items-center justify-center cursor-pointer hover:brightness-125 transition-all opacity-80`}
                            style={{ left: `${left}%`, width: `${width}%` }}
                         >
                             <div className="w-full h-full flex items-center justify-center bg-black/20">
                                <span className="text-[9px] text-white/90 truncate px-1">{block.meaning}</span>
                             </div>
                         </div>
                     )
                })}
            </div>

            {/* Language Layers */}
            <div className="space-y-1 mt-1">
                {state.languageLayers.filter(l => l.isVisible).map(layer => (
                    <div key={layer.id} className="relative h-8 w-full bg-slate-900/20 rounded border border-slate-800/50 hover:border-slate-700 transition-colors">
                         <div className="absolute -left-0 top-0 bottom-0 w-1 rounded-l bg-slate-700"></div>
                         <div className="absolute left-2 top-1/2 -translate-y-1/2 text-[9px] font-mono text-slate-500 z-10 pointer-events-none opacity-50">{layer.code.toUpperCase()}</div>

                         {layer.blocks.map(block => {
                            const meaning = state.meaningTrack.find(m => m.id === block.parentId);
                            if(!meaning) return null;

                            const left = (meaning.startTime / state.duration) * 100;
                            const width = (meaning.duration / state.duration) * 100;
                            const guardColor = block.confidence < 0.7 ? 'bg-red-500' : 'bg-emerald-500';

                            return (
                                <div 
                                    key={block.id}
                                    className={`absolute top-[2px] bottom-[2px] rounded-sm bg-slate-700/60 border border-slate-600/30 text-[9px] flex flex-col justify-center px-2 text-slate-300 overflow-hidden ${block.isLiteral ? 'opacity-70' : ''}`}
                                    style={{ left: `${left}%`, width: `${width}%` }}
                                >
                                    <span className="truncate leading-none">{block.text}</span>
                                    <div className="w-full h-[1px] bg-slate-800 mt-[1px] opacity-70">
                                        <div className={`h-full ${guardColor}`} style={{ width: `${block.confidence * 100}%` }}></div>
                                    </div>
                                </div>
                            )
                         })}
                    </div>
                ))}
            </div>

            {/* TEXT TRACK */}
            <div className="relative h-8 w-full mt-2 bg-slate-900/20 rounded border border-slate-800/50">
                <div className="absolute -left-0 top-0 bottom-0 w-1 rounded-l bg-cyan-600"></div>
                <div className="absolute left-2 top-1/2 -translate-y-1/2 text-[9px] font-mono text-slate-500 z-10 pointer-events-none opacity-50 flex items-center gap-1">
                    <Type className="w-3 h-3" /> TEXT
                </div>
                {state.textTrack.map(txt => {
                     const left = (txt.startTime / state.duration) * 100;
                     const width = (txt.duration / state.duration) * 100;
                     return (
                         <div
                            key={txt.id}
                            className="absolute top-[2px] bottom-[2px] rounded-sm bg-cyan-900/60 border border-cyan-500/50 text-[9px] flex items-center px-2 text-cyan-100 overflow-hidden hover:brightness-125 cursor-pointer"
                            style={{ left: `${left}%`, width: `${width}%` }}
                         >
                            {txt.text}
                         </div>
                     )
                })}
            </div>

            {/* AUDIO TRACK */}
            <div className="relative h-8 w-full mt-1 bg-slate-900/20 rounded border border-slate-800/50">
                <div className="absolute -left-0 top-0 bottom-0 w-1 rounded-l bg-purple-600"></div>
                <div className="absolute left-2 top-1/2 -translate-y-1/2 text-[9px] font-mono text-slate-500 z-10 pointer-events-none opacity-50 flex items-center gap-1">
                    <Music className="w-3 h-3" /> AUDIO
                </div>
                {state.audioTrack.map(aud => {
                     const left = (aud.startTime / state.duration) * 100;
                     const width = (aud.duration / state.duration) * 100;
                     return (
                         <div
                            key={aud.id}
                            className="absolute top-[2px] bottom-[2px] rounded-sm bg-purple-900/60 border border-purple-500/50 text-[9px] flex items-center px-2 text-purple-100 overflow-hidden hover:brightness-125 cursor-pointer"
                            style={{ left: `${left}%`, width: `${width}%` }}
                         >
                            <div className="w-full h-full opacity-30 flex items-end pb-1 gap-[1px]">
                                {Array.from({length: 20}).map((_, i) => (
                                    <div key={i} className="flex-1 bg-purple-300" style={{ height: `${Math.random() * 100}%` }}></div>
                                ))}
                            </div>
                            <span className="absolute left-2">{aud.name}</span>
                         </div>
                     )
                })}
            </div>

        </div>
      </div>
    </div>
  );
};

