import React, { useState, useEffect, useRef } from 'react';
import { INITIAL_VIDEO_STATE, INITIAL_CHAT_MESSAGE } from './constants';
import { VideoState, ChatMessage, ToolNames, ToolArgs, LanguageLayer, SimulationMode, EditorMode, RightPanelTab, VideoTransform, VideoAdjustment } from './types';
import VideoPlayer from './components/VideoPlayer';
import Timeline from './components/Timeline';
import AIChat from './components/AIChat';
import EditorSidebar from './components/EditorSidebar';
import PropertiesPanel from './components/PropertiesPanel';
import { createGeminiSession } from './services/geminiService';
import { Users, MonitorPlay, Settings2, MessageSquare } from 'lucide-react';
import { Chat } from '@google/genai';

const App: React.FC = () => {
  const [videoState, setVideoState] = useState<VideoState>({ ...INITIAL_VIDEO_STATE, activeMode: 'meaning' });
  const [rightPanel, setRightPanel] = useState<RightPanelTab>('chat');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'init', role: 'model', content: INITIAL_CHAT_MESSAGE }
  ]);
  const [isProcessing, setIsProcessing] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);

  // Initialize Chat Session
  useEffect(() => {
    chatSessionRef.current = createGeminiSession();
  }, []);

  const handleSendMessage = async (userMessage: string) => {
    if (!chatSessionRef.current) return;

    setIsProcessing(true);
    const userMsgId = Date.now().toString();
    setMessages(prev => [...prev, { id: userMsgId, role: 'user', content: userMessage }]);

    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMessage });
      const functionCalls = result.functionCalls;

      if (functionCalls && functionCalls.length > 0) {
        setMessages(prev => [...prev, { id: Date.now().toString() + '-fc', role: 'model', content: 'Consulting cultural database...', isFunctionCall: true }]);
        const responses: any[] = [];

        for (const call of functionCalls) {
            const toolName = call.name;
            const args = call.args as ToolArgs;
            let responseResult = { result: "Success" };

            switch (toolName) {
                case ToolNames.ADD_LANGUAGE:
                    const newLayer: LanguageLayer = {
                        id: `target-${args.language.toLowerCase()}`,
                        name: `${args.language} (${args.style || 'Standard'})`,
                        code: args.language.substr(0,2).toLowerCase(),
                        type: 'target',
                        isVisible: true,
                        blocks: videoState.meaningTrack.map(m => ({
                            id: Math.random().toString(36),
                            parentId: m.id,
                            text: `[Translated ${m.meaning} to ${args.language}]`,
                            language: args.language,
                            isLiteral: false,
                            confidence: 0.9
                        }))
                    };
                    setVideoState(prev => ({
                        ...prev,
                        languageLayers: [...prev.languageLayers, newLayer],
                        activeLanguageId: newLayer.id
                    }));
                    responseResult = { result: `Added ${args.language} layer.` };
                    break;
                case ToolNames.SET_TONE:
                     setVideoState(prev => {
                         const newMeaningTrack = prev.meaningTrack.map(block => {
                             if(block.id === args.blockId) { return { ...block, sentiment: args.sentiment }; }
                             return block;
                         });
                         return { ...prev, meaningTrack: newMeaningTrack };
                     });
                     responseResult = { result: `Tone set to ${args.sentiment}` };
                     break;
                case ToolNames.ANALYZE_MEANING:
                    responseResult = { result: "The segment contains a proverb 'Àgbà kì í wà lọ́jà' implying leadership responsibility. Tone implies disappointment." };
                    break;
                case ToolNames.ANALYZE_CULTURAL_LOSS:
                    responseResult = { result: "Detected 20% nuance loss in English layer. Proverb 'The goat has entered' was translated literally." };
                    break;
            }
            responses.push({ name: toolName, response: responseResult, id: call.id });
        }
        const finalResponse = await chatSessionRef.current.sendToolResponse({ functionResponses: responses });
        if (finalResponse.text) {
             setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: finalResponse.text }]);
        }
      } else if (result.text) {
        setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: result.text }]);
      }
    } catch (error) {
      console.error("Chat Error:", error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: "Connection to cultural node lost." }]);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleTogglePlay = () => setVideoState(prev => ({ ...prev, isPlaying: !prev.isPlaying }));
  const handleSeek = (time: number) => setVideoState(prev => ({ ...prev, currentTime: time }));
  const handleTimeUpdate = (time: number) => setVideoState(prev => ({ ...prev, currentTime: time }));
  const handleDurationChange = (duration: number) => setVideoState(prev => ({ ...prev, duration: duration }));

  const toggleLayerVisibility = (id: string) => {
      setVideoState(prev => ({
          ...prev,
          languageLayers: prev.languageLayers.map(l => l.id === id ? { ...l, isVisible: !l.isVisible } : l)
      }));
  };

  const addTextLayer = (styleId: string) => {
      // Logic to add a new text layer based on style
      const newText = {
          id: Math.random().toString(36),
          text: 'NEW TEXT LAYER',
          startTime: videoState.currentTime,
          duration: 3,
          style: {
              fontFamily: styleId === 'neon' ? 'Orbitron' : 'Inter',
              fontSize: 36,
              color: styleId === 'glitch' ? '#ef4444' : '#ffffff',
              x: 50,
              y: 50,
              opacity: 1,
              shadow: styleId === 'neon' ? '0 0 10px cyan' : 'none'
          }
      };
      setVideoState(prev => ({...prev, textTrack: [...prev.textTrack, newText] }));
  };

  const addAudioLayer = (trackId: string) => {
      const newAudio = {
          id: Math.random().toString(36),
          name: `Track ${trackId}`,
          startTime: videoState.currentTime,
          duration: 15,
          volume: 1,
          type: 'music' as const
      };
      setVideoState(prev => ({...prev, audioTrack: [...prev.audioTrack, newAudio] }));
  };

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-slate-950 text-slate-200 selection:bg-amber-500/30">

      {/* LEFT: Editor Sidebar (Tools & Drawers) */}
      <EditorSidebar 
          state={videoState}
          onSetMode={(mode) => setVideoState(prev => ({ ...prev, activeMode: mode }))}
          onSetEffect={(effect) => setVideoState(prev => ({ ...prev, activeEffect: effect }))}
          onToggleLayer={toggleLayerVisibility}
          onSetActiveLayer={(id) => setVideoState(prev => ({ ...prev, activeLanguageId: id }))}
          onAddText={addTextLayer}
          onAddAudio={addAudioLayer}
      />

      {/* CENTER: Stage & Timeline */}
      <div className="flex-1 flex flex-col min-w-0 relative">

        {/* Header */}
        <div className="h-14 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-950">
            <div className="flex items-center gap-4">
                <h1 className="font-display font-bold text-xl tracking-widest text-white">ORÍ <span className="text-amber-500">STUDIO</span></h1>
                <div className="h-4 w-[1px] bg-slate-800"></div>
                <div className="text-xs font-mono text-slate-500">PROJECT: YORUBA_WISDOM_01</div>
            </div>

            <div className="flex items-center gap-2 bg-slate-900 rounded-lg p-1 border border-slate-800">
                {(['native', 'global', 'learner'] as SimulationMode[]).map(mode => (
                    <button key={mode} onClick={() => setVideoState(prev => ({...prev, simulationMode: mode}))} 
                        className={`px-3 py-1 rounded-md text-xs font-medium uppercase transition-all ${videoState.simulationMode === mode ? 'bg-slate-700 text-white' : 'text-slate-500 hover:text-slate-300'}`}>
                        {mode}
                    </button>
                ))}
            </div>

            <div className="flex items-center gap-4">
                 <button onClick={() => setVideoState(prev => ({ ...prev, crowdMode: !prev.crowdMode }))}
                    className={`flex items-center gap-2 text-xs font-mono transition-colors ${videoState.crowdMode ? 'text-red-400 animate-pulse' : 'text-slate-500 hover:text-white'}`}>
                    <Users className="w-4 h-4" /> {videoState.crowdMode ? 'CROWD: ON' : 'CROWD: OFF'}
                 </button>
                <button className="px-5 py-1.5 bg-amber-600 hover:bg-amber-500 text-white text-xs font-bold tracking-wider rounded transition-all shadow-[0_0_15px_rgba(217,119,6,0.4)]">
                    EXPORT
                </button>
            </div>
        </div>

        {/* Video Stage */}
        <div className="flex-1 p-6 flex justify-center items-center bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-slate-900 to-slate-950">
            <div className="w-full max-w-4xl aspect-video relative z-10 shadow-2xl">
                <VideoPlayer 
                    state={videoState}
                    onTimeUpdate={handleTimeUpdate}
                    onDurationChange={handleDurationChange}
                    onTogglePlay={handleTogglePlay}
                />
            </div>
        </div>

        {/* Timeline */}
        <div className="h-72 border-t border-slate-800 bg-slate-950 z-20">
            <Timeline state={videoState} onSeek={handleSeek} />
        </div>
      </div>

      {/* RIGHT: Inspector & Chat */}
      <div className="w-80 border-l border-slate-800 bg-slate-950 flex flex-col z-30 shadow-2xl">
         {/* Toggle Tabs */}
         <div className="flex border-b border-slate-800">
             <button onClick={() => setRightPanel('properties')} className={`flex-1 py-3 text-xs font-bold tracking-wider flex items-center justify-center gap-2 ${rightPanel === 'properties' ? 'text-white border-b-2 border-purple-500 bg-slate-900' : 'text-slate-500 hover:bg-slate-900/50'}`}>
                 <Settings2 className="w-4 h-4" /> PROPERTIES
             </button>
             <button onClick={() => setRightPanel('chat')} className={`flex-1 py-3 text-xs font-bold tracking-wider flex items-center justify-center gap-2 ${rightPanel === 'chat' ? 'text-white border-b-2 border-amber-500 bg-slate-900' : 'text-slate-500 hover:bg-slate-900/50'}`}>
                 <MessageSquare className="w-4 h-4" /> AI ASSISTANT
             </button>
         </div>

         <div className="flex-1 overflow-hidden relative">
             {rightPanel === 'chat' ? (
                <AIChat messages={messages} onSendMessage={handleSendMessage} isProcessing={isProcessing} />
             ) : (
                <PropertiesPanel 
                    state={videoState}
                    onChangeTransform={(t) => setVideoState(prev => ({...prev, transform: t}))}
                    onChangeAdjustment={(a) => setVideoState(prev => ({...prev, adjustment: a}))}
                    onChangeSpeed={(s) => setVideoState(prev => ({...prev, playbackSpeed: s}))}
                />
             )}
         </div>
      </div>

    </div>
  );
};

export default App;

export type Sentiment = 'neutral' | 'anger' | 'joy' | 'urgency' | 'proverb' | 'sarcasm';

export interface MeaningBlock {
  id: string;
  startTime: number;
  duration: number;
  originalText: string;
  meaning: string;
  sentiment: Sentiment;
  culturalNote?: string;
}

export interface TranslationBlock {
  id: string;
  parentId: string;
  text: string;
  language: string;
  isLiteral: boolean;
  confidence: number;
}

export interface LanguageLayer {
  id: string;
  name: string;
  code: string;
  type: 'source' | 'target';
  isVisible: boolean;
  blocks: TranslationBlock[];
}

export type TextAnimation = 'none' | 'fade' | 'pop' | 'slide' | 'typewriter';

export interface TextBlock {
  id: string;
  text: string;
  startTime: number;
  duration: number;
  animation: TextAnimation; // New
  style: {
    fontFamily: string;
    fontSize: number;
    color: string;
    x: number;
    y: number;
    opacity: number;
    shadow: string;
  }
}

export interface StickerBlock {
  id: string;
  content: string; // Emoji or URL
  startTime: number;
  duration: number;
  x: number;
  y: number;
  scale: number;
}

export interface AudioBlock {
  id: string;
  name: string;
  startTime: number;
  duration: number;
  volume: number;
  type: 'music' | 'sfx';
}

export type SimulationMode = 'native' | 'global' | 'learner';
export type AspectRatio = '16:9' | '9:16' | '1:1' | '4:5';

// NEW: Editor specific types
export type EditorMode = 'meaning' | 'text' | 'stickers' | 'audio' | 'effects' | 'ratio' | 'filters';
export type RightPanelTab = 'properties' | 'chat';

export interface VideoTransform {
  scale: number;
  positionX: number;
  positionY: number;
  rotation: number;
  opacity: number;
}

export interface VideoAdjustment {
  brightness: number;
  contrast: number;
  saturation: number;
  blur: number;
  hue: number;
}

export interface VideoState {
  isPlaying: boolean;
  currentTime: number;
  duration: number;
  volume: number;
  playbackSpeed: number; 
  aspectRatio: AspectRatio; // New
  canvasColor: string; // New

  activeLanguageId: string;
  meaningTrack: MeaningBlock[];
  languageLayers: LanguageLayer[];
  textTrack: TextBlock[]; 
  stickerTrack: StickerBlock[]; // New
  audioTrack: AudioBlock[]; 

  crowdMode: boolean;
  simulationMode: SimulationMode;

  // New Editing State
  transform: VideoTransform;
  adjustment: VideoAdjustment;
  activeEffect: string | null;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model' | 'system';
  content: string;
  isFunctionCall?: boolean;
}

