            <button className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-white transition-colors" title="Delete">
                <Trash2 className="w-4 h-4" />
            </button>
            <div className="w-[1px] h-4 bg-slate-700 mx-1"></div>
            <button className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-cyan-500 transition-colors" title="Magnet Mode">
