            <div className="h-[1px] bg-slate-800 w-full"></div>

            {/* Adjustments Section */}
            <div className="space-y-4">
                <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 flex items-center gap-2 justify-between">
                   <span className="flex items-center gap-2"><Sun className="w-3 h-3" /> Adjustments</span>
                   <KeyframeButton />
                </h3>

                {[
                    { label: 'Brightness', key: 'brightness', min: 0, max: 200, icon: Sun },
                    { label: 'Contrast', key: 'contrast', min: 0, max: 200, icon: Contrast },
                    { label: 'Saturation', key: 'saturation', min: 0, max: 200, icon: Droplets },
                    { label: 'Blur', key: 'blur', min: 0, max: 20, icon: Zap },
