  ANALYZE_MEANING = 'analyze_meaning',
  ADD_LANGUAGE = 'add_language',
  SET_TONE = 'set_tone',
  TRANSLATE_LAYER = 'translate_layer',
  ANALYZE_CULTURAL_LOSS = 'analyze_cultural_loss',
}

export type ToolArgs = Record<string, any>;

import React from 'react';
import { VideoState, EditorMode, LanguageLayer, AspectRatio, FilterPreset, EffectType } from '../types';
import { BrainCircuit, Wand2, Sliders, Layers, Mic2, Globe, Plus, Eye, EyeOff, LayoutTemplate, Type, Music, PlayCircle, Smile, Square, Smartphone, Monitor, Image, Sparkles, FolderOpen, Film } from 'lucide-react';

interface EditorSidebarProps {
  state: VideoState;
  onSetMode: (mode: EditorMode) => void;
  onToggleLayer: (id: string) => void;
  onSetActiveLayer: (id: string) => void;
  onAddText: (style: string, animation?: string) => void;
  onAddAudio: (track: string) => void;
  onAddSticker: (content: string) => void;
  onAddEffect: (type: EffectType, name: string) => void;
  onAddOverlay: (src: string, type: 'image' | 'video') => void;
  onChangeRatio: (ratio: AspectRatio) => void;
  onSetFilter: (filter: FilterPreset) => void;
}

const FILTER_PRESETS: { id: FilterPreset, name: string, class: string }[] = [
    { id: 'none', name: 'Original', class: 'bg-slate-700' },
    { id: 'vibrant', name: 'Vibrant', class: 'bg-gradient-to-tr from-yellow-400 to-red-500' },
