import React from 'react';
import { VideoState, VideoTransform, VideoAdjustment, MaskShape, AnimationIn, AnimationOut, AnimationCombo, CanvasType, BlurLevel, ChromaKey, SpeedType, SpeedCurvePreset } from '../types';
import { Sliders, Maximize, Move, RotateCw, Sun, Droplets, Contrast, Zap, Diamond, Palette, Scissors, PlaySquare, EyeOff, Gauge, Activity } from 'lucide-react';

interface PropertiesPanelProps {
  state: VideoState;
  onChangeTransform: (transform: VideoTransform) => void;
  onChangeAdjustment: (adj: VideoAdjustment) => void;
  onChangeSpeed: (speed: number) => void;
  onChangeSpeedType: (type: SpeedType) => void;
  onChangeSpeedCurve: (curve: SpeedCurvePreset) => void;
  onChangeCanvasColor: (color: string) => void;
  onChangeCanvasType: (type: CanvasType) => void;
  onChangeBlurLevel: (level: BlurLevel) => void;
  onChangeMask: (mask: MaskShape) => void;
  onChangeAnimationIn: (anim: AnimationIn) => void;
  onChangeAnimationOut: (anim: AnimationOut) => void;
  onChangeAnimationCombo: (anim: AnimationCombo) => void;
  onChangeChromaKey: (chroma: ChromaKey) => void;
}

const PropertiesPanel: React.FC<PropertiesPanelProps> = ({ state, onChangeTransform, onChangeAdjustment, onChangeSpeed, onChangeSpeedType, onChangeSpeedCurve, onChangeCanvasColor, onChangeCanvasType, onChangeBlurLevel, onChangeMask, onChangeAnimationIn, onChangeAnimationOut, onChangeAnimationCombo, onChangeChromaKey }) => {

  const handleTransform = (key: keyof VideoTransform, value: number) => {
      onChangeTransform({ ...state.transform, [key]: value });
  };

  const handleAdjustment = (key: keyof VideoAdjustment, value: number) => {
      onChangeAdjustment({ ...state.adjustment, [key]: value });
  };

  const KeyframeButton = () => (
      <button className="text-slate-600 hover:text-amber-500 transition-colors" title="Add Keyframe">
          <Diamond className="w-3 h-3" />
      </button>
  );

  return (
    <div className="h-full bg-slate-950 flex flex-col">
        <div className="p-4 border-b border-slate-800">
             <h2 className="font-display font-bold text-white tracking-widest flex items-center gap-2">
                <Sliders className="w-4 h-4 text-purple-500" /> INSPECTOR
             </h2>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar">

            {/* Speed Section */}
            <div className="space-y-3">
                 <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 flex items-center gap-2">
                    <Gauge className="w-3 h-3" /> Speed
                </h3>
                <div className="flex gap-2 mb-2 bg-slate-900 p-1 rounded-lg">
                    <button 
                        onClick={() => onChangeSpeedType('normal')}
                        className={`flex-1 py-1.5 text-[10px] rounded transition-all ${state.speedType === 'normal' ? 'bg-slate-700 text-white font-bold' : 'text-slate-500 hover:text-slate-300'}`}
                    >
                        Normal
                    </button>
                    <button 
                         onClick={() => onChangeSpeedType('curve')}
                         className={`flex-1 py-1.5 text-[10px] rounded transition-all ${state.speedType === 'curve' ? 'bg-slate-700 text-white font-bold' : 'text-slate-500 hover:text-slate-300'}`}
                    >
                        Curve
                    </button>
                </div>

                {state.speedType === 'normal' ? (
                     <div className="flex gap-2 flex-wrap">
                        {[0.5, 1.0, 1.5, 2.0, 5.0].map(speed => (
                            <button 
                                key={speed}
                                onClick={() => onChangeSpeed(speed)}
                                className={`px-3 py-1 rounded text-xs font-mono border transition-all ${state.playbackSpeed === speed ? 'bg-purple-900/50 border-purple-500 text-purple-300' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-slate-600'}`}
                            >
                                {speed}x
                            </button>
                        ))}
                    </div>
                ) : (
                    <div className="grid grid-cols-3 gap-2">
                        {(['custom', 'montage', 'hero', 'bullet', 'jump'] as SpeedCurvePreset[]).map(curve => (
                             <button
                                key={curve}
                                onClick={() => onChangeSpeedCurve(curve)}
                                className={`flex flex-col items-center p-2 rounded border transition-all ${state.speedCurve === curve ? 'bg-purple-900/30 border-purple-500 text-purple-300' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-slate-600'}`}
                             >
                                 <Activity className="w-4 h-4 mb-1" />
                                 <span className="text-[9px] capitalize">{curve}</span>
                             </button>
                        ))}
                    </div>
                )}
            </div>

             <div className="h-[1px] bg-slate-800 w-full"></div>

            {/* Animation Section */}
            <div className="space-y-4">
                <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 flex items-center gap-2">
                    <PlaySquare className="w-3 h-3" /> Animation
                </h3>

                <div className="space-y-2">
                    <label className="text-[9px] text-slate-500 uppercase font-mono">In</label>
                    <div className="grid grid-cols-4 gap-2">
                        {['none', 'zoomIn', 'slideUp', 'fade', 'shake'].map(anim => (
                            <button
                                key={anim}
                                onClick={() => onChangeAnimationIn(anim as AnimationIn)}
                                className={`py-1.5 text-[9px] border rounded capitalize truncate transition-all ${state.animationIn === anim ? 'bg-purple-900/50 border-purple-500 text-purple-300' : 'bg-slate-900 border-slate-800 text-slate-400'}`}
                            >
                                {anim}
                            </button>
