                </div>

                <div className="space-y-2">
                    <label className="text-[9px] text-slate-500 uppercase font-mono">Out</label>
                    <div className="grid grid-cols-4 gap-2">
                        {['none', 'zoomOut', 'slideDown', 'fade'].map(anim => (
                            <button
                                key={anim}
                                onClick={() => onChangeAnimationOut(anim as AnimationOut)}
                                className={`py-1.5 text-[9px] border rounded capitalize truncate transition-all ${state.animationOut === anim ? 'bg-purple-900/50 border-purple-500 text-purple-300' : 'bg-slate-900 border-slate-800 text-slate-400'}`}
                            >
