import React from 'react';
import { VideoState, Sentiment } from '../types';
import { Scissors, Trash2, Magnet, Undo2, Redo2, ZoomIn, ZoomOut, Type, Music, Smile, Sparkles, FolderOpen, Zap } from 'lucide-react';

interface TimelineProps {
  state: VideoState;
  onSeek: (time: number) => void;
}

const SentimentColorMap: Record<Sentiment, string> = {
  neutral: 'bg-slate-600 border-slate-500',
  anger: 'bg-red-900/80 border-red-500',
  joy: 'bg-cyan-900/80 border-cyan-500',
  urgency: 'bg-amber-900/80 border-amber-500',
  proverb: 'bg-yellow-900/80 border-yellow-500',
  sarcasm: 'bg-pink-900/80 border-pink-500',
};

const Timeline: React.FC<TimelineProps> = ({ state, onSeek }) => {
  const percentage = (state.currentTime / state.duration) * 100;

  const handleTimelineClick = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const clickPercentage = x / rect.width;
    const newTime = Math.max(0, Math.min(state.duration, clickPercentage * state.duration));
    onSeek(newTime);
  };

  const TrackHeader = ({ icon: Icon, label, color }: { icon: any, label: string, color: string }) => (
      <div className="absolute left-2 top-1/2 -translate-y-1/2 flex items-center gap-1.5 z-10 pointer-events-none opacity-50 bg-slate-950/80 px-1.5 py-0.5 rounded border border-slate-800">
          <Icon className={`w-3 h-3 ${color}`} />
          <span className="text-[8px] font-mono text-slate-300 tracking-tighter">{label}</span>
      </div>
  );

  return (
    <div className="w-full h-full flex flex-col bg-slate-950 border-t border-slate-800 select-none">

      {/* Timeline Toolbar */}
      <div className="h-10 border-b border-slate-800 bg-slate-900 flex items-center justify-between px-4">
         <div className="flex items-center gap-2">
            <button className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-white transition-colors">
                <Scissors className="w-4 h-4" />
            </button>
            <button className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-white transition-colors">
                <Trash2 className="w-4 h-4" />
            </button>
            <div className="w-[1px] h-4 bg-slate-700 mx-1"></div>
            <button className="p-1.5 hover:bg-slate-800 rounded text-cyan-500" title="Magnet Mode">
                <Magnet className="w-4 h-4" />
            </button>
         </div>
         <div className="flex items-center gap-2">
            <button className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-white"><Undo2 className="w-4 h-4" /></button>
            <button className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-white"><Redo2 className="w-4 h-4" /></button>
            <div className="w-[1px] h-4 bg-slate-700 mx-1"></div>
            <ZoomOut className="w-3 h-3 text-slate-500" />
            <div className="w-20 h-1 bg-slate-800 rounded-full">
                <div className="w-1/3 h-full bg-slate-600 rounded-full"></div>
            </div>
            <ZoomIn className="w-3 h-3 text-slate-500" />
         </div>
      </div>

      {/* Time Markers */}
      <div className="h-6 flex items-center justify-between text-[10px] font-mono text-slate-500 px-4 border-b border-slate-800/50 bg-slate-900/30">
        <span>00:00</span>
        <span>{new Date(state.duration * 1000).toISOString().substr(14, 5)}</span>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar relative bg-slate-950/50">
        <div className="relative min-h-[400px] p-2" onClick={handleTimelineClick}>

            {/* Playhead Line */}
            <div 
                className="absolute top-0 bottom-0 w-[1px] bg-cyan-500 z-50 pointer-events-none shadow-[0_0_10px_rgba(6,182,212,0.8)]"
                style={{ left: `${percentage}%` }}
            >
                <div className="absolute -top-1 -left-[5px] w-0 h-0 border-l-[6px] border-l-transparent border-r-[6px] border-r-transparent border-t-[8px] border-t-cyan-500"></div>
            </div>

            {/* MAIN VIDEO TRACK */}
            <div className="mb-2 relative h-12 w-full bg-slate-900/50 rounded-lg border border-slate-800 overflow-hidden group hover:border-slate-700 transition-colors">
                 <TrackHeader icon={Zap} label="VIDEO_01" color="text-amber-500" />
                 <div className="absolute inset-0 flex items-center justify-center opacity-10">
                    <div className="w-full h-full bg-[repeating-linear-gradient(90deg,transparent,transparent_50px,rgba(255,255,255,0.05)_50px,rgba(255,255,255,0.05)_51px)]"></div>
                 </div>
            </div>

             {/* TRANSITION TRACK */}
             <div className="relative h-6 w-full mb-1 bg-slate-900/10 rounded border border-slate-800/30">
                <TrackHeader icon={Zap} label="TRANS" color="text-yellow-400" />
                {state.transitionTrack.map(trans => {
                     const left = (trans.startTime / state.duration) * 100;
                     const width = (trans.duration / state.duration) * 100;
                     return (
                         <div
                            key={trans.id}
                            className="absolute top-[1px] bottom-[1px] rounded-sm bg-yellow-500/40 border border-yellow-400/50 flex items-center justify-center cursor-pointer"
                            style={{ left: `${left}%`, width: `${width}%` }}
                         >
                            <span className="text-[7px] text-white font-bold uppercase">{trans.name}</span>
                         </div>
                     )
                })}
            </div>

             {/* OVERLAY TRACK (PIP) */}
             <div className="relative h-8 w-full mb-1 bg-slate-900/20 rounded border border-slate-800/50">
                <TrackHeader icon={FolderOpen} label="PIP_LAY" color="text-blue-500" />
                {state.overlayTrack.map(ov => {
                     const left = (ov.startTime / state.duration) * 100;
                     const width = (ov.duration / state.duration) * 100;
                     return (
                         <div
                            key={ov.id}
                            className="absolute top-[2px] bottom-[2px] rounded-sm bg-blue-900/60 border border-blue-500/50 text-[10px] flex items-center px-2 text-blue-100 overflow-hidden hover:brightness-125 cursor-pointer transition-all"
                            style={{ left: `${left}%`, width: `${width}%` }}
                         >
                            <span className="truncate">{ov.name}</span>
                         </div>
                     )
                })}
            </div>

            {/* MEANING / SPINE TRACK */}
            <div className="mb-2 relative h-10 w-full bg-slate-900/50 rounded-lg border border-slate-800 overflow-hidden">
                <TrackHeader icon={Star} label="SPINE" color="text-amber-500" />
                {state.meaningTrack.map((block) => {
                     const left = (block.startTime / state.duration) * 100;
                     const width = (block.duration / state.duration) * 100;
                     return (
                         <div 
                            key={block.id}
                            className={`absolute top-1 bottom-1 rounded border ${SentimentColorMap[block.sentiment]} flex items-center justify-center cursor-pointer hover:brightness-125 transition-all opacity-80`}
                            style={{ left: `${left}%`, width: `${width}%` }}
                         >
                            <span className="text-[9px] text-white/90 truncate px-1">{block.meaning}</span>
                         </div>
                     )
                })}
            </div>

            {/* TEXT TRACK */}
            <div className="relative h-8 w-full mt-2 bg-slate-900/20 rounded border border-slate-800/50">
                <TrackHeader icon={Type} label="TYPO" color="text-cyan-600" />
                {state.textTrack.map(txt => {
                     const left = (txt.startTime / state.duration) * 100;
                     const width = (txt.duration / state.duration) * 100;
                     return (
                         <div
                            key={txt.id}
                            className="absolute top-[2px] bottom-[2px] rounded-sm bg-cyan-900/60 border border-cyan-500/50 text-[9px] flex items-center px-2 text-cyan-100 overflow-hidden hover:brightness-125 cursor-pointer"
                            style={{ left: `${left}%`, width: `${width}%` }}
                         >
                            {txt.text}
                         </div>
                     )
                })}
            </div>

            {/* EFFECTS TRACK */}
            <div className="relative h-8 w-full mt-1 bg-slate-900/20 rounded border border-slate-800/50">
                <TrackHeader icon={Sparkles} label="SFX_V" color="text-pink-600" />
                {state.effectTrack.map(eff => {
                     const left = (eff.startTime / state.duration) * 100;
                     const width = (eff.duration / state.duration) * 100;
                     return (
                         <div
                            key={eff.id}
                            className="absolute top-[2px] bottom-[2px] rounded-sm bg-pink-900/60 border border-pink-500/50 text-[10px] flex items-center px-2 text-pink-100 overflow-hidden hover:brightness-125 cursor-pointer"
                            style={{ left: `${left}%`, width: `${width}%` }}
                         >
                            {eff.name}
                         </div>
                     )
                })}
            </div>

            {/* AUDIO TRACK */}
            <div className="relative h-8 w-full mt-1 bg-slate-900/20 rounded border border-slate-800/50">
                <TrackHeader icon={Music} label="AUDIO" color="text-purple-600" />
                {state.audioTrack.map(aud => {
                     const left = (aud.startTime / state.duration) * 100;
                     const width = (aud.duration / state.duration) * 100;
                     return (
                         <div
                            key={aud.id}
                            className="absolute top-[2px] bottom-[2px] rounded-sm bg-purple-900/60 border border-purple-500/50 text-[9px] flex items-center px-2 text-purple-100 overflow-hidden hover:brightness-125 cursor-pointer"
                            style={{ left: `${left}%`, width: `${width}%` }}
                         >
                            <span className="absolute left-2">{aud.name}</span>
                         </div>
                     )
                })}
            </div>

        </div>
      </div>
    </div>
  );
};

export default Timeline;

