             <div className="relative h-10 w-full mb-1 bg-slate-900/10 rounded border border-slate-800/30">
                <TrackHeader icon={FolderOpen} label="Overlays" color="text-blue-500" />
                {state.overlayTrack.map(ov => {
                     const left = (ov.startTime / state.duration) * 100;
                     const width = (ov.duration / state.duration) * 100;
                     return (
                         <div
                            key={ov.id}
                            className="absolute top-[2px] bottom-[2px] rounded-md bg-blue-900/40 border border-blue-500/30 text-[10px] flex items-center px-2 text-blue-100 overflow-hidden hover:brightness-110 transition-all"
                            style={{ left: `${left}%`, width: `${width}%` }}
