import React, { useState, useRef, useEffect } from 'react';
import { VideoState, Sentiment, Keyframe } from '../types';
import { Scissors, Trash2, Magnet, Undo2, Redo2, ZoomIn, ZoomOut, Type, Music, Smile, Sparkles, FolderOpen, Zap, Star, Diamond } from 'lucide-react';

interface TimelineProps {
  state: VideoState;
  onSeek: (time: number) => void;
  onSplit: () => void;
  onDelete: () => void;
  onTrim: (trackName: keyof VideoState, id: string, startTime: number, duration: number) => void;
}

const SentimentColorMap: Record<Sentiment, string> = {
  neutral: 'bg-slate-600 border-slate-500',
  anger: 'bg-red-900/80 border-red-500',
  joy: 'bg-cyan-900/80 border-cyan-500',
  urgency: 'bg-amber-900/80 border-amber-500',
  proverb: 'bg-yellow-900/80 border-yellow-500',
  sarcasm: 'bg-pink-900/80 border-pink-500',
};

const Timeline: React.FC<TimelineProps> = ({ state, onSeek, onSplit, onDelete, onTrim }) => {
  const percentage = (state.currentTime / state.duration) * 100;
  const timelineRef = useRef<HTMLDivElement>(null);

  const [dragState, setDragState] = useState<{
    trackName: keyof VideoState;
    id: string;
    edge: 'start' | 'end';
    initialMouseX: number;
    initialStartTime: number;
    initialDuration: number;
  } | null>(null);

  const handleTimelineClick = (e: React.MouseEvent<HTMLDivElement>) => {
    if ((e.target as HTMLElement).closest('.trim-handle')) return;

    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const clickPercentage = x / rect.width;
    const newTime = Math.max(0, Math.min(state.duration, clickPercentage * state.duration));
    onSeek(newTime);
  };

  const onStartTrim = (e: React.MouseEvent, trackName: keyof VideoState, id: string, edge: 'start' | 'end', startTime: number, duration: number) => {
    e.stopPropagation();
    setDragState({
      trackName,
      id,
      edge,
      initialMouseX: e.clientX,
      initialStartTime: startTime,
      initialDuration: duration
    });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragState || !timelineRef.current) return;

      const timelineWidth = timelineRef.current.getBoundingClientRect().width;
      const dx = ((e.clientX - dragState.initialMouseX) / timelineWidth) * state.duration;

      let newStartTime = dragState.initialStartTime;
      let newDuration = dragState.initialDuration;

      if (dragState.edge === 'start') {
        newStartTime = Math.max(0, dragState.initialStartTime + dx);
        newDuration = Math.max(0.1, dragState.initialDuration - (newStartTime - dragState.initialStartTime));
      } else {
        newDuration = Math.max(0.1, dragState.initialDuration + dx);
      }

      onTrim(dragState.trackName, dragState.id, newStartTime, newDuration);
    };

    const handleMouseUp = () => {
      setDragState(null);
    };

    if (dragState) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragState, state.duration, onTrim]);

  const TrackHeader = ({ icon: Icon, label, color }: { icon: any, label: string, color: string }) => (
    <div className="absolute left-2 top-1/2 -translate-y-1/2 flex items-center gap-1.5 z-10 pointer-events-none opacity-50 bg-slate-950/80 px-1.5 py-0.5 rounded border border-slate-800">
      <Icon className={`w-3 h-3 ${color}`} />
      <span className="text-[8px] font-mono text-slate-300 tracking-tighter uppercase">{label}</span>
    </div>
  );

  const renderClip = (item: any, trackName: keyof VideoState, className: string, children?: React.ReactNode) => {
    const left = (item.startTime / state.duration) * 100;
    const width = (item.duration / state.duration) * 100;
    const isSelected = state.currentTime >= item.startTime && state.currentTime <= item.startTime + item.duration;

    return (
      <div 
        key={item.id}
        className={`absolute top-1 bottom-1 rounded border overflow-visible cursor-pointer group transition-all ${isSelected ? 'ring-2 ring-amber-500 z-30 brightness-110 shadow-[0_0_15px_rgba(245,158,11,0.3)]' : 'hover:brightness-110'} ${className}`}
        style={{ left: `${left}%`, width: `${width}%` }}
      >
        <div 
          className="trim-handle absolute left-0 top-0 bottom-0 w-2 bg-white/30 hover:bg-white/60 cursor-ew-resize opacity-0 group-hover:opacity-100 transition-opacity z-10 rounded-l"
          onMouseDown={(e) => onStartTrim(e, trackName, item.id, 'start', item.startTime, item.duration)}
        />

        {children}

        <div 
          className="trim-handle absolute right-0 top-0 bottom-0 w-2 bg-white/30 hover:bg-white/60 cursor-ew-resize opacity-0 group-hover:opacity-100 transition-opacity z-10 rounded-r"
          onMouseDown={(e) => onStartTrim(e, trackName, item.id, 'end', item.startTime, item.duration)}
        />
      </div>
    );
  };

  return (
    <div className="w-full h-full flex flex-col bg-slate-950 border-t border-slate-800 select-none">
      <div className="h-10 border-b border-slate-800 bg-slate-900 flex items-center justify-between px-4">
         <div className="flex items-center gap-2">
            <button 
                onClick={onSplit}
                className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-white transition-all flex items-center gap-1.5 px-3 group"
                title="Split (B)"
            >
                <Scissors className="w-4 h-4 group-hover:rotate-12 transition-transform" />
                <span className="text-[10px] font-bold">Split</span>
            </button>
            <button 
                onClick={onDelete}
                className="p-1.5 hover:bg-slate-800 rounded text-slate-400 hover:text-red-500 transition-all flex items-center gap-1.5 px-3 group"
                title="Delete (Backspace)"
            >
                <Trash2 className="w-4 h-4 group-hover:scale-110 transition-transform" />
                <span className="text-[10px] font-bold">Delete</span>
            </button>
            <div className="w-[1px] h-4 bg-slate-700 mx-1"></div>
            <button className="p-1.5 hover:bg-slate-800 rounded text-cyan-500" title="Snap Mode">
                <Magnet className="w-4 h-4" />
            </button>
         </div>
         <div className="flex items-center gap-2">
            <div className="text-[10px] font-mono text-slate-400 mr-2 bg-slate-950 px-2 py-0.5 rounded border border-slate-800">
                {new Date(state.currentTime * 1000).toISOString().substr(14, 9)} / {new Date(state.duration * 1000).toISOString().substr(14, 5)}
            </div>
            <div className="w-[1px] h-4 bg-slate-700 mx-1"></div>
            <ZoomOut className="w-3 h-3 text-slate-500" />
            <div className="w-20 h-1 bg-slate-800 rounded-full">
                <div className="w-1/3 h-full bg-slate-600 rounded-full"></div>
            </div>
            <ZoomIn className="w-3 h-3 text-slate-500" />
         </div>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar relative bg-slate-950">
        <div className="relative min-h-[500px] p-2" ref={timelineRef} onClick={handleTimelineClick}>
            <div 
                className="absolute top-0 bottom-0 w-[1px] bg-cyan-500 z-50 pointer-events-none shadow-[0_0_15px_rgba(6,182,212,1)]"
                style={{ left: `${percentage}%` }}
            >
                <div className="absolute -top-1 -left-[5px] w-0 h-0 border-l-[6px] border-l-transparent border-r-[6px] border-r-transparent border-t-[8px] border-t-cyan-500"></div>
            </div>

            <div className="mb-2 relative h-14 w-full bg-slate-900/30 rounded-lg border border-slate-800 overflow-hidden group hover:border-slate-700 transition-colors">
                 <TrackHeader icon={Zap} label="Video" color="text-amber-500" />
                 {Object.entries(state.transform.keyframes).map(([prop, keys]) => (
                     (keys as Keyframe[]).map(k => (
                         <div 
                            key={k.id} 
                            className="absolute bottom-1 w-2 h-2 bg-amber-500 rotate-45 z-40 border border-white/20 shadow-[0_0_5px_rgba(245,158,11,0.5)]"
                            style={{ left: `${(k.time / state.duration) * 100}%` }}
                         />
                     ))
                 ))}
                 <div className="absolute inset-0 flex items-center justify-center opacity-5">
                    <div className="w-full h-full bg-[repeating-linear-gradient(90deg,transparent,transparent_50px,rgba(255,255,255,0.05)_50px,rgba(255,255,255,0.05)_51px)]"></div>
                 </div>
            </div>

             <div className="relative h-10 w-full mb-1 bg-slate-900/10 rounded border border-slate-800/30">
                <TrackHeader icon={FolderOpen} label="Overlays" color="text-blue-500" />
                {state.overlayTrack.map(ov => renderClip(ov, 'overlayTrack', 'bg-blue-900/40 border-blue-500/30 text-blue-100', 
                    <span className="truncate px-2 text-[10px]">{ov.name}</span>
                ))}
            </div>

            <div className="mb-4 relative h-12 w-full bg-slate-900/20 rounded-lg border border-slate-800">
                <TrackHeader icon={Star} label="Meaning" color="text-amber-500" />
                {state.meaningTrack.map((block) => renderClip(block, 'meaningTrack', `${SentimentColorMap[block.sentiment]} opacity-90`,
                    <span className="text-[10px] text-white font-bold truncate px-2 w-full text-center">{block.meaning}</span>
                ))}
            </div>

            <div className="relative h-10 w-full mb-1 bg-slate-900/10 rounded border border-slate-800/20">
                <TrackHeader icon={Type} label="Typography" color="text-cyan-500" />
                {state.textTrack.map(txt => renderClip(txt, 'textTrack', 'bg-cyan-900/30 border-cyan-500/40 text-cyan-50',
                    <span className="truncate px-2 text-[10px]">{txt.text}</span>
                ))}
            </div>

            <div className="relative h-10 w-full mb-1 bg-slate-900/10 rounded border border-slate-800/20">
                <TrackHeader icon={Music} label="Audio" color="text-purple-500" />
                {state.audioTrack.map(aud => renderClip(aud, 'audioTrack', `${aud.type === 'music' ? 'bg-purple-900/30 border-purple-500/40' : 'bg-emerald-900/30 border-emerald-500/40'}`,
                    <>
                        {aud.type === 'music' && (
                            <div className="w-full flex items-end gap-0.5 opacity-20 h-full py-1">
                                {Array.from({length: 40}).map((_, i) => (
                                    <div key={i} className="flex-1 bg-purple-300" style={{ height: `${Math.random() * 80 + 20}%` }}></div>
                                ))}
                            </div>
                        )}
                        <span className="absolute left-2 text-[9px] text-white font-bold pointer-events-none truncate">{aud.name}</span>
                    </>
                ))}
            </div>
        </div>
      </div>
    </div>
  );
};

export default Timeline;

import React, { useState, useEffect, useRef } from 'react';
import { INITIAL_VIDEO_STATE, INITIAL_CHAT_MESSAGE } from './constants';
import { VideoState, ChatMessage, ToolNames, ToolArgs, LanguageLayer, SimulationMode, EditorMode, RightPanelTab, VideoTransform, VideoAdjustment, TextAnimation, EffectType, TransitionType, AnimationIn, AnimationOut, AnimationCombo, CanvasType, BlurLevel, ChromaKey, SpeedType, SpeedCurvePreset, VoiceEffect, Keyframe, TextBlock, AudioBlock, StickerBlock, EffectBlock, OverlayBlock } from './types';
import VideoPlayer from './components/VideoPlayer';
import Timeline from './components/Timeline';
import AIChat from './components/AIChat';
import EditorSidebar from './components/EditorSidebar';
import PropertiesPanel from './components/PropertiesPanel';
import { createGeminiSession } from './services/geminiService';
import { Settings2, MessageSquare, ChevronLeft, ChevronRight, Share2, Download } from 'lucide-react';
import { Chat } from '@google/genai';

const App: React.FC = () => {
  const [videoState, setVideoState] = useState<VideoState>({ ...INITIAL_VIDEO_STATE });
  const [rightPanel, setRightPanel] = useState<RightPanelTab>('chat');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'init', role: 'model', content: INITIAL_CHAT_MESSAGE }
  ]);
  const [isProcessing, setIsProcessing] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);

  useEffect(() => {
    chatSessionRef.current = createGeminiSession();

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (e.key.toLowerCase() === 'b') handleSplit();
      if (e.key === 'Delete' || e.key === 'Backspace') handleDelete();
      if (e.key === ' ') {
        e.preventDefault();
        setVideoState(prev => ({ ...prev, isPlaying: !prev.isPlaying }));
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handleSplit = () => {
    setVideoState(prev => {
      const { currentTime } = prev;
      const newState = { ...prev };
      const splitTrack = <T extends { id: string, startTime: number, duration: number }>(track: T[]) => {
        const index = track.findIndex(m => currentTime > m.startTime && currentTime < m.startTime + m.duration);
        if (index === -1) return track;
        const original = track[index];
        const firstPart = { ...original, duration: currentTime - original.startTime };
        const secondPart = { ...original, id: Math.random().toString(36), startTime: currentTime, duration: original.duration - (currentTime - original.startTime) };
        const newTrack = [...track];
        newTrack.splice(index, 1, firstPart, secondPart);
        return newTrack;
      };
      newState.meaningTrack = splitTrack(prev.meaningTrack);
      newState.textTrack = splitTrack(prev.textTrack);
      newState.audioTrack = splitTrack(prev.audioTrack);
      newState.effectTrack = splitTrack(prev.effectTrack);
      newState.overlayTrack = splitTrack(prev.overlayTrack);
      return newState;
    });
  };

  const handleTrim = (trackName: keyof VideoState, id: string, startTime: number, duration: number) => {
    setVideoState(prev => {
      const track = prev[trackName] as any[];
      if (!Array.isArray(track)) return prev;
      const newTrack = track.map(item => 
        item.id === id ? { ...item, startTime, duration: Math.max(0.1, duration) } : item
      );
      return { ...prev, [trackName]: newTrack };
    });
  };

  const handleDelete = () => {
    setVideoState(prev => {
      const { currentTime } = prev;
      const filterItem = (item: { startTime: number, duration: number }) => 
        currentTime < item.startTime || currentTime > item.startTime + item.duration;
      return {
        ...prev,
        meaningTrack: prev.meaningTrack.filter(filterItem),
        textTrack: prev.textTrack.filter(filterItem),
        audioTrack: prev.audioTrack.filter(filterItem),
        effectTrack: prev.effectTrack.filter(filterItem),
        overlayTrack: prev.overlayTrack.filter(filterItem),
        transitionTrack: prev.transitionTrack.filter(filterItem),
      };
    });
  };

  const handleAddText = (styleId: string, animation: string = 'pop') => {
    const newText: TextBlock = {
      id: Math.random().toString(36),
      text: styleId === 'sub' ? 'New Subtitle' : 'NEW TITLE',
      startTime: videoState.currentTime,
      duration: 3,
      animation: animation as TextAnimation,
      style: {
        fontFamily: 'Inter',
        fontSize: styleId === 'sub' ? 24 : 64,
        color: '#ffffff',
        x: 50,
        y: styleId === 'sub' ? 85 : 50,
        opacity: 1,
        shadow: 'none'
      }
    };
    setVideoState(prev => ({ ...prev, textTrack: [...prev.textTrack, newText] }));
  };

  const handleAddAudio = (trackName: string) => {
    const newAudio: AudioBlock = {
      id: Math.random().toString(36),
      name: trackName,
      startTime: videoState.currentTime,
      duration: 5,
      volume: 0.8,
      type: trackName.includes('Beat') ? 'music' : 'sfx'
    };
    setVideoState(prev => ({ ...prev, audioTrack: [...prev.audioTrack, newAudio] }));
  };

  const handleAddSticker = (content: string) => {
    const newSticker: StickerBlock = {
      id: Math.random().toString(36),
      content,
      startTime: videoState.currentTime,
      duration: 2,
      x: 50,
      y: 50,
      scale: 1,
      loopAnimation: 'none'
    };
    setVideoState(prev => ({ ...prev, stickerTrack: [...prev.stickerTrack, newSticker] }));
  };

  const handleAddEffect = (type: EffectType, name: string) => {
    const newEffect: EffectBlock = {
      id: Math.random().toString(36),
      type,
      name,
      startTime: videoState.currentTime,
      duration: 4
    };
    setVideoState(prev => ({ ...prev, effectTrack: [...prev.effectTrack, newEffect] }));
  };

  const handleAddOverlay = (src: string, type: 'image' | 'video') => {
    const newOverlay: OverlayBlock = {
      id: Math.random().toString(36),
      type,
      src,
      name: 'Layer ' + (videoState.overlayTrack.length + 1),
      startTime: videoState.currentTime,
      duration: 5,
      x: 50,
      y: 50,
      scale: 0.5,
      rotation: 0,
      opacity: 0.8
    };
    setVideoState(prev => ({ ...prev, overlayTrack: [...prev.overlayTrack, newOverlay] }));
  };

  const handleToggleKeyframe = (prop: string) => {
    setVideoState(prev => {
      const currentKeys = prev.transform.keyframes[prop] || [];
      const existingIndex = currentKeys.findIndex(k => Math.abs(k.time - prev.currentTime) < 0.1);
      let newKeys: Keyframe[];
      if (existingIndex !== -1) {
        newKeys = currentKeys.filter((_, i) => i !== existingIndex);
      } else {
        const val = prev.transform[prop as keyof VideoTransform] as number;
        newKeys = [...currentKeys, { id: Math.random().toString(36), time: prev.currentTime, value: val }].sort((a,b) => a.time - b.time);
      }
      return {
        ...prev,
        transform: {
          ...prev.transform,
          keyframes: { ...prev.transform.keyframes, [prop]: newKeys }
        }
      };
    });
  };

  const handleSendMessage = async (userMessage: string) => {
    if (!chatSessionRef.current) return;
    setIsProcessing(true);
    setMessages(prev => [...prev, { id: Date.now().toString(), role: 'user', content: userMessage }]);
    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMessage });
      const functionCalls = result.functionCalls;
      if (functionCalls && functionCalls.length > 0) {
        const responses: any[] = [];
        for (const call of functionCalls) {
          const toolName = call.name;
          const args = call.args as ToolArgs;
          let responseResult = { result: "Success" };
          switch (toolName) {
            case ToolNames.ADD_LANGUAGE:
              const newLayer: LanguageLayer = {
                id: `target-${args.language.toLowerCase()}`,
                name: args.language,
                code: args.language.substr(0,2).toLowerCase(),
                type: 'target',
                isVisible: true,
                blocks: videoState.meaningTrack.map(m => ({
                  id: Math.random().toString(36),
                  parentId: m.id,
                  text: `[${args.language} Analysis]`,
                  language: args.language,
                  isLiteral: false,
                  confidence: 0.9
                }))
              };
              setVideoState(prev => ({ ...prev, languageLayers: [...prev.languageLayers, newLayer], activeLanguageId: newLayer.id }));
              responseResult = { result: `Node '${args.language}' synchronized.` };
              break;
            case ToolNames.SET_TONE:
              setVideoState(prev => ({ ...prev, meaningTrack: prev.meaningTrack.map(b => b.id === args.blockId ? { ...b, sentiment: args.sentiment } : b) }));
              responseResult = { result: `Tone modulated.` };
              break;
          }
          responses.push({ name: toolName, response: responseResult, id: call.id });
        }
        const finalResponse = await chatSessionRef.current.sendToolResponse({ functionResponses: responses });
        if (finalResponse.text) setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: finalResponse.text }]);
      } else if (result.text) {
        setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: result.text }]);
      }
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: "Engine sync error." }]);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-black text-slate-400 selection:bg-blue-500/30">
      <EditorSidebar 
        state={videoState}
        onSetMode={(mode) => setVideoState(prev => ({ ...prev, activeMode: mode }))}
        onToggleLayer={(id) => setVideoState(prev => ({ ...prev, languageLayers: prev.languageLayers.map(l => l.id === id ? { ...l, isVisible: !l.isVisible } : l) }))}
        onSetActiveLayer={(id) => setVideoState(prev => ({ ...prev, activeLanguageId: id }))}
        onAddText={handleAddText} 
        onAddAudio={handleAddAudio}
        onAddSticker={handleAddSticker}
        onAddEffect={handleAddEffect}
        onAddOverlay={handleAddOverlay}
        onAddTransition={(t, n) => setVideoState(prev => ({...prev, transitionTrack: [...prev.transitionTrack, { id: Math.random().toString(), type: t, name: n, startTime: prev.currentTime, duration: 1 }]}))}
        onAutoCaption={() => {}}
        onChangeRatio={(r) => setVideoState(prev => ({ ...prev, aspectRatio: r }))}
        onSetFilter={(f) => setVideoState(prev => ({ ...prev, activeFilter: f }))}
      />

      <div className="flex-1 flex flex-col min-w-0 relative">
        <div className="h-12 border-b border-[#1a1a1a] flex items-center justify-between px-6 bg-black z-30">
          <div className="flex items-center gap-8">
            <h1 className="font-display font-bold text-xs text-white uppercase tracking-[0.3em]">ORÍ <span className="text-slate-500">ENGINE</span></h1>
            <div className="flex items-center gap-4 border-l border-[#1a1a1a] pl-8">
              <button className="text-slate-600 hover:text-white transition-colors"><ChevronLeft className="w-4 h-4" /></button>
              <span className="text-[9px] font-mono tracking-widest text-slate-500 uppercase">Master_Sequence_01</span>
              <button className="text-slate-600 hover:text-white transition-colors"><ChevronRight className="w-4 h-4" /></button>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 bg-[#0a0a0a] rounded border border-[#1a1a1a] p-0.5">
              {(['native', 'global', 'learner'] as SimulationMode[]).map(mode => (
                <button key={mode} onClick={() => setVideoState(prev => ({...prev, simulationMode: mode}))} 
                  className={`px-3 py-1 rounded text-[8px] font-bold uppercase transition-all ${videoState.simulationMode === mode ? 'bg-white text-black' : 'text-slate-600 hover:text-slate-300'}`}>
                  {mode}
                </button>
              ))}
            </div>
            <div className="flex items-center gap-2 ml-4">
                <button className="p-1.5 text-slate-500 hover:text-white"><Share2 className="w-4 h-4" /></button>
                <button className="px-4 py-1.5 bg-blue-600 text-white text-[9px] font-black tracking-widest rounded hover:bg-blue-500 transition-all flex items-center gap-2 uppercase"><Download className="w-3 h-3" /> Export</button>
            </div>
          </div>
        </div>

        <div className="flex-1 flex justify-center items-center bg-black overflow-hidden relative">
          <VideoPlayer state={videoState} onTimeUpdate={(t) => setVideoState(prev => ({...prev, currentTime: t}))} onDurationChange={() => {}} onTogglePlay={() => setVideoState(prev => ({...prev, isPlaying: !prev.isPlaying}))} />
        </div>

        <div className="h-72 border-t border-[#1a1a1a] bg-black z-20">
          <Timeline 
            state={videoState} 
            onSeek={(t) => setVideoState(prev => ({...prev, currentTime: t}))} 
            onSplit={handleSplit}
            onDelete={handleDelete}
            onTrim={handleTrim}
          />
        </div>
      </div>

      <div className="w-72 border-l border-[#1a1a1a] bg-black flex flex-col z-30">
         <div className="flex border-b border-[#1a1a1a]">
           <button onClick={() => setRightPanel('properties')} className={`flex-1 py-3 text-[9px] font-black tracking-widest flex items-center justify-center gap-2 transition-all ${rightPanel === 'properties' ? 'text-white border-b border-white bg-[#0a0a0a]' : 'text-slate-600 hover:bg-[#0a0a0a]'}`}><Settings2 className="w-3.5 h-3.5" /> INSPECTOR</button>
           <button onClick={() => setRightPanel('chat')} className={`flex-1 py-3 text-[9px] font-black tracking-widest flex items-center justify-center gap-2 transition-all ${rightPanel === 'chat' ? 'text-white border-b border-white bg-[#0a0a0a]' : 'text-slate-600 hover:bg-[#0a0a0a]'}`}><MessageSquare className="w-3.5 h-3.5" /> AI NODE</button>
         </div>
         <div className="flex-1 overflow-hidden">
           {rightPanel === 'chat' ? (
            <AIChat messages={messages} onSendMessage={handleSendMessage} isProcessing={isProcessing} />
           ) : (
            <PropertiesPanel 
              state={videoState}
              onChangeTransform={(t) => setVideoState(prev => ({...prev, transform: t}))}
              onChangeAdjustment={(a) => setVideoState(prev => ({...prev, adjustment: a}))}
              onChangeSpeed={(s) => setVideoState(prev => ({...prev, playbackSpeed: s}))}
              onChangeSpeedType={(t) => setVideoState(prev => ({...prev, speedType: t}))}
              onChangeSpeedCurve={(c) => setVideoState(prev => ({...prev, speedCurve: c}))}
              onChangeCanvasColor={(c) => setVideoState(prev => ({...prev, canvasColor: c}))}
              onChangeCanvasType={(t) => setVideoState(prev => ({...prev, canvasType: t}))}
              onChangeBlurLevel={(l) => setVideoState(prev => ({...prev, canvasBlurLevel: l}))}
              onChangeMask={(m) => setVideoState(prev => ({...prev, mask: m}))}
              onChangeAnimationIn={(a) => setVideoState(prev => ({...prev, animationIn: a as AnimationIn}))}
              onChangeAnimationOut={(a) => setVideoState(prev => ({...prev, animationOut: a as AnimationOut}))}
              onChangeAnimationCombo={(a) => setVideoState(prev => ({...prev, animationCombo: a as AnimationCombo}))}
              onChangeChromaKey={(c) => setVideoState(prev => ({...prev, chromaKey: c}))}
              onChangeVoiceFX={(f) => setVideoState(prev => ({...prev, voiceEffect: f}))}
              onToggleKeyframe={handleToggleKeyframe}
            />
           )}
         </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { VideoState, Sentiment, Keyframe } from '../types';
import { Scissors, Trash2, Magnet, ZoomIn, ZoomOut, Type, Music, FolderOpen, Zap, Star, Diamond } from 'lucide-react';

interface TimelineProps {
  state: VideoState;
  onSeek: (time: number) => void;
  onSplit: () => void;
  onDelete: () => void;
  onTrim: (trackName: keyof VideoState, id: string, startTime: number, duration: number) => void;
}

const SentimentColorMap: Record<Sentiment, string> = {
  neutral: 'border-slate-800',
  anger: 'border-l-red-500',
  joy: 'border-l-cyan-400',
  urgency: 'border-l-amber-500',
  proverb: 'border-l-white',
  sarcasm: 'border-l-pink-400',
};

const Timeline: React.FC<TimelineProps> = ({ state, onSeek, onSplit, onDelete, onTrim }) => {
  const percentage = (state.currentTime / state.duration) * 100;
  const timelineRef = useRef<HTMLDivElement>(null);

  const [dragState, setDragState] = useState<{
    trackName: keyof VideoState;
    id: string;
    edge: 'start' | 'end';
    initialMouseX: number;
    initialStartTime: number;
    initialDuration: number;
  } | null>(null);

  const handleTimelineClick = (e: React.MouseEvent<HTMLDivElement>) => {
    if ((e.target as HTMLElement).closest('.trim-handle')) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const clickPercentage = x / rect.width;
    const newTime = Math.max(0, Math.min(state.duration, clickPercentage * state.duration));
    onSeek(newTime);
  };

  const onStartTrim = (e: React.MouseEvent, trackName: keyof VideoState, id: string, edge: 'start' | 'end', startTime: number, duration: number) => {
    e.stopPropagation();
    setDragState({
      trackName,
      id,
      edge,
      initialMouseX: e.clientX,
      initialStartTime: startTime,
      initialDuration: duration
    });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragState || !timelineRef.current) return;
      const timelineWidth = timelineRef.current.getBoundingClientRect().width;
      const dx = ((e.clientX - dragState.initialMouseX) / timelineWidth) * state.duration;
      let newStartTime = dragState.initialStartTime;
      let newDuration = dragState.initialDuration;
      if (dragState.edge === 'start') {
        newStartTime = Math.max(0, dragState.initialStartTime + dx);
        newDuration = Math.max(0.1, dragState.initialDuration - (newStartTime - dragState.initialStartTime));
      } else {
        newDuration = Math.max(0.1, dragState.initialDuration + dx);
      }
      onTrim(dragState.trackName, dragState.id, newStartTime, newDuration);
    };
    const handleMouseUp = () => setDragState(null);
    if (dragState) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragState, state.duration, onTrim]);

  const TrackHeader = ({ icon: Icon, label }: { icon: any, label: string }) => (
    <div className="absolute left-2 top-1/2 -translate-y-1/2 flex items-center gap-1.5 z-10 pointer-events-none opacity-40 bg-black/80 px-1.5 py-0.5 rounded border border-[#1a1a1a]">
      <Icon className="w-2.5 h-2.5 text-slate-400" />
      <span className="text-[7px] font-mono text-slate-400 tracking-tighter uppercase">{label}</span>
    </div>
  );

  const renderClip = (item: any, trackName: keyof VideoState, className: string, children?: React.ReactNode) => {
    const left = (item.startTime / state.duration) * 100;
    const width = (item.duration / state.duration) * 100;
    const isSelected = state.currentTime >= item.startTime && state.currentTime <= item.startTime + item.duration;

    return (
      <div 
        key={item.id}
        className={`absolute top-1 bottom-1 rounded border-y border-r overflow-visible cursor-pointer group transition-all bg-[#0d0d0d] border-[#1a1a1a] ${isSelected ? 'ring-1 ring-white/50 z-30 brightness-125' : 'hover:bg-[#151515]'} ${className}`}
        style={{ left: `${left}%`, width: `${width}%` }}
      >
        <div 
          className="trim-handle absolute left-0 top-0 bottom-0 w-1 bg-white/20 hover:bg-white/40 cursor-ew-resize opacity-0 group-hover:opacity-100 transition-opacity z-10 rounded-l"
          onMouseDown={(e) => onStartTrim(e, trackName, item.id, 'start', item.startTime, item.duration)}
        />
        <div className="flex items-center h-full px-2 overflow-hidden pointer-events-none">
            {children}
        </div>
        <div 
          className="trim-handle absolute right-0 top-0 bottom-0 w-1 bg-white/20 hover:bg-white/40 cursor-ew-resize opacity-0 group-hover:opacity-100 transition-opacity z-10 rounded-r"
          onMouseDown={(e) => onStartTrim(e, trackName, item.id, 'end', item.startTime, item.duration)}
        />
      </div>
    );
  };

  return (
    <div className="w-full h-full flex flex-col bg-black border-t border-[#1a1a1a] select-none">
      <div className="h-10 border-b border-[#1a1a1a] bg-black flex items-center justify-between px-4">
         <div className="flex items-center gap-1">
            <button onClick={onSplit} className="p-2 hover:bg-[#0a0a0a] rounded text-slate-500 hover:text-white transition-all flex items-center gap-2 px-3 border border-transparent hover:border-[#1a1a1a]"><Scissors className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Split</span></button>
            <button onClick={onDelete} className="p-2 hover:bg-[#0a0a0a] rounded text-slate-500 hover:text-red-500 transition-all flex items-center gap-2 px-3 border border-transparent hover:border-[#1a1a1a]"><Trash2 className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Delete</span></button>
            <div className="w-[1px] h-4 bg-[#1a1a1a] mx-2"></div>
            <button className="p-2 text-blue-500/50 hover:text-blue-500"><Magnet className="w-3.5 h-3.5" /></button>
         </div>
         <div className="flex items-center gap-4">
            <div className="text-[9px] font-mono text-slate-600 bg-black px-2 py-0.5 rounded border border-[#1a1a1a] tracking-widest">
                {new Date(state.currentTime * 1000).toISOString().substr(14, 9)} / {new Date(state.duration * 1000).toISOString().substr(14, 5)}
            </div>
            <div className="flex items-center gap-2">
                <ZoomOut className="w-3 h-3 text-slate-700" />
                <div className="w-16 h-[1px] bg-[#1a1a1a]"><div className="w-1/3 h-full bg-slate-600"></div></div>
                <ZoomIn className="w-3 h-3 text-slate-700" />
            </div>
         </div>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar relative bg-black">
        <div className="relative min-h-[400px] p-2" ref={timelineRef} onClick={handleTimelineClick}>
            <div className="absolute top-0 bottom-0 w-[1px] bg-white/80 z-50 pointer-events-none" style={{ left: `${percentage}%` }}>
                <div className="absolute -top-1 -left-[3px] w-1.5 h-1.5 bg-white rounded-full"></div>
            </div>

            <div className="mb-2 relative h-12 w-full bg-[#050505] rounded-sm border border-[#1a1a1a] overflow-hidden group hover:border-[#2a2a2a] transition-colors">
                 <TrackHeader icon={Zap} label="Scene" />
                 {Object.entries(state.transform.keyframes).map(([prop, keys]) => (
                     (keys as Keyframe[]).map(k => (
                         <div key={k.id} className="absolute bottom-1 w-1.5 h-1.5 bg-white rotate-45 z-40 border border-black shadow-[0_0_5px_rgba(255,255,255,0.3)]" style={{ left: `${(k.time / state.duration) * 100}%` }} />
                     ))
                 ))}
                 <div className="absolute inset-0 opacity-[0.03] bg-[repeating-linear-gradient(90deg,transparent,transparent_49px,#fff_50px)]"></div>
            </div>

             <div className="relative h-9 w-full mb-1 bg-[#050505] rounded-sm border border-[#1a1a1a]">
                <TrackHeader icon={FolderOpen} label="Overlays" />
                {state.overlayTrack.map(ov => renderClip(ov, 'overlayTrack', '', <span className="truncate text-[8px] uppercase tracking-widest text-slate-400">{ov.name}</span>))}
            </div>

            <div className="mb-2 relative h-10 w-full bg-[#050505] rounded-sm border border-[#1a1a1a]">
                <TrackHeader icon={Star} label="Meaning" />
                {state.meaningTrack.map((block) => renderClip(block, 'meaningTrack', `border-l-2 ${SentimentColorMap[block.sentiment]}`,
                    <span className="text-[8px] text-slate-300 font-bold uppercase tracking-wider truncate text-center w-full">{block.meaning}</span>
                ))}
            </div>

            <div className="relative h-9 w-full mb-1 bg-[#050505] rounded-sm border border-[#1a1a1a]">
                <TrackHeader icon={Type} label="Typography" />
                {state.textTrack.map(txt => renderClip(txt, 'textTrack', '', <span className="truncate text-[8px] uppercase tracking-widest text-slate-400">{txt.text}</span>))}
            </div>

            <div className="relative h-9 w-full mb-1 bg-[#050505] rounded-sm border border-[#1a1a1a]">
                <TrackHeader icon={Music} label="Audio" />
                {state.audioTrack.map(aud => renderClip(aud, 'audioTrack', '', <span className="truncate text-[8px] uppercase tracking-widest text-slate-500">{aud.name}</span>))}
            </div>
        </div>
      </div>
    </div>
  );
};

