import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { Send, Terminal } from 'lucide-react';

interface AIChatProps {
  messages: ChatMessage[];
  onSendMessage: (message: string) => void;
  isProcessing: boolean;
}

const AIChat: React.FC<AIChatProps> = ({ messages, onSendMessage, isProcessing }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !isProcessing) {
      onSendMessage(input);
      setInput('');
    }
  };

  return (
    <div className="flex flex-col h-full bg-black">
      <div className="p-4 border-b border-[#1a1a1a] flex items-center gap-3">
        <Terminal className="w-4 h-4 text-white" />
        <span className="text-[10px] font-black text-white tracking-[0.3em] uppercase">Tactical_Intelligence</span>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar" ref={scrollRef}>
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-3 rounded border text-[11px] leading-relaxed tracking-wide ${
                msg.role === 'user'
                  ? 'bg-white text-black border-white'
                  : 'bg-[#0a0a0a] text-slate-400 border-[#1a1a1a]'
              }`}>
                {msg.isFunctionCall ? (
                    <span className="animate-pulse flex items-center gap-2 text-[9px] font-mono">
                        <span className="w-1 h-1 bg-white rounded-full"></span> DATA_FETCHING...
                    </span>
                ) : (
                    msg.content.split('\n').map((line, i) => <p key={i} className="mb-1 last:mb-0">{line}</p>)
                )}
            </div>
          </div>
        ))}
        {isProcessing && (
          <div className="flex justify-start">
             <div className="flex gap-1 p-2">
                <span className="w-1 h-1 bg-white rounded-full animate-bounce"></span>
                <span className="w-1 h-1 bg-white rounded-full animate-bounce delay-75"></span>
                <span className="w-1 h-1 bg-white rounded-full animate-bounce delay-150"></span>
              </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="p-4 bg-black border-t border-[#1a1a1a]">
        <div className="relative flex items-center">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Command Node..."
            className="w-full bg-[#0a0a0a] border border-[#1a1a1a] text-white rounded px-3 py-2 text-[10px] focus:outline-none focus:border-white transition-all font-mono"
            disabled={isProcessing}
          />
          <button type="submit" disabled={!input.trim() || isProcessing} className="absolute right-2 text-slate-500 hover:text-white disabled:opacity-0 transition-opacity">
            <Send className="w-3.5 h-3.5" />
          </button>
        </div>
      </form>
    </div>
  );
};

export default AIChat;

import React, { useRef, useEffect } from 'react';
import { VideoState, Sentiment, EffectType, TransitionType } from '../types';
import { SAMPLE_VIDEO_URL } from '../constants';
import { Play, Pause } from 'lucide-react';

interface VideoPlayerProps {
  state: VideoState;
  onTimeUpdate: (time: number) => void;
  onDurationChange: (duration: number) => void;
  onTogglePlay: () => void;
}

const getSentimentStyles = (sentiment: Sentiment) => {
  switch (sentiment) {
    case 'anger': return 'text-red-500 font-bold tracking-tighter uppercase';
    case 'proverb': return 'text-white italic font-light tracking-wide';
    default: return 'text-white font-medium';
  }
};

const VideoPlayer: React.FC<VideoPlayerProps> = ({ state, onTimeUpdate, onDurationChange, onTogglePlay }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if (videoRef.current) {
      if (state.isPlaying && videoRef.current.paused) {
        videoRef.current.play().catch(() => {});
      } else if (!state.isPlaying && !videoRef.current.paused) {
        videoRef.current.pause();
      }
    }
  }, [state.isPlaying]);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.volume = state.volume;
      videoRef.current.playbackRate = state.playbackSpeed;
    }
  }, [state.volume, state.playbackSpeed]);

  useEffect(() => {
    if (videoRef.current && Math.abs(videoRef.current.currentTime - state.currentTime) > 0.5) {
      videoRef.current.currentTime = state.currentTime;
    }
  }, [state.currentTime]);

  const activeLayer = state.languageLayers.find(l => l.id === state.activeLanguageId);
  const activeBlock = activeLayer?.blocks.find(b => {
    const meaning = state.meaningTrack.find(m => m.id === b.parentId);
    return meaning && state.currentTime >= meaning.startTime && state.currentTime <= meaning.startTime + meaning.duration;
  });
  const activeMeaning = activeBlock ? state.meaningTrack.find(m => m.id === activeBlock.parentId) : null;
  const activeTextOverlays = state.textTrack.filter(t => state.currentTime >= t.startTime && state.currentTime <= t.startTime + t.duration);

  return (
    <div className="relative w-full h-full flex items-center justify-center">
      <div className="relative overflow-hidden bg-black aspect-video max-h-[85vh] shadow-[0_0_100px_rgba(0,0,0,1)] border border-[#1a1a1a]">
         <video
            ref={videoRef}
            className="w-full h-full object-contain"
            src={SAMPLE_VIDEO_URL}
            loop
            playsInline
            onTimeUpdate={(e) => onTimeUpdate(e.currentTarget.currentTime)}
            onLoadedMetadata={(e) => onDurationChange(e.currentTarget.duration)}
         />

         {/* Subtitles - Minimalist */}
         <div className="absolute inset-0 pointer-events-none flex flex-col justify-end items-center pb-12 px-8 z-20">
            {activeBlock && activeMeaning && (
                <div className={`bg-black/80 px-4 py-1.5 border border-[#1a1a1a] text-sm tracking-widest ${getSentimentStyles(activeMeaning.sentiment)}`}>
                    {activeBlock.text}
                </div>
            )}
         </div>

         {/* Typography Overlays */}
         <div className="absolute inset-0 pointer-events-none z-20 overflow-hidden">
             {activeTextOverlays.map(text => (
                 <div 
                    key={text.id}
                    className="absolute whitespace-pre-wrap text-center transform -translate-x-1/2 -translate-y-1/2 font-display"
                    style={{
                        left: `${text.style.x}%`,
                        top: `${text.style.y}%`,
                        fontSize: `${text.style.fontSize}px`,
                        color: text.style.color,
                        opacity: text.style.opacity,
                        fontWeight: 'bold'
                    }}
                 >
                     {text.text}
                 </div>
             ))}
         </div>

         {/* Play Toggle Overlay */}
         <div className="absolute inset-0 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity duration-300 bg-black/10 cursor-pointer z-40" onClick={onTogglePlay}>
            <div className="p-4 bg-white/10 backdrop-blur-md rounded-full border border-white/20">
                {state.isPlaying ? <Pause className="w-8 h-8 text-white" /> : <Play className="w-8 h-8 text-white ml-1" />}
            </div>
