import { useState, useCallback, useEffect } from 'react';
import { INITIAL_VIDEO_STATE } from '../constants';
import { VideoState, VideoTransform, Keyframe, TextBlock, AudioBlock } from '../types';

export const useVideoEditor = () => {
  const [state, setState] = useState<VideoState>({ ...INITIAL_VIDEO_STATE });

  const handleTimeUpdate = useCallback((t: number) => setState(prev => ({ ...prev, currentTime: t })), []);
  const togglePlay = useCallback(() => setState(prev => ({ ...prev, isPlaying: !prev.isPlaying })), []);

  const handleSplit = useCallback(() => {
    setState(prev => {
      const { currentTime } = prev;
      const splitTrack = <T extends { id: string, startTime: number, duration: number }>(track: T[]) => {
        const index = track.findIndex(m => currentTime > m.startTime && currentTime < m.startTime + m.duration);
        if (index === -1) return track;
        const original = track[index];
        const firstPart = { ...original, duration: currentTime - original.startTime };
        const secondPart = { ...original, id: Math.random().toString(36), startTime: currentTime, duration: original.duration - (currentTime - original.startTime) };
        const newTrack = [...track];
        newTrack.splice(index, 1, firstPart, secondPart);
        return newTrack;
      };
      return {
        ...prev,
        meaningTrack: splitTrack(prev.meaningTrack),
        textTrack: splitTrack(prev.textTrack),
        audioTrack: splitTrack(prev.audioTrack),
        effectTrack: splitTrack(prev.effectTrack),
        overlayTrack: splitTrack(prev.overlayTrack),
      };
    });
  }, []);

  const handleTrim = useCallback((trackName: keyof VideoState, id: string, startTime: number, duration: number) => {
    setState(prev => {
      const track = prev[trackName] as any[];
      if (!Array.isArray(track)) return prev;
      return { 
        ...prev, 
        [trackName]: track.map(item => item.id === id ? { ...item, startTime, duration: Math.max(0.1, duration) } : item) 
      };
    });
  }, []);

  const handleDelete = useCallback(() => {
    setState(prev => {
      const { currentTime } = prev;
      const filterItem = (item: { startTime: number, duration: number }) => 
        currentTime < item.startTime || currentTime > item.startTime + item.duration;
      return {
        ...prev,
        meaningTrack: prev.meaningTrack.filter(filterItem),
        textTrack: prev.textTrack.filter(filterItem),
        audioTrack: prev.audioTrack.filter(filterItem),
        effectTrack: prev.effectTrack.filter(filterItem),
        overlayTrack: prev.overlayTrack.filter(filterItem),
        transitionTrack: prev.transitionTrack.filter(filterItem),
      };
    });
  }, []);

  const handleAddText = useCallback((styleId: string) => {
    const newText: TextBlock = {
      id: Math.random().toString(36),
      text: styleId === 'sub' ? 'New Subtitle' : 'NEW TITLE',
      startTime: state.currentTime,
      duration: 3,
      animation: 'pop',
      style: { fontFamily: 'Inter', fontSize: styleId === 'sub' ? 24 : 64, color: '#ffffff', x: 50, y: styleId === 'sub' ? 85 : 50, opacity: 1, shadow: 'none' }
    };
    setState(prev => ({ ...prev, textTrack: [...prev.textTrack, newText] }));
  }, [state.currentTime]);

  const handleAddAudio = useCallback((trackName: string) => {
    const newAudio: AudioBlock = {
      id: Math.random().toString(36),
      name: trackName,
      startTime: state.currentTime,
      duration: 5,
      volume: 0.8,
      type: trackName.includes('Beat') ? 'music' : 'sfx'
    };
    setState(prev => ({ ...prev, audioTrack: [...prev.audioTrack, newAudio] }));
  }, [state.currentTime]);

  /**
   * Helper to interpolate value between keyframes
   */
  const getInterpolatedValue = (keyframes: Keyframe[], time: number, defaultValue: number): number => {
    if (keyframes.length === 0) return defaultValue;
    if (time <= keyframes[0].time) return keyframes[0].value;
    if (time >= keyframes[keyframes.length - 1].time) return keyframes[keyframes.length - 1].value;

    for (let i = 0; i < keyframes.length - 1; i++) {
      const k1 = keyframes[i];
      const k2 = keyframes[i + 1];
      if (time >= k1.time && time <= k2.time) {
        const t = (time - k1.time) / (k2.time - k1.time);
        return k1.value + (k2.value - k1.value) * t;
      }
    }
    return defaultValue;
  };

  // Sync transform values with keyframes during playback or seek
  useEffect(() => {
    setState(prev => {
      const { keyframes } = prev.transform;
      const newTransform = { ...prev.transform };
      let changed = false;

      Object.keys(keyframes).forEach(prop => {
        const keys = keyframes[prop];
        if (keys.length > 0) {
          const currentVal = prev.transform[prop as keyof VideoTransform] as number;
          const interpolated = getInterpolatedValue(keys, prev.currentTime, currentVal);
          if (interpolated !== currentVal) {
            (newTransform as any)[prop] = interpolated;
            changed = true;
          }
        }
      });

      return changed ? { ...prev, transform: newTransform } : prev;
    });
  }, [state.currentTime]);

  const handleUpdateTransform = useCallback((prop: keyof VideoTransform, value: number) => {
    setState(prev => {
      const newTransform = { ...prev.transform, [prop]: value };
      const currentKeys = prev.transform.keyframes[prop as string] || [];

      // If we are currently "on" a keyframe (within a small threshold), update the keyframe value too
      const existingKeyIndex = currentKeys.findIndex(k => Math.abs(k.time - prev.currentTime) < 0.05);

      if (existingKeyIndex !== -1) {
        const newKeys = [...currentKeys];
        newKeys[existingKeyIndex] = { ...newKeys[existingKeyIndex], value };
        newTransform.keyframes = { ...newTransform.keyframes, [prop as string]: newKeys };
      } else if (currentKeys.length > 0) {
        // Auto-key: If there are existing keyframes for this property, create a new one at current time
        const newKey: Keyframe = { id: Math.random().toString(36), time: prev.currentTime, value };
        const newKeys = [...currentKeys, newKey].sort((a, b) => a.time - b.time);
        newTransform.keyframes = { ...newTransform.keyframes, [prop as string]: newKeys };
      }

      return { ...prev, transform: newTransform };
    });
  }, []);

  const handleToggleKeyframe = useCallback((prop: string) => {
    setState(prev => {
      const currentKeys = prev.transform.keyframes[prop] || [];
      const existingIndex = currentKeys.findIndex(k => Math.abs(k.time - prev.currentTime) < 0.1);
      let newKeys: Keyframe[];

      if (existingIndex !== -1) {
        newKeys = currentKeys.filter((_, i) => i !== existingIndex);
      } else {
        const val = prev.transform[prop as keyof VideoTransform] as number;
        newKeys = [...currentKeys, { id: Math.random().toString(36), time: prev.currentTime, value: val }].sort((a, b) => a.time - b.time);
      }

      return { 
        ...prev, 
        transform: { 
          ...prev.transform, 
          keyframes: { ...prev.transform.keyframes, [prop]: newKeys } 
        } 
      };
    });
  }, []);

  return {
    state,
    setState,
    handleTimeUpdate,
    togglePlay,
    handleSplit,
    handleTrim,
    handleDelete,
    handleAddText,
    handleAddAudio,
    handleToggleKeyframe,
    handleUpdateTransform
  };
};

import React from 'react';
import { VideoState, VideoTransform, VideoAdjustment, ChromaKey } from '../types';
import { Maximize, Diamond, Palette, Scissors } from 'lucide-react';

interface PropertiesPanelProps {
  state: VideoState;
  onChangeTransform: (transform: VideoTransform) => void;
  onUpdateTransformProperty: (prop: keyof VideoTransform, value: number) => void;
  onChangeAdjustment: (adj: VideoAdjustment) => void;
  onToggleKeyframe: (prop: string) => void;
  onChangeChromaKey: (chroma: ChromaKey) => void;
}

const PropertiesPanel: React.FC<PropertiesPanelProps> = ({ 
  state, 
  onUpdateTransformProperty, 
  onChangeAdjustment, 
  onToggleKeyframe, 
  onChangeChromaKey 
}) => {

  const KeyframeButton = ({ prop }: { prop: string }) => {
      const hasKeyAtCurrent = state.transform.keyframes[prop]?.some(k => Math.abs(k.time - state.currentTime) < 0.1);
      return (
          <button 
            onClick={() => onToggleKeyframe(prop)}
            className={`transition-all p-1 rounded ${hasKeyAtCurrent ? 'text-white' : 'text-slate-800 hover:text-slate-600'}`} 
            title={hasKeyAtCurrent ? "Remove Keyframe" : "Add Keyframe"}
          >
              <Diamond className={`w-2.5 h-2.5 ${hasKeyAtCurrent ? 'fill-current' : ''}`} />
          </button>
      );
  };

  const Section = ({ icon: Icon, title, children }: { icon: any, title: string, children?: React.ReactNode }) => (
      <div className="space-y-4">
          <h3 className="text-[9px] font-black text-slate-600 uppercase tracking-[0.3em] flex items-center gap-2">
              <Icon className="w-3 h-3" /> {title}
          </h3>
          <div className="space-y-4 bg-black p-3 rounded border border-[#1a1a1a]">
              {children}
          </div>
      </div>
  );

  return (
    <div className="h-full bg-black flex flex-col custom-scrollbar overflow-y-auto">
        <div className="p-4 space-y-8 pb-20">

            <Section icon={Maximize} title="Spatial">
                {[
                    { label: 'Scale', prop: 'scale', min: 0.1, max: 2, step: 0.01 },
                    { label: 'Rotate', prop: 'rotation', min: -180, max: 180, step: 1 },
                    { label: 'Opac', prop: 'opacity', min: 0, max: 100, step: 1 },
                    { label: 'X_Pos', prop: 'positionX', min: -500, max: 500, step: 1 },
                ].map(item => {
                    const value = state.transform[item.prop as keyof VideoTransform] as number;
                    return (
                        <div key={item.prop} className="space-y-1.5">
                            <div className="flex justify-between items-center">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">{item.label}</label>
                                <div className="flex items-center gap-2">
                                    <span className="text-[9px] font-mono text-white">
                                        {typeof value === 'number' ? value.toFixed(2) : value}
                                    </span>
                                    <KeyframeButton prop={item.prop} />
                                </div>
                            </div>
                            <input 
                                type="range" 
                                min={item.min} 
                                max={item.max} 
                                step={item.step}
                                value={value}
                                onChange={(e) => onUpdateTransformProperty(item.prop as keyof VideoTransform, parseFloat(e.target.value))}
                                className="w-full"
                            />
                        </div>
                    );
                })}
            </Section>

            <Section icon={Palette} title="Correction">
                <div className="space-y-4">
                    <div className="flex justify-between items-center">
                        <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Intensity</label>
                        <span className="text-[9px] font-mono text-white">{state.adjustment.filterIntensity}%</span>
                    </div>
                    <input 
                        type="range" min="0" max="100"
                        value={state.adjustment.filterIntensity}
                        onChange={(e) => onChangeAdjustment({...state.adjustment, filterIntensity: parseInt(e.target.value)})}
                        className="w-full"
                    />
                </div>
            </Section>

            <Section icon={Scissors} title="Extraction">
                <div className="flex items-center justify-between">
                    <span className="text-[9px] text-slate-500 uppercase tracking-widest">Auto_Chroma</span>
                    <input 
                        type="checkbox" 
                        checked={state.chromaKey.enabled}
                        onChange={(e) => onChangeChromaKey({ ...state.chromaKey, enabled: e.target.checked })}
                        className="accent-white w-3 h-3 cursor-pointer"
                    />
                </div>
            </Section>

        </div>
    </div>
  );
};

export default PropertiesPanel;

import React, { useState, useEffect } from 'react';
import { useVideoEditor } from './hooks/useVideoEditor';
import { useAIController } from './hooks/useAIController';
import VideoPlayer from './components/VideoPlayer';
import Timeline from './components/Timeline';
import AIChat from './components/AIChat';
import EditorSidebar from './components/EditorSidebar';
import PropertiesPanel from './components/PropertiesPanel';
import Header from './components/Header';
import { RightPanelTab } from './types';
import { Settings2, MessageSquare } from 'lucide-react';

const App: React.FC = () => {
  const { 
    state, 
    setState, 
    handleTimeUpdate, 
    togglePlay, 
    handleSplit, 
    handleTrim, 
    handleDelete, 
    handleAddText, 
    handleAddAudio,
    handleToggleKeyframe,
    handleUpdateTransform
  } = useVideoEditor();

  const { messages, isProcessing, handleSendMessage } = useAIController(state, setState);
  const [rightPanel, setRightPanel] = useState<RightPanelTab>('chat');

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (e.key.toLowerCase() === 'b') handleSplit();
      if (e.key === 'Delete' || e.key === 'Backspace') handleDelete();
      if (e.key === ' ') {
        e.preventDefault();
        togglePlay();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleSplit, handleDelete, togglePlay]);

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-black text-slate-400 selection:bg-blue-500/30">
      <EditorSidebar 
        state={state}
        onSetMode={(mode) => setState(prev => ({ ...prev, activeMode: mode }))}
        onToggleLayer={(id) => setState(prev => ({ ...prev, languageLayers: prev.languageLayers.map(l => l.id === id ? { ...l, isVisible: !l.isVisible } : l) }))}
        onSetActiveLayer={(id) => setState(prev => ({ ...prev, activeLanguageId: id }))}
        onAddText={handleAddText} 
        onAddAudio={handleAddAudio}
        onAddSticker={(c) => {}}
        onAddEffect={(t, n) => {}}
        onAddOverlay={(s, t) => {}}
        onAddTransition={(t, n) => {}}
        onAutoCaption={() => {}}
        onChangeRatio={(r) => setState(prev => ({ ...prev, aspectRatio: r }))}
        onSetFilter={(f) => setState(prev => ({ ...prev, activeFilter: f }))}
      />

      <div className="flex-1 flex flex-col min-w-0 relative">
        <Header simulationMode={state.simulationMode} onSetSimulationMode={(m) => setState(prev => ({...prev, simulationMode: m}))} />

        <div className="flex-1 flex justify-center items-center bg-black overflow-hidden relative">
          <VideoPlayer state={state} onTimeUpdate={handleTimeUpdate} onDurationChange={(d) => setState(prev => ({...prev, duration: d}))} onTogglePlay={togglePlay} />
        </div>

        <div className="h-72 border-t border-[#1a1a1a] bg-black z-20">
          <Timeline state={state} onSeek={handleTimeUpdate} onSplit={handleSplit} onDelete={handleDelete} onTrim={handleTrim} />
        </div>
      </div>

      <div className="w-72 border-l border-[#1a1a1a] bg-black flex flex-col z-30">
         <div className="flex border-b border-[#1a1a1a]">
           <button onClick={() => setRightPanel('properties')} className={`flex-1 py-3 text-[9px] font-black tracking-widest flex items-center justify-center gap-2 transition-all ${rightPanel === 'properties' ? 'text-white border-b border-white bg-[#0a0a0a]' : 'text-slate-600 hover:bg-[#0a0a0a]'}`}><Settings2 className="w-3.5 h-3.5" /> INSPECTOR</button>
           <button onClick={() => setRightPanel('chat')} className={`flex-1 py-3 text-[9px] font-black tracking-widest flex items-center justify-center gap-2 transition-all ${rightPanel === 'chat' ? 'text-white border-b border-white bg-[#0a0a0a]' : 'text-slate-600 hover:bg-[#0a0a0a]'}`}><MessageSquare className="w-3.5 h-3.5" /> AI NODE</button>
         </div>
         <div className="flex-1 overflow-hidden">
           {rightPanel === 'chat' ? (
            <AIChat messages={messages} onSendMessage={handleSendMessage} isProcessing={isProcessing} />
           ) : (
            <PropertiesPanel 
              state={state}
              onChangeTransform={(t) => setState(prev => ({...prev, transform: t}))}
              onUpdateTransformProperty={handleUpdateTransform}
              onChangeAdjustment={(a) => setState(prev => ({...prev, adjustment: a}))}
              onToggleKeyframe={handleToggleKeyframe}
              onChangeChromaKey={(c) => setState(prev => ({...prev, chromaKey: c}))}
            />
           )}
         </div>
      </div>
    </div>
  );
};

export default App;

