import { GoogleGenAI, FunctionDeclaration, Type, Tool } from "@google/genai";
import { ToolNames } from "../types";

const analyzeMeaningTool: FunctionDeclaration = {
  name: ToolNames.ANALYZE_MEANING,
  description: "Analyze the cultural meaning and intent of a specific segment.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      segmentId: { type: Type.STRING, description: "ID of the MeaningBlock to analyze." },
      focus: { type: Type.STRING, description: "Focus area: 'proverb', 'tone', 'context'." }
    },
    required: ["segmentId"],
  },
};

const addLanguageTool: FunctionDeclaration = {
  name: ToolNames.ADD_LANGUAGE,
  description: "Add a new target language layer for translation.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      language: { type: Type.STRING, description: "Target language name (e.g., French, Swahili)." },
      style: { type: Type.STRING, description: "Translation style: 'formal', 'slang', 'poetic'." }
    },
    required: ["language"],
  },
};

const setToneTool: FunctionDeclaration = {
  name: ToolNames.SET_TONE,
  description: "Manually override the sentiment/tone of a block.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      blockId: { type: Type.STRING, description: "ID of the block." },
      sentiment: { type: Type.STRING, description: "Sentiment: 'neutral', 'anger', 'joy', 'urgency', 'proverb', 'sarcasm'." }
    },
    required: ["blockId", "sentiment"],
  },
};

const analyzeCulturalLossTool: FunctionDeclaration = {
  name: ToolNames.ANALYZE_CULTURAL_LOSS,
  description: "Analyze how much meaning was lost in a specific translation layer.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      layerId: { type: Type.STRING, description: "ID of the language layer." },
    },
    required: ["layerId"],
  },
};

const tools: Tool[] = [{
  functionDeclarations: [analyzeMeaningTool, addLanguageTool, setToneTool, analyzeCulturalLossTool],
}];

const SYSTEM_INSTRUCTION = `
You are TIMEFRAME, an advanced AI engine for "Meaning-First" video editing and directorial control.
Your core philosophy: Empower the user as a Director by translating intent, culture, and cinematic emotion.
You have access to a "Meaning Graph" of the video.
When a user asks to translate, consider the cultural context (proverbs, tone, hierarchy).
Use 'analyze_meaning' to explain cultural depth.
Use 'add_language' to generate new translation layers.
Use 'set_tone' to adjust how subtitles are rendered based on emotion (e.g., Anger, Sarcasm).
Use 'analyze_cultural_loss' to check if a translation layer is missing nuance.
Your outputs should be concise, professional, and technologically superior.
`;

export const createGeminiSession = () => {
  // Always use process.env.API_KEY directly when initializing the GoogleGenAI client
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Using 'gemini-3-flash-preview' for basic text tasks like translation and metadata analysis.
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      tools: tools,
    }
  });
};

