import React, { useState, useRef, useEffect, useCallback } from 'react';
import { createGeminiSession } from '../services/geminiService';
import { ChatMessage, ToolNames, ToolArgs, LanguageLayer, VideoState, Sentiment } from '../types';
import { Chat } from '@google/genai';
import { INITIAL_CHAT_MESSAGE } from '../constants';

export const useAIController = (videoState: VideoState, setVideoState: React.Dispatch<React.SetStateAction<VideoState>>) => {
  const [messages, setMessages] = useState<ChatMessage[]>([{ id: 'init', role: 'model', content: INITIAL_CHAT_MESSAGE }]);
  const [isProcessing, setIsProcessing] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);

  useEffect(() => {
    chatSessionRef.current = createGeminiSession();
  }, []);

  const handleSendMessage = useCallback(async (userMessage: string) => {
    if (!chatSessionRef.current) return;
    setIsProcessing(true);
    setMessages(prev => [...prev, { id: Date.now().toString(), role: 'user', content: userMessage }]);

    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMessage });
      const functionCalls = result.functionCalls;

      if (functionCalls && functionCalls.length > 0) {
        const responses: any[] = [];
        for (const call of functionCalls) {
          const toolName = call.name;
          const args = call.args as ToolArgs;
          let responseResult = { result: "Success" };

          // Visual Feedback: Start AI Analysis
          setVideoState(prev => ({ ...prev, isAnalyzing: true }));

          switch (toolName) {
            case ToolNames.ADD_LANGUAGE:
              const newLayer: LanguageLayer = {
                id: `target-${args.language.toLowerCase()}`,
                name: args.language,
                code: args.language.substr(0,2).toLowerCase(),
                type: 'target',
                isVisible: true,
                blocks: videoState.meaningTrack.map(m => ({
                  id: Math.random().toString(36),
                  parentId: m.id,
                  text: `[Neural Link: ${args.language}]`,
                  language: args.language,
                  isLiteral: false,
                  confidence: 0.9
                }))
              };
              setVideoState(prev => ({ 
                ...prev, 
                languageLayers: [...prev.languageLayers, newLayer], 
                activeLanguageId: newLayer.id,
                lastDirectorialAction: `Created ${args.language} node.`
              }));
              responseResult = { result: `Node ${args.language} online.` };
              break;

            case ToolNames.SET_TONE:
              const tone = args.sentiment as Sentiment;
              setVideoState(prev => {
                const newAdjustments = { ...prev.adjustment };
                // Directive: Change color grading based on tone
                if (tone === 'anger') {
                  newAdjustments.contrast = 150;
                  newAdjustments.saturation = 80;
                  newAdjustments.hue = -20;
                } else if (tone === 'joy') {
                  newAdjustments.brightness = 120;
                  newAdjustments.saturation = 140;
                } else if (tone === 'proverb') {
                  newAdjustments.blur = 5;
                  newAdjustments.contrast = 90;
                }

                return { 
                    ...prev, 
                    meaningTrack: prev.meaningTrack.map(b => b.id === args.blockId ? { ...b, sentiment: tone } : b),
                    adjustment: newAdjustments,
                    lastDirectorialAction: `Calibrated visual engine for ${tone} tone.`
                };
              });
              responseResult = { result: `Tone calibrated.` };
              break;

            case ToolNames.ANALYZE_MEANING:
               // Analysis effect handled by the isAnalyzing flag for a few seconds
               setTimeout(() => {
                 setVideoState(prev => ({ ...prev, isAnalyzing: false }));
               }, 3000);
               responseResult = { result: "Deep structure analyzed." };
               break;
          }
          responses.push({ name: toolName, response: responseResult, id: call.id });
        }

        const finalResponse = await chatSessionRef.current.sendToolResponse({ functionResponses: responses });
        if (finalResponse.text) setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: finalResponse.text }]);
      } else if (result.text) {
        setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: result.text }]);
      }
    } catch (error) {
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: "Link failure. Engine offline." }]);
    } finally {
      setIsProcessing(false);
      // Ensure scanning effect ends
      setTimeout(() => setVideoState(prev => ({ ...prev, isAnalyzing: false })), 500);
    }
  }, [videoState.meaningTrack, setVideoState]);

  return { messages, isProcessing, handleSendMessage };
};

import React, { useRef, useEffect } from 'react';
import { VideoState, Sentiment } from '../types';
import { SAMPLE_VIDEO_URL } from '../constants';
import { Play, Pause, Cpu, Activity, ShieldAlert } from 'lucide-react';

interface VideoPlayerProps {
  state: VideoState;
  onTimeUpdate: (time: number) => void;
  onDurationChange: (duration: number) => void;
  onTogglePlay: () => void;
}

const getSentimentStyles = (sentiment: Sentiment) => {
  switch (sentiment) {
    case 'anger': return 'text-red-500 font-bold tracking-tighter uppercase shadow-[0_0_10px_rgba(239,68,68,0.5)]';
    case 'proverb': return 'text-cyan-200 italic font-light tracking-widest';
    case 'urgency': return 'text-amber-500 font-black animate-pulse';
    default: return 'text-white font-medium';
  }
};

const VideoPlayer: React.FC<VideoPlayerProps> = ({ state, onTimeUpdate, onDurationChange, onTogglePlay }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if (videoRef.current) {
      if (state.isPlaying && videoRef.current.paused) {
        videoRef.current.play().catch(() => {});
      } else if (!state.isPlaying && !videoRef.current.paused) {
        videoRef.current.pause();
      }
    }
  }, [state.isPlaying]);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.volume = state.volume;
      videoRef.current.playbackRate = state.playbackSpeed;
    }
  }, [state.volume, state.playbackSpeed]);

  useEffect(() => {
    if (videoRef.current && Math.abs(videoRef.current.currentTime - state.currentTime) > 0.5) {
      videoRef.current.currentTime = state.currentTime;
    }
  }, [state.currentTime]);

  const activeLayer = state.languageLayers.find(l => l.id === state.activeLanguageId);
  const activeBlock = activeLayer?.blocks.find(b => {
    const meaning = state.meaningTrack.find(m => m.id === b.parentId);
    return meaning && state.currentTime >= meaning.startTime && state.currentTime <= meaning.startTime + meaning.duration;
  });
  const activeMeaning = activeBlock ? state.meaningTrack.find(m => m.id === activeBlock.parentId) : null;
  const activeTextOverlays = state.textTrack.filter(t => state.currentTime >= t.startTime && state.currentTime <= t.startTime + t.duration);

  // Directorial Filters based on adjustment state
  const filterString = `
    brightness(${state.adjustment.brightness}%)
    contrast(${state.adjustment.contrast}%)
    saturate(${state.adjustment.saturation}%)
    blur(${state.adjustment.blur}px)
    hue-rotate(${state.adjustment.hue}deg)
  `;

  return (
    <div className="relative w-full h-full flex items-center justify-center p-4">
      <div className={`relative overflow-hidden bg-black aspect-video max-h-[85vh] w-full transition-all duration-700 shadow-[0_0_100px_rgba(0,0,0,1)] border ${state.isAnalyzing ? 'border-cyan-500/50 active-glow' : 'border-[#1a1a1a]'}`}>

         {/* Neural Scan Overlay */}
         {state.isAnalyzing && (
            <div className="absolute inset-0 z-30 pointer-events-none">
                <div className="absolute inset-0 bg-cyan-500/5 animate-pulse"></div>
                <div className="absolute top-0 left-0 w-full h-1 bg-cyan-500/30 animate-[scan_2s_linear_infinite]"></div>
                <div className="absolute inset-0 overflow-hidden opacity-20">
                    <div className="grid grid-cols-12 gap-1 text-[6px] font-mono text-cyan-400 p-2">
                        {Array.from({length: 48}).map((_, i) => (
                            <div key={i}>{Math.random().toString(16).substr(2, 4)}</div>
                        ))}
                    </div>
                </div>
                <div className="absolute top-4 left-4 flex items-center gap-2">
                    <Cpu className="w-3 h-3 text-cyan-500 animate-spin" />
                    <span className="text-[8px] font-mono text-cyan-500 uppercase tracking-widest">Neural_Scanning_Active</span>
                </div>
                <div className="absolute bottom-4 right-4 flex flex-col items-end gap-1">
                    <Activity className="w-4 h-4 text-cyan-500 opacity-50" />
                    <span className="text-[6px] font-mono text-cyan-500 uppercase">Contextual_Parsing_Buffer: {Math.floor(Math.random() * 100)}%</span>
                </div>
            </div>
         )}

         {/* AI Notification Overlay */}
         {state.lastDirectorialAction && (
             <div className="absolute top-4 left-1/2 -translate-x-1/2 z-40 animate-out fade-out fill-mode-forwards duration-[3000ms]">
                 <div className="bg-black/80 border border-white/10 px-4 py-1.5 rounded flex items-center gap-3">
                    <ShieldAlert className="w-3 h-3 text-white" />
                    <span className="text-[9px] font-mono text-white tracking-widest uppercase">{state.lastDirectorialAction}</span>
                 </div>
             </div>
         )}

         <video
            ref={videoRef}
            className="w-full h-full object-contain transition-all duration-500"
            style={{ 
                filter: filterString,
                transform: `scale(${state.transform.scale}) translate(${state.transform.positionX}px, ${state.transform.positionY}px) rotate(${state.transform.rotation}deg)`,
                opacity: state.transform.opacity / 100
            }}
            src={SAMPLE_VIDEO_URL}
            loop
            playsInline
            onTimeUpdate={(e) => onTimeUpdate(e.currentTarget.currentTime)}
            onLoadedMetadata={(e) => onDurationChange(e.currentTarget.duration)}
         />

         {/* Subtitles - Meaning-Focused */}
         <div className="absolute inset-0 pointer-events-none flex flex-col justify-end items-center pb-16 px-12 z-20">
            {activeBlock && activeMeaning && (
                <div className={`bg-black/90 px-6 py-2 border border-white/5 text-sm tracking-[0.15em] transition-all duration-300 ${getSentimentStyles(activeMeaning.sentiment)}`}>
                    {activeBlock.text}
                    {activeMeaning.sentiment === 'proverb' && (
                        <div className="text-[8px] text-cyan-500/60 mt-1 italic tracking-widest font-mono text-center">
                             {activeMeaning.culturalNote}
                        </div>
                    )}
                </div>
            )}
         </div>

         {/* Typography Overlays */}
         <div className="absolute inset-0 pointer-events-none z-20 overflow-hidden">
             {activeTextOverlays.map(text => (
                 <div 
                    key={text.id}
                    className="absolute whitespace-pre-wrap text-center transform -translate-x-1/2 -translate-y-1/2 font-display"
                    style={{
                        left: `${text.style.x}%`,
                        top: `${text.style.y}%`,
                        fontSize: `${text.style.fontSize}px`,
                        color: text.style.color,
                        opacity: text.style.opacity,
                        fontWeight: 'bold'
                    }}
                 >
                     {text.text}
                 </div>
             ))}
         </div>

         {/* Play Toggle Overlay */}
         <div className="absolute inset-0 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity duration-300 bg-black/10 cursor-pointer z-40" onClick={onTogglePlay}>
            <div className="p-4 bg-white/10 backdrop-blur-md rounded-full border border-white/20">
                {state.isPlaying ? <Pause className="w-8 h-8 text-white" /> : <Play className="w-8 h-8 text-white ml-1" />}
            </div>
         </div>
      </div>

      <style>{`
        @keyframes scan {
          0% { top: 0%; }
          100% { top: 100%; }
        }
      `}</style>
    </div>
  );
};

