import React, { useState, useRef, useEffect, useCallback } from 'react';
import { createGeminiSession } from '../services/geminiService';
import { ChatMessage, ToolNames, ToolArgs, VideoState, SubtitleBlock, FilterPreset } from '../types';
import { Chat } from '@google/genai';
import { INITIAL_CHAT_MESSAGE } from '../constants';

export const useAIController = (videoState: VideoState, setVideoState: React.Dispatch<React.SetStateAction<VideoState>>) => {
  const [messages, setMessages] = useState<ChatMessage[]>([{ id: 'init', role: 'model', content: INITIAL_CHAT_MESSAGE }]);
  const [isProcessing, setIsProcessing] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);

  useEffect(() => {
    chatSessionRef.current = createGeminiSession();
  }, []);

  const handleSendMessage = useCallback(async (userMessage: string) => {
    if (!chatSessionRef.current) return;
    setIsProcessing(true);
    setMessages(prev => [...prev, { id: Date.now().toString(), role: 'user', content: userMessage }]);

    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMessage });
      const functionCalls = result.functionCalls;

      if (functionCalls && functionCalls.length > 0) {
        const responses: any[] = [];
        for (const call of functionCalls) {
          const toolName = call.name;
          const args = call.args as ToolArgs;
          let responseResult = { result: "Done" };

          setVideoState(prev => ({ ...prev, isAnalyzing: true }));

          switch (toolName) {
            case ToolNames.ADD_SUBTITLE:
              const newSub: SubtitleBlock = {
                id: Math.random().toString(36),
                text: args.text,
                startTime: args.startTime ?? prev.currentTime,
                duration: args.duration ?? 3
              };
              setVideoState(prev => ({ 
                ...prev, 
                subtitleTrack: [...prev.subtitleTrack, newSub],
                lastDirectorialAction: `Added subtitle: "${args.text}"`
              }));
              break;

            case ToolNames.SET_FILTER:
              setVideoState(prev => ({ 
                ...prev, 
                activeFilter: args.filter as FilterPreset,
                lastDirectorialAction: `Applied ${args.filter} filter.`
              }));
              break;

            case ToolNames.ADJUST_TRANSFORM:
                setVideoState(prev => ({
                    ...prev,
                    transform: {
                        ...prev.transform,
                        scale: args.scale ?? prev.transform.scale,
                        rotation: args.rotation ?? prev.transform.rotation,
                        opacity: args.opacity ?? prev.transform.opacity
                    },
                    lastDirectorialAction: 'Updated transform properties.'
                }));
                break;
          }
          responses.push({ name: toolName, response: responseResult, id: call.id });
        }

        const finalResponse = await chatSessionRef.current.sendToolResponse({ functionResponses: responses });
        if (finalResponse.text) setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: finalResponse.text }]);
      } else if (result.text) {
        setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: result.text }]);
      }
    } catch (error) {
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: "Something went wrong. Please try again." }]);
    } finally {
      setIsProcessing(false);
      setTimeout(() => setVideoState(prev => ({ ...prev, isAnalyzing: false })), 500);
    }
  }, [setVideoState]);

  return { messages, isProcessing, handleSendMessage };
};

import React, { useRef, useEffect } from 'react';
import { VideoState, FilterPreset } from '../types';
import { Play, Pause, Activity } from 'lucide-react';

interface VideoPlayerProps {
  state: VideoState;
  onTimeUpdate: (time: number) => void;
  onDurationChange: (duration: number) => void;
  onTogglePlay: () => void;
}

const getFilterCSS = (preset: FilterPreset): string => {
    switch (preset) {
        case 'vibrant': return 'saturate(1.5) contrast(1.1)';
        case 'cinema': return 'sepia(0.2) contrast(1.2) brightness(0.9) saturate(0.8)';
        case 'vintage': return 'sepia(0.5) contrast(0.8) brightness(1.1)';
        case 'bw': return 'grayscale(1)';
        case 'cyber': return 'hue-rotate(180deg) saturate(2) brightness(1.2)';
        default: return 'none';
    }
};

const VideoPlayer: React.FC<VideoPlayerProps> = ({ state, onTimeUpdate, onDurationChange, onTogglePlay }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if (videoRef.current) {
      if (state.isPlaying && videoRef.current.paused) {
        videoRef.current.play().catch(() => {});
      } else if (!state.isPlaying && !videoRef.current.paused) {
        videoRef.current.pause();
      }
    }
  }, [state.isPlaying]);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.volume = state.volume;
      videoRef.current.playbackRate = state.playbackSpeed;
    }
  }, [state.volume, state.playbackSpeed]);

  useEffect(() => {
    if (videoRef.current && Math.abs(videoRef.current.currentTime - state.currentTime) > 0.5) {
      videoRef.current.currentTime = state.currentTime;
    }
  }, [state.currentTime]);

  const activeSub = state.subtitleTrack.find(s => state.currentTime >= s.startTime && state.currentTime <= s.startTime + s.duration);
  const activeTextOverlays = state.textTrack.filter(t => state.currentTime >= t.startTime && state.currentTime <= t.startTime + t.duration);

  // Combine Adjustment and Preset Filter
  const filterString = `
    brightness(${state.adjustment.brightness}%)
    contrast(${state.adjustment.contrast}%)
    saturate(${state.adjustment.saturation}%)
    blur(${state.adjustment.blur}px)
    hue-rotate(${state.adjustment.hue}deg)
    ${getFilterCSS(state.activeFilter)}
  `;

  return (
    <div className="relative w-full h-full flex items-center justify-center p-4">
      <div className={`relative overflow-hidden bg-black aspect-video max-h-[85vh] w-full transition-all duration-700 shadow-2xl border ${state.isAnalyzing ? 'border-white/50' : 'border-[#1a1a1a]'}`}>

         {state.isAnalyzing && (
            <div className="absolute inset-0 z-30 pointer-events-none bg-white/5">
                <div className="absolute top-0 left-0 w-full h-[1px] bg-white/40 animate-[scan_1.5s_linear_infinite]"></div>
                <div className="absolute bottom-4 left-4 flex items-center gap-2">
                    <Activity className="w-3 h-3 text-white/50" />
                    <span className="text-[8px] font-mono text-white/50 uppercase tracking-widest">Applying AI Adjustments...</span>
                </div>
            </div>
         )}

         <video
            ref={videoRef}
            className="w-full h-full object-contain"
            style={{ 
                filter: filterString,
                transform: `scale(${state.transform.scale}) translate(${state.transform.positionX}px, ${state.transform.positionY}px) rotate(${state.transform.rotation}deg)`,
                opacity: state.transform.opacity / 100
            }}
            src={state.videoClips[0]?.url} // Simply use the first clip for this MVP
            loop
            playsInline
            onTimeUpdate={(e) => onTimeUpdate(e.currentTarget.currentTime)}
            onLoadedMetadata={(e) => onDurationChange(e.currentTarget.duration)}
         />

         {/* Subtitles Overlay */}
         <div className="absolute inset-x-0 bottom-12 pointer-events-none flex justify-center px-12 z-20">
            {activeSub && (
                <div className="bg-black/80 px-4 py-1.5 rounded text-white text-base font-medium shadow-lg backdrop-blur-sm border border-white/10">
                    {activeSub.text}
                </div>
            )}
         </div>

         {/* Text/Typography Overlays */}
         <div className="absolute inset-0 pointer-events-none z-20">
             {activeTextOverlays.map(text => (
                 <div 
                    key={text.id}
                    className="absolute whitespace-pre-wrap text-center transform -translate-x-1/2 -translate-y-1/2"
                    style={{
                        left: `${text.style.x}%`,
                        top: `${text.style.y}%`,
                        fontSize: `${text.style.fontSize}px`,
                        color: text.style.color,
                        opacity: text.style.opacity,
                        fontFamily: text.style.fontFamily,
                        textShadow: text.style.shadow
                    }}
                 >
                     {text.text}
                 </div>
             ))}
         </div>

         <div className="absolute inset-0 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity bg-black/10 cursor-pointer z-40" onClick={onTogglePlay}>
            <div className="p-4 bg-white/10 backdrop-blur-md rounded-full border border-white/20">
                {state.isPlaying ? <Pause className="w-8 h-8 text-white" /> : <Play className="w-8 h-8 text-white ml-1" />}
            </div>
         </div>
      </div>

      <style>{`
        @keyframes scan {
          0% { top: 0%; }
          100% { top: 100%; }
        }
      `}</style>
    </div>
  );
};

export default VideoPlayer;

import React, { useState, useRef, useEffect } from 'react';
import { VideoState, Keyframe } from '../types';
import { Scissors, Trash2, Magnet, ZoomIn, ZoomOut, Type, Music, FolderOpen, Zap, Diamond, Subtitles } from 'lucide-react';

interface TimelineProps {
  state: VideoState;
  onSeek: (time: number) => void;
  onSplit: () => void;
  onDelete: () => void;
  onTrim: (trackName: keyof VideoState, id: string, startTime: number, duration: number) => void;
}

const Timeline: React.FC<TimelineProps> = ({ state, onSeek, onSplit, onDelete, onTrim }) => {
  const percentage = (state.currentTime / state.duration) * 100;
  const timelineRef = useRef<HTMLDivElement>(null);

  const [dragState, setDragState] = useState<{
    trackName: keyof VideoState;
    id: string;
    edge: 'start' | 'end';
    initialMouseX: number;
    initialStartTime: number;
    initialDuration: number;
  } | null>(null);

  const handleTimelineClick = (e: React.MouseEvent<HTMLDivElement>) => {
    if ((e.target as HTMLElement).closest('.trim-handle')) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const clickPercentage = x / rect.width;
    const newTime = Math.max(0, Math.min(state.duration, clickPercentage * state.duration));
    onSeek(newTime);
  };

  const onStartTrim = (e: React.MouseEvent, trackName: keyof VideoState, id: string, edge: 'start' | 'end', startTime: number, duration: number) => {
    e.stopPropagation();
    setDragState({
      trackName,
      id,
      edge,
      initialMouseX: e.clientX,
      initialStartTime: startTime,
      initialDuration: duration
    });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragState || !timelineRef.current) return;
      const timelineWidth = timelineRef.current.getBoundingClientRect().width;
      const dx = ((e.clientX - dragState.initialMouseX) / timelineWidth) * state.duration;
      let newStartTime = dragState.initialStartTime;
      let newDuration = dragState.initialDuration;
      if (dragState.edge === 'start') {
        newStartTime = Math.max(0, dragState.initialStartTime + dx);
        newDuration = Math.max(0.1, dragState.initialDuration - (newStartTime - dragState.initialStartTime));
      } else {
        newDuration = Math.max(0.1, dragState.initialDuration + dx);
      }
      onTrim(dragState.trackName, dragState.id, newStartTime, newDuration);
    };
    const handleMouseUp = () => setDragState(null);
    if (dragState) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragState, state.duration, onTrim]);

  const TrackHeader = ({ icon: Icon, label }: { icon: any, label: string }) => (
    <div className="absolute left-2 top-1/2 -translate-y-1/2 flex items-center gap-1.5 z-10 pointer-events-none opacity-40 bg-black/80 px-1.5 py-0.5 rounded border border-[#1a1a1a]">
      <Icon className="w-2.5 h-2.5 text-slate-400" />
      <span className="text-[7px] font-mono text-slate-400 tracking-tighter uppercase">{label}</span>
    </div>
  );

  const renderClip = (item: any, trackName: keyof VideoState, className: string, children?: React.ReactNode) => {
    const left = (item.startTime / state.duration) * 100;
    const width = (item.duration / state.duration) * 100;
    const isSelected = state.currentTime >= item.startTime && state.currentTime <= item.startTime + item.duration;

    return (
      <div 
        key={item.id}
        className={`absolute top-1 bottom-1 rounded border overflow-hidden cursor-pointer group transition-all bg-[#121212] border-[#222] ${isSelected ? 'ring-1 ring-white/40 z-30 bg-[#1a1a1a]' : 'hover:bg-[#151515]'} ${className}`}
        style={{ left: `${left}%`, width: `${width}%` }}
      >
        <div 
          className="trim-handle absolute left-0 top-0 bottom-0 w-1 bg-white/10 hover:bg-white/30 cursor-ew-resize opacity-0 group-hover:opacity-100 transition-opacity z-10"
          onMouseDown={(e) => onStartTrim(e, trackName, item.id, 'start', item.startTime, item.duration)}
        />
        <div className="flex items-center h-full px-2 overflow-hidden pointer-events-none">
            {children}
        </div>
        <div 
          className="trim-handle absolute right-0 top-0 bottom-0 w-1 bg-white/10 hover:bg-white/30 cursor-ew-resize opacity-0 group-hover:opacity-100 transition-opacity z-10"
          onMouseDown={(e) => onStartTrim(e, trackName, item.id, 'end', item.startTime, item.duration)}
        />
      </div>
    );
  };

  return (
    <div className="w-full h-full flex flex-col bg-black border-t border-[#1a1a1a] select-none">
      <div className="h-10 border-b border-[#1a1a1a] bg-black flex items-center justify-between px-4">
         <div className="flex items-center gap-1">
            <button onClick={onSplit} className="p-2 hover:bg-[#0a0a0a] rounded text-slate-500 hover:text-white transition-all flex items-center gap-2 px-3 border border-transparent hover:border-[#1a1a1a]"><Scissors className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Split</span></button>
            <button onClick={onDelete} className="p-2 hover:bg-[#0a0a0a] rounded text-slate-500 hover:text-red-500 transition-all flex items-center gap-2 px-3 border border-transparent hover:border-[#1a1a1a]"><Trash2 className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Delete</span></button>
            <div className="w-[1px] h-4 bg-[#1a1a1a] mx-2"></div>
            <button className="p-2 text-white/50 hover:text-white"><Magnet className="w-3.5 h-3.5" /></button>
         </div>
         <div className="flex items-center gap-4">
            <div className="text-[9px] font-mono text-white bg-[#0a0a0a] px-2 py-0.5 rounded border border-[#1a1a1a] tracking-widest">
                {new Date(state.currentTime * 1000).toISOString().substr(14, 9)} / {new Date(state.duration * 1000).toISOString().substr(14, 5)}
            </div>
            <div className="flex items-center gap-2">
                <ZoomOut className="w-3 h-3 text-slate-700" />
                <div className="w-16 h-[1px] bg-[#1a1a1a]"><div className="w-1/3 h-full bg-slate-400"></div></div>
                <ZoomIn className="w-3 h-3 text-slate-700" />
            </div>
         </div>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar relative bg-[#050505]">
        <div className="relative min-h-[400px] p-2" ref={timelineRef} onClick={handleTimelineClick}>
            <div className="absolute top-0 bottom-0 w-[1px] bg-white z-50 pointer-events-none" style={{ left: `${percentage}%` }}>
                <div className="absolute -top-1 -left-[3px] w-1.5 h-4 bg-white rounded-sm"></div>
            </div>

            {/* Keyframe Track (Auto-generated) */}
            <div className="mb-2 relative h-8 w-full bg-black rounded-sm border border-[#1a1a1a]">
                 <TrackHeader icon={Zap} label="Keyframes" />
                 {Object.entries(state.transform.keyframes).map(([prop, keys]) => (
                     (keys as Keyframe[]).map(k => (
                         <div key={k.id} className="absolute top-1/2 -translate-y-1/2 w-2 h-2 bg-blue-500 rotate-45 z-40 border border-white" style={{ left: `${(k.time / state.duration) * 100}%` }} />
                     ))
                 ))}
            </div>

            {/* Main Video Track */}
            <div className="mb-2 relative h-14 w-full bg-black rounded-sm border border-[#1a1a1a]">
                 <TrackHeader icon={FolderOpen} label="Media" />
                 {state.videoClips.map(clip => renderClip(clip, 'videoClips', 'border-l-blue-500 border-l-2', 
                    <div className="flex items-center gap-2 w-full h-full">
                        <img src={clip.thumbnail} className="h-full w-12 object-cover rounded-sm opacity-50" />
                        <span className="truncate text-[8px] font-bold uppercase tracking-wider text-slate-300">{clip.name}</span>
                    </div>
                 ))}
            </div>

             <div className="relative h-10 w-full mb-1 bg-black rounded-sm border border-[#1a1a1a]">
                <TrackHeader icon={Subtitles} label="Subtitles" />
                {state.subtitleTrack.map(sub => renderClip(sub, 'subtitleTrack', 'border-l-yellow-500/50 border-l-2', 
                    <span className="truncate text-[8px] uppercase tracking-widest text-slate-400 italic">{sub.text}</span>
                ))}
            </div>

            <div className="relative h-10 w-full mb-1 bg-black rounded-sm border border-[#1a1a1a]">
                <TrackHeader icon={Type} label="Text" />
                {state.textTrack.map(txt => renderClip(txt, 'textTrack', 'border-l-purple-500/50 border-l-2', 
                    <span className="truncate text-[8px] uppercase tracking-widest text-slate-400 font-bold">{txt.text}</span>
                ))}
            </div>

            <div className="relative h-10 w-full mb-1 bg-black rounded-sm border border-[#1a1a1a]">
                <TrackHeader icon={Music} label="Audio" />
                {state.audioTrack.map(aud => renderClip(aud, 'audioTrack', 'border-l-green-500/50 border-l-2', 
                    <span className="truncate text-[8px] uppercase tracking-widest text-slate-500 font-mono">{aud.name}</span>
                ))}
            </div>
        </div>
      </div>
    </div>
  );
};

