  name: string;
  startTime: number;
  duration: number;
  volume: number;
  type: 'music' | 'sfx' | 'voiceover';
}

export type AspectRatio = '16:9' | '9:16' | '1:1' | '4:5';
export type FilterPreset = 'none' | 'vibrant' | 'cinema' | 'vintage' | 'bw' | 'cyber';

export interface ChromaKey {
  enabled: boolean;
  color: string;
  intensity: number;
  shadow: number;
}

export type EditorMode = 'media' | 'text' | 'audio' | 'filters' | 'effects' | 'transitions' | 'ratio';
export type RightPanelTab = 'properties' | 'chat';

/**
 * Defines the simulation modes available for project review.
 */
export type SimulationMode = 'native' | 'global' | 'learner';

export interface VideoState {
  isPlaying: boolean;
  currentTime: number;
  duration: number;
  volume: number;
  activeMode: EditorMode;

  playbackSpeed: number; 
  aspectRatio: AspectRatio; 

  chromaKey: ChromaKey;
  activeFilter: FilterPreset;

  videoClips: VideoClip[];
  subtitleTrack: SubtitleBlock[];
  textTrack: TextBlock[]; 
  audioTrack: AudioBlock[]; 

  transform: VideoTransform;
  adjustment: VideoAdjustment;

  isAnalyzing: boolean;
  lastDirectorialAction?: string;
  selectedTextId?: string; // Track which text overlay is being edited
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model' | 'system';
  content: string;
  isFunctionCall?: boolean;
}

export enum ToolNames {
  ADD_SUBTITLE = 'add_subtitle',
  ADD_TEXT = 'add_text',
  SET_FILTER = 'set_filter',
  ADJUST_TRANSFORM = 'adjust_transform',
  SPLIT_CLIP = 'split_clip'
}

export type ToolArgs = Record<string, any>;

import { useState, useCallback, useEffect } from 'react';
import { INITIAL_VIDEO_STATE } from '../constants';
import { VideoState, VideoTransform, Keyframe, TextBlock, AudioBlock } from '../types';

export const useVideoEditor = () => {
  const [state, setState] = useState<VideoState>({ ...INITIAL_VIDEO_STATE });

  const handleTimeUpdate = useCallback((t: number) => setState(prev => ({ ...prev, currentTime: t })), []);
  const togglePlay = useCallback(() => setState(prev => ({ ...prev, isPlaying: !prev.isPlaying })), []);

  const handleSplit = useCallback(() => {
    setState(prev => {
      const { currentTime } = prev;
      const splitTrack = <T extends { id: string, startTime: number, duration: number }>(track: T[]) => {
        const index = track.findIndex(m => currentTime > m.startTime && currentTime < m.startTime + m.duration);
        if (index === -1) return track;
        const original = track[index];
        const firstPart = { ...original, duration: currentTime - original.startTime };
        const secondPart = { ...original, id: Math.random().toString(36), startTime: currentTime, duration: original.duration - (currentTime - original.startTime) };
        const newTrack = [...track];
        newTrack.splice(index, 1, firstPart, secondPart);
        return newTrack;
      };
      return {
        ...prev,
        videoClips: splitTrack(prev.videoClips),
        subtitleTrack: splitTrack(prev.subtitleTrack),
        textTrack: splitTrack(prev.textTrack),
        audioTrack: splitTrack(prev.audioTrack),
      };
    });
  }, []);

  const handleTrim = useCallback((trackName: keyof VideoState, id: string, startTime: number, duration: number) => {
    setState(prev => {
      const track = prev[trackName] as any[];
      if (!Array.isArray(track)) return prev;
      return { 
        ...prev, 
        [trackName]: track.map(item => item.id === id ? { ...item, startTime, duration: Math.max(0.1, duration) } : item) 
      };
    });
  }, []);

  const handleDelete = useCallback(() => {
    setState(prev => {
      const { currentTime, selectedTextId } = prev;
      const filterItem = (item: { id: string, startTime: number, duration: number }) => {
        if (item.id === selectedTextId) return false;
        return currentTime < item.startTime || currentTime > item.startTime + item.duration;
      };
      return {
        ...prev,
        videoClips: prev.videoClips.filter(filterItem),
        subtitleTrack: prev.subtitleTrack.filter(filterItem),
        textTrack: prev.textTrack.filter(filterItem),
        audioTrack: prev.audioTrack.filter(filterItem),
        selectedTextId: undefined
      };
    });
  }, []);

  const handleAddText = useCallback((styleId: string) => {
    const id = Math.random().toString(36);
    const newText: TextBlock = {
      id,
      text: styleId === 'sub' ? 'Double click to edit text' : 'NEW TITLE',
      startTime: state.currentTime,
      duration: 3,
      animation: 'pop',
      style: { 
        fontFamily: styleId === 'sub' ? 'Inter' : 'Orbitron', 
        fontSize: styleId === 'sub' ? 24 : 64, 
        color: '#ffffff', 
        x: 50, 
        y: styleId === 'sub' ? 80 : 50, 
        opacity: 1, 
        shadow: '0 0 10px rgba(0,0,0,0.5)',
        fontWeight: '700',
        textAlign: 'center'
      }
    };
    setState(prev => ({ ...prev, textTrack: [...prev.textTrack, newText], selectedTextId: id, activeMode: 'text' }));
  }, [state.currentTime]);

  const handleUpdateTextProperty = useCallback((id: string, updates: Partial<TextBlock> | { style: Partial<TextBlock['style']> }) => {
    setState(prev => ({
      ...prev,
      textTrack: prev.textTrack.map(t => {
        if (t.id !== id) return t;
        if ('style' in updates) {
          return { ...t, style: { ...t.style, ...updates.style } };
        }
        return { ...t, ...updates };
      })
    }));
  }, []);

  const handleAddAudio = useCallback((trackName: string) => {
    const newAudio: AudioBlock = {
      id: Math.random().toString(36),
      name: trackName,
      startTime: state.currentTime,
      duration: 5,
      volume: 0.8,
      type: trackName.includes('Beat') ? 'music' : 'sfx'
    };
    setState(prev => ({ ...prev, audioTrack: [...prev.audioTrack, newAudio] }));
  }, [state.currentTime]);

  const getInterpolatedValue = (keyframes: Keyframe[], time: number, defaultValue: number): number => {
    if (keyframes.length === 0) return defaultValue;
    if (time <= keyframes[0].time) return keyframes[0].value;
    if (time >= keyframes[keyframes.length - 1].time) return keyframes[keyframes.length - 1].value;

    for (let i = 0; i < keyframes.length - 1; i++) {
      const k1 = keyframes[i];
      const k2 = keyframes[i + 1];
      if (time >= k1.time && time <= k2.time) {
        const t = (time - k1.time) / (k2.time - k1.time);
        return k1.value + (k2.value - k1.value) * t;
      }
    }
    return defaultValue;
  };

  useEffect(() => {
    setState(prev => {
      const { keyframes } = prev.transform;
      const newTransform = { ...prev.transform };
      let changed = false;

      Object.keys(keyframes).forEach(prop => {
        const keys = keyframes[prop];
        if (keys.length > 0) {
          const currentVal = prev.transform[prop as keyof VideoTransform] as number;
          const interpolated = getInterpolatedValue(keys, prev.currentTime, currentVal);
          if (interpolated !== currentVal) {
            (newTransform as any)[prop] = interpolated;
            changed = true;
          }
        }
      });

      return changed ? { ...prev, transform: newTransform } : prev;
    });
  }, [state.currentTime]);

  const handleUpdateTransform = useCallback((prop: keyof VideoTransform, value: number) => {
    setState(prev => {
      const newTransform = { ...prev.transform, [prop]: value };
      const currentKeys = prev.transform.keyframes[prop as string] || [];
      const existingKeyIndex = currentKeys.findIndex(k => Math.abs(k.time - prev.currentTime) < 0.05);

      if (existingKeyIndex !== -1) {
        const newKeys = [...currentKeys];
        newKeys[existingKeyIndex] = { ...newKeys[existingKeyIndex], value };
        newTransform.keyframes = { ...newTransform.keyframes, [prop as string]: newKeys };
      } else if (currentKeys.length > 0) {
        const newKey: Keyframe = { id: Math.random().toString(36), time: prev.currentTime, value };
        const newKeys = [...currentKeys, newKey].sort((a, b) => a.time - b.time);
        newTransform.keyframes = { ...newTransform.keyframes, [prop as string]: newKeys };
      }

      return { ...prev, transform: newTransform };
    });
  }, []);

  const handleToggleKeyframe = useCallback((prop: string) => {
    setState(prev => {
      const currentKeys = prev.transform.keyframes[prop] || [];
      const existingIndex = currentKeys.findIndex(k => Math.abs(k.time - prev.currentTime) < 0.1);
      let newKeys: Keyframe[];

      if (existingIndex !== -1) {
        newKeys = currentKeys.filter((_, i) => i !== existingIndex);
      } else {
        const val = prev.transform[prop as keyof VideoTransform] as number;
        newKeys = [...currentKeys, { id: Math.random().toString(36), time: prev.currentTime, value: val }].sort((a, b) => a.time - b.time);
      }

      return { 
        ...prev, 
        transform: { 
          ...prev.transform, 
          keyframes: { ...prev.transform.keyframes, [prop]: newKeys } 
        } 
      };
    });
  }, []);

  return {
    state,
    setState,
    handleTimeUpdate,
    togglePlay,
    handleSplit,
    handleTrim,
    handleDelete,
    handleAddText,
    handleUpdateTextProperty,
    handleAddAudio,
    handleToggleKeyframe,
    handleUpdateTransform
  };
};

import React, { useRef, useEffect } from 'react';
import { VideoState, FilterPreset } from '../types';
import { Play, Pause, Activity } from 'lucide-react';

interface VideoPlayerProps {
  state: VideoState;
  onTimeUpdate: (time: number) => void;
  onDurationChange: (duration: number) => void;
  onTogglePlay: () => void;
  onSelectText: (id: string) => void;
}

const getFilterCSS = (preset: FilterPreset): string => {
    switch (preset) {
        case 'vibrant': return 'saturate(1.5) contrast(1.1)';
        case 'cinema': return 'sepia(0.2) contrast(1.2) brightness(0.9) saturate(0.8)';
        case 'vintage': return 'sepia(0.5) contrast(0.8) brightness(1.1)';
        case 'bw': return 'grayscale(1)';
        case 'cyber': return 'hue-rotate(180deg) saturate(2) brightness(1.2)';
        default: return 'none';
    }
};

const VideoPlayer: React.FC<VideoPlayerProps> = ({ state, onTimeUpdate, onDurationChange, onTogglePlay, onSelectText }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if (videoRef.current) {
      if (state.isPlaying && videoRef.current.paused) {
        videoRef.current.play().catch(() => {});
      } else if (!state.isPlaying && !videoRef.current.paused) {
        videoRef.current.pause();
      }
    }
  }, [state.isPlaying]);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.volume = state.volume;
      videoRef.current.playbackRate = state.playbackSpeed;
    }
  }, [state.volume, state.playbackSpeed]);

  useEffect(() => {
    if (videoRef.current && Math.abs(videoRef.current.currentTime - state.currentTime) > 0.5) {
      videoRef.current.currentTime = state.currentTime;
    }
  }, [state.currentTime]);

  const activeSub = state.subtitleTrack.find(s => state.currentTime >= s.startTime && state.currentTime <= s.startTime + s.duration);
  const activeTextOverlays = state.textTrack.filter(t => state.currentTime >= t.startTime && state.currentTime <= t.startTime + t.duration);

  const filterString = `
    brightness(${state.adjustment.brightness}%)
    contrast(${state.adjustment.contrast}%)
    saturate(${state.adjustment.saturation}%)
    blur(${state.adjustment.blur}px)
    hue-rotate(${state.adjustment.hue}deg)
    ${getFilterCSS(state.activeFilter)}
  `;

  return (
    <div className="relative w-full h-full flex items-center justify-center p-4">
      <div className={`relative overflow-hidden bg-black aspect-video max-h-[85vh] w-full transition-all duration-700 shadow-2xl border ${state.isAnalyzing ? 'border-white/50' : 'border-[#1a1a1a]'}`}>

         {state.isAnalyzing && (
            <div className="absolute inset-0 z-30 pointer-events-none bg-white/5">
                <div className="absolute top-0 left-0 w-full h-[1px] bg-white/40 animate-[scan_1.5s_linear_infinite]"></div>
                <div className="absolute bottom-4 left-4 flex items-center gap-2">
                    <Activity className="w-3 h-3 text-white/50" />
                    <span className="text-[8px] font-mono text-white/50 uppercase tracking-widest">Applying AI Adjustments...</span>
                </div>
            </div>
         )}

         <video
            ref={videoRef}
            className="w-full h-full object-contain"
            style={{ 
                filter: filterString,
                transform: `scale(${state.transform.scale}) translate(${state.transform.positionX}px, ${state.transform.positionY}px) rotate(${state.transform.rotation}deg)`,
                opacity: state.transform.opacity / 100
            }}
            src={state.videoClips[0]?.url}
            loop
            playsInline
            onTimeUpdate={(e) => onTimeUpdate(e.currentTarget.currentTime)}
            onLoadedMetadata={(e) => onDurationChange(e.currentTarget.duration)}
         />

         {/* Subtitles Overlay */}
         <div className="absolute inset-x-0 bottom-12 pointer-events-none flex justify-center px-12 z-20">
            {activeSub && (
                <div className="bg-black/80 px-4 py-1.5 rounded text-white text-base font-medium shadow-lg backdrop-blur-sm border border-white/10">
                    {activeSub.text}
                </div>
            )}
         </div>

         {/* Text/Typography Overlays */}
         <div className="absolute inset-0 z-20 overflow-hidden pointer-events-none">
             {activeTextOverlays.map(text => (
                 <div 
                    key={text.id}
                    onClick={(e) => { e.stopPropagation(); onSelectText(text.id); }}
                    onDoubleClick={(e) => { e.stopPropagation(); onSelectText(text.id); }}
                    className={`absolute whitespace-pre-wrap transition-all transform -translate-x-1/2 -translate-y-1/2 cursor-pointer pointer-events-auto group ${state.selectedTextId === text.id ? 'outline outline-1 outline-blue-500 outline-offset-4 ring-2 ring-blue-500/20' : ''}`}
                    style={{
                        left: `${text.style.x}%`,
                        top: `${text.style.y}%`,
                        fontSize: `${text.style.fontSize}px`,
                        color: text.style.color,
                        opacity: text.style.opacity,
                        fontFamily: text.style.fontFamily,
                        textShadow: text.style.shadow,
                        fontWeight: text.style.fontWeight || 'normal',
                        textAlign: text.style.textAlign || 'center',
                    }}
                 >
                     {text.text}
                     {state.selectedTextId === text.id && (
                         <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-blue-500 text-[8px] font-black uppercase px-2 py-0.5 rounded text-white whitespace-nowrap tracking-widest animate-in fade-in zoom-in duration-200">
                             Editing Layer
                         </div>
                     )}
                 </div>
             ))}
         </div>

         <div className="absolute inset-0 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity bg-black/10 cursor-pointer z-10" onClick={onTogglePlay}>
            <div className="p-4 bg-white/10 backdrop-blur-md rounded-full border border-white/20">
                {state.isPlaying ? <Pause className="w-8 h-8 text-white" /> : <Play className="w-8 h-8 text-white ml-1" />}
            </div>
         </div>
      </div>

      <style>{`
        @keyframes scan {
          0% { top: 0%; }
          100% { top: 100%; }
        }
      `}</style>
    </div>
  );
};

export default VideoPlayer;

import React from 'react';
import { VideoState, VideoTransform, VideoAdjustment, ChromaKey, TextBlock } from '../types';
import { Maximize, Diamond, Palette, Scissors, Type, AlignLeft, AlignCenter, AlignRight, Bold } from 'lucide-react';

interface PropertiesPanelProps {
  state: VideoState;
  onChangeTransform: (transform: VideoTransform) => void;
  onUpdateTransformProperty: (prop: keyof VideoTransform, value: number) => void;
  onChangeAdjustment: (adj: VideoAdjustment) => void;
  onToggleKeyframe: (prop: string) => void;
  onChangeChromaKey: (chroma: ChromaKey) => void;
  onUpdateText: (id: string, updates: Partial<TextBlock> | { style: Partial<TextBlock['style']> }) => void;
}

const FONTS = ['Inter', 'Orbitron', 'JetBrains Mono', 'Impact', 'Arial', 'Times New Roman'];

const PropertiesPanel: React.FC<PropertiesPanelProps> = ({ 
  state, 
  onUpdateTransformProperty, 
  onChangeAdjustment, 
  onToggleKeyframe, 
  onChangeChromaKey,
  onUpdateText
}) => {

  const selectedText = state.textTrack.find(t => t.id === state.selectedTextId);

  const KeyframeButton = ({ prop }: { prop: string }) => {
      const hasKeyAtCurrent = state.transform.keyframes[prop]?.some(k => Math.abs(k.time - state.currentTime) < 0.1);
      return (
          <button 
            onClick={() => onToggleKeyframe(prop)}
            className={`transition-all p-1 rounded ${hasKeyAtCurrent ? 'text-white' : 'text-slate-800 hover:text-slate-600'}`} 
            title={hasKeyAtCurrent ? "Remove Keyframe" : "Add Keyframe"}
          >
              <Diamond className={`w-2.5 h-2.5 ${hasKeyAtCurrent ? 'fill-current' : ''}`} />
          </button>
      );
  };

  const Section = ({ icon: Icon, title, children }: { icon: any, title: string, children?: React.ReactNode }) => (
      <div className="space-y-4">
          <h3 className="text-[9px] font-black text-slate-600 uppercase tracking-[0.3em] flex items-center gap-2">
              <Icon className="w-3 h-3" /> {title}
          </h3>
          <div className="space-y-4 bg-black p-3 rounded border border-[#1a1a1a]">
              {children}
          </div>
      </div>
  );

  return (
    <div className="h-full bg-black flex flex-col custom-scrollbar overflow-y-auto">
        <div className="p-4 space-y-8 pb-20">

            {selectedText && (
                <Section icon={Type} title="Typography">
                    <div className="space-y-4">
                        <div className="space-y-1.5">
                            <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Content</label>
                            <textarea 
                                value={selectedText.text}
                                onChange={(e) => onUpdateText(selectedText.id, { text: e.target.value })}
                                className="w-full bg-[#0a0a0a] border border-[#1a1a1a] rounded p-2 text-[10px] text-white focus:border-white focus:outline-none h-16 resize-none"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                            <div className="space-y-1.5">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Font Face</label>
                                <select 
                                    value={selectedText.style.fontFamily}
                                    onChange={(e) => onUpdateText(selectedText.id, { style: { fontFamily: e.target.value } })}
                                    className="w-full bg-[#0a0a0a] border border-[#1a1a1a] rounded p-1.5 text-[10px] text-white focus:border-white outline-none"
                                >
                                    {FONTS.map(f => <option key={f} value={f}>{f}</option>)}
                                </select>
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Size</label>
                                <input 
                                    type="number"
                                    value={selectedText.style.fontSize}
                                    onChange={(e) => onUpdateText(selectedText.id, { style: { fontSize: parseInt(e.target.value) || 1 } })}
                                    className="w-full bg-[#0a0a0a] border border-[#1a1a1a] rounded p-1.5 text-[10px] text-white focus:border-white outline-none"
                                />
                            </div>
                        </div>

                        <div className="flex items-center gap-2">
                            <div className="flex-1 space-y-1.5">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Color</label>
                                <div className="flex items-center gap-2 bg-[#0a0a0a] border border-[#1a1a1a] rounded p-1">
                                    <input 
                                        type="color"
                                        value={selectedText.style.color}
                                        onChange={(e) => onUpdateText(selectedText.id, { style: { color: e.target.value } })}
                                        className="w-6 h-6 rounded border-none bg-transparent cursor-pointer"
                                    />
                                    <span className="text-[9px] font-mono text-white uppercase">{selectedText.style.color}</span>
                                </div>
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Weight</label>
                                <button 
                                    onClick={() => onUpdateText(selectedText.id, { style: { fontWeight: selectedText.style.fontWeight === '700' ? '400' : '700' } })}
                                    className={`p-2 rounded border transition-all ${selectedText.style.fontWeight === '700' ? 'bg-white text-black border-white' : 'border-[#1a1a1a] text-slate-500'}`}
                                >
                                    <Bold className="w-3 h-3" />
                                </button>
                            </div>
                        </div>

                        <div className="space-y-1.5">
                            <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Alignment</label>
                            <div className="flex bg-[#0a0a0a] border border-[#1a1a1a] rounded overflow-hidden">
                                {(['left', 'center', 'right'] as const).map(align => (
                                    <button 
                                        key={align}
                                        onClick={() => onUpdateText(selectedText.id, { style: { textAlign: align } })}
                                        className={`flex-1 flex items-center justify-center p-2 hover:bg-white/5 transition-all ${selectedText.style.textAlign === align ? 'bg-white/10 text-white border-x border-white/10' : 'text-slate-600'}`}
                                    >
                                        {align === 'left' && <AlignLeft className="w-3.5 h-3.5" />}
                                        {align === 'center' && <AlignCenter className="w-3.5 h-3.5" />}
                                        {align === 'right' && <AlignRight className="w-3.5 h-3.5" />}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                             <div className="space-y-1.5">
                                <div className="flex justify-between items-center">
                                    <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Pos X %</label>
                                    <span className="text-[9px] text-white">{selectedText.style.x}%</span>
                                </div>
                                <input 
                                    type="range" min="0" max="100"
                                    value={selectedText.style.x}
                                    onChange={(e) => onUpdateText(selectedText.id, { style: { x: parseInt(e.target.value) } })}
                                    className="w-full"
                                />
                            </div>
                            <div className="space-y-1.5">
                                <div className="flex justify-between items-center">
                                    <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Pos Y %</label>
                                    <span className="text-[9px] text-white">{selectedText.style.y}%</span>
                                </div>
                                <input 
                                    type="range" min="0" max="100"
                                    value={selectedText.style.y}
                                    onChange={(e) => onUpdateText(selectedText.id, { style: { y: parseInt(e.target.value) } })}
                                    className="w-full"
                                />
                            </div>
                        </div>
                    </div>
                </Section>
            )}

            <Section icon={Maximize} title="Spatial">
                {[
                    { label: 'Scale', prop: 'scale', min: 0.1, max: 2, step: 0.01 },
                    { label: 'Rotate', prop: 'rotation', min: -180, max: 180, step: 1 },
                    { label: 'Opac', prop: 'opacity', min: 0, max: 100, step: 1 },
                    { label: 'X_Pos', prop: 'positionX', min: -500, max: 500, step: 1 },
                ].map(item => {
                    const value = state.transform[item.prop as keyof VideoTransform] as number;
                    return (
                        <div key={item.prop} className="space-y-1.5">
                            <div className="flex justify-between items-center">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">{item.label}</label>
                                <div className="flex items-center gap-2">
                                    <span className="text-[9px] font-mono text-white">
                                        {typeof value === 'number' ? value.toFixed(2) : value}
                                    </span>
                                    <KeyframeButton prop={item.prop} />
                                </div>
                            </div>
                            <input 
                                type="range" 
                                min={item.min} 
                                max={item.max} 
                                step={item.step}
                                value={value}
                                onChange={(e) => onUpdateTransformProperty(item.prop as keyof VideoTransform, parseFloat(e.target.value))}
                                className="w-full"
                            />
                        </div>
                    );
                })}
