         {/* Diagnostic Overlay */}
         <div className="absolute inset-0 z-50 pointer-events-none border border-white/5">
             <div className="absolute top-1/2 left-0 w-full h-[1px] bg-white/5"></div>
             <div className="absolute top-0 left-1/2 w-[1px] h-full bg-white/5"></div>
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2">
                 <Target className="w-12 h-12 text-white/5 stroke-[0.5]" />
