             {/* Dynamic Data Blocks */}
             <div className="absolute top-4 left-4 p-2 bg-black/40 border border-white/5 rounded backdrop-blur-sm">
                 <div className="flex gap-2">
                     <div className="w-1 h-8 bg-blue-500/40 animate-pulse"></div>
                     <div className="flex flex-col gap-1">
                         <span className="text-[6px] text-white font-black">SPATIAL_SYNC</span>
