import React, { useState, useRef, useEffect, useCallback } from 'react';
import { createGeminiSession } from '../services/geminiService';
import { ChatMessage, ToolNames, ToolArgs, VideoState, SubtitleBlock, FilterPreset, EffectBlock, EffectType, DirectorialLogEntry } from '../types';
import { Chat } from '@google/genai';
import { INITIAL_CHAT_MESSAGE } from '../constants';

export const useAIController = (videoState: VideoState, setVideoState: React.Dispatch<React.SetStateAction<VideoState>>) => {
  const [messages, setMessages] = useState<ChatMessage[]>([{ id: 'init', role: 'model', content: INITIAL_CHAT_MESSAGE }]);
  const [isProcessing, setIsProcessing] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);

  useEffect(() => {
    chatSessionRef.current = createGeminiSession();
  }, []);

  const addLog = useCallback((action: string, type: 'ai' | 'user' = 'ai') => {
    const entry: DirectorialLogEntry = {
        id: Math.random().toString(36),
        timestamp: Date.now(),
        action,
        type
    };
    setVideoState(prev => ({ ...prev, directorialLog: [entry, ...prev.directorialLog].slice(0, 10) }));
  }, [setVideoState]);

  const handleSendMessage = useCallback(async (userMessage: string) => {
    if (!chatSessionRef.current) return;
    setIsProcessing(true);
    setMessages(prev => [...prev, { id: Date.now().toString(), role: 'user', content: userMessage }]);
    addLog(userMessage, 'user');

    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMessage });
      const functionCalls = result.functionCalls;

      if (functionCalls && functionCalls.length > 0) {
        const responses: any[] = [];
        for (const call of functionCalls) {
          const toolName = call.name;
          const args = call.args as ToolArgs;
          let responseResult = { result: "Operation Successful" };

          setVideoState(prev => ({ ...prev, isAnalyzing: true }));

          switch (toolName) {
            case ToolNames.ADD_SUBTITLE:
              const newSub: SubtitleBlock = {
                id: Math.random().toString(36),
                text: args.text,
                startTime: args.startTime ?? videoState.currentTime,
                duration: args.duration ?? 3
              };
              setVideoState(prev => ({ 
                ...prev, 
                subtitleTrack: [...prev.subtitleTrack, newSub],
                lastDirectorialAction: `Subtitle node injected: "${args.text}"`
              }));
              addLog(`Injected subtitle: ${args.text}`);
              break;

            case ToolNames.SET_FILTER:
              setVideoState(prev => ({ 
                ...prev, 
                activeFilter: args.filter as FilterPreset,
                lastDirectorialAction: `Neural color grade calibrated: ${args.filter}`
              }));
              addLog(`Calibrated color grade: ${args.filter}`);
              break;

            case ToolNames.ADJUST_TRANSFORM:
                setVideoState(prev => ({
                    ...prev,
                    transform: {
                        ...prev.transform,
                        scale: args.scale ?? prev.transform.scale,
                        rotation: args.rotation ?? prev.transform.rotation,
                        opacity: args.opacity ?? prev.transform.opacity
                    },
                    lastDirectorialAction: 'Spatial parameters updated.'
                }));
                addLog('Spatial parameters synchronized.');
                break;

            case ToolNames.ADD_EFFECT:
              const newFx: EffectBlock = {
                id: Math.random().toString(36),
                type: args.type as EffectType,
                startTime: args.startTime ?? videoState.currentTime,
                duration: args.duration ?? 5,
                intensity: args.intensity ?? 50
              };
              setVideoState(prev => ({
                ...prev,
                effectTrack: [...prev.effectTrack, newFx],
                lastDirectorialAction: `VFX Overlay enabled: ${args.type}`
              }));
              addLog(`Overlayed VFX: ${args.type}`);
              break;

            case ToolNames.DIRECTOR_MOVE:
                setVideoState(prev => ({
                    ...prev,
                    activeFilter: (args.filter as FilterPreset) ?? prev.activeFilter,
                    transform: {
                        ...prev.transform,
                        scale: args.zoom ?? prev.transform.scale
                    },
                    effectTrack: args.effect && args.effect !== 'none' ? [...prev.effectTrack, {
                        id: Math.random().toString(36),
                        type: args.effect as EffectType,
                        startTime: prev.currentTime,
                        duration: 5,
                        intensity: 75
                    }] : prev.effectTrack,
                    lastDirectorialAction: `Move Executed: ${args.moveName}`
                }));
                addLog(`Executed Director Move: ${args.moveName}`);
                break;

            case ToolNames.SET_CLIP_TRANSITION:
                setVideoState(prev => ({
                    ...prev,
                    videoClips: prev.videoClips.map(c => {
                        const isTarget = args.clipId ? c.id === args.clipId : (prev.currentTime >= c.startTime && prev.currentTime <= c.startTime + c.duration);
                        if (isTarget) {
                            return {
                                ...c,
                                fadeInDuration: args.fadeIn ?? c.fadeInDuration,
                                fadeOutDuration: args.fadeOut ?? c.fadeOutDuration
                            };
                        }
                        return c;
                    }),
                    lastDirectorialAction: 'Clip transitions recalibrated.'
                }));
                addLog(`Recalibrated clip transitions (In: ${args.fadeIn}s, Out: ${args.fadeOut}s)`);
                break;
          }
          responses.push({ name: toolName, response: responseResult, id: call.id });
        }

        const finalResponse = await chatSessionRef.current.sendToolResponse({ functionResponses: responses });
        if (finalResponse.text) setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: finalResponse.text }]);
      } else if (result.text) {
        setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: result.text }]);
      }
    } catch (error) {
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: "Interface sync lost. Neural reboot suggested." }]);
    } finally {
      setIsProcessing(false);
      setTimeout(() => setVideoState(prev => ({ ...prev, isAnalyzing: false })), 500);
    }
  }, [setVideoState, videoState.currentTime, addLog]);

  return { messages, isProcessing, handleSendMessage };
};

