interface TimelineProps {
  state: VideoState;
  onSeek: (time: number) => void;
  onSplit: () => void;
  onDelete: () => void;
  onTrim: (trackName: keyof VideoState, id: string, startTime: number, duration: number) => void;
  onSelectClip?: (id: string) => void;
  onUpdateClipFade?: (id: string, updates: { fadeInDuration?: number, fadeOutDuration?: number }) => void;
}

const Timeline: React.FC<TimelineProps> = ({ state, onSeek, onSplit, onDelete, onTrim, onSelectClip, onUpdateClipFade }) => {
  const percentage = (state.currentTime / state.duration) * 100;
  const timelineRef = useRef<HTMLDivElement>(null);

  const [dragState, setDragState] = useState<{
    trackName: keyof VideoState;
    id: string;
    type: 'trim' | 'fade-in' | 'fade-out';
    edge?: 'start' | 'end';
    initialMouseX: number;
    initialStartTime: number;
    initialDuration: number;
    initialFadeIn?: number;
    initialFadeOut?: number;
  } | null>(null);

  const handleTimelineClick = (e: React.MouseEvent<HTMLDivElement>) => {
    if ((e.target as HTMLElement).closest('.timeline-item-handle')) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const clickPercentage = x / rect.width;
    const newTime = Math.max(0, Math.min(state.duration, clickPercentage * state.duration));
    onSeek(newTime);
  };

  const onStartTrim = (e: React.MouseEvent, trackName: keyof VideoState, id: string, edge: 'start' | 'end', startTime: number, duration: number) => {
    e.stopPropagation();
    setDragState({
      trackName,
      id,
      type: 'trim',
      edge,
      initialMouseX: e.clientX,
      initialStartTime: startTime,
      initialDuration: duration
    });
  };

  const onStartFadeDrag = (e: React.MouseEvent, id: string, type: 'fade-in' | 'fade-out', initialFade: number) => {
    e.stopPropagation();
    const clip = state.videoClips.find(c => c.id === id);
    if (!clip) return;
    setDragState({
      trackName: 'videoClips',
      id,
      type,
      initialMouseX: e.clientX,
      initialStartTime: clip.startTime,
      initialDuration: clip.duration,
      initialFadeIn: clip.fadeInDuration,
      initialFadeOut: clip.fadeOutDuration
    });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragState || !timelineRef.current) return;
      const timelineWidth = timelineRef.current.getBoundingClientRect().width;
      const dx = ((e.clientX - dragState.initialMouseX) / timelineWidth) * state.duration;

      if (dragState.type === 'trim') {
        let newStartTime = dragState.initialStartTime;
        let newDuration = dragState.initialDuration;
        if (dragState.edge === 'start') {
          newStartTime = Math.max(0, dragState.initialStartTime + dx);
          newDuration = Math.max(0.1, dragState.initialDuration - (newStartTime - dragState.initialStartTime));
        } else {
          newDuration = Math.max(0.1, dragState.initialDuration + dx);
        }
        onTrim(dragState.trackName, dragState.id, newStartTime, newDuration);
      } else if (dragState.type === 'fade-in' && onUpdateClipFade) {
        const newFade = Math.max(0, Math.min(dragState.initialDuration / 2, (dragState.initialFadeIn || 0) + dx));
        onUpdateClipFade(dragState.id, { fadeInDuration: newFade });
      } else if (dragState.type === 'fade-out' && onUpdateClipFade) {
        const newFade = Math.max(0, Math.min(dragState.initialDuration / 2, (dragState.initialFadeOut || 0) - dx));
        onUpdateClipFade(dragState.id, { fadeOutDuration: newFade });
      }
    };
    const handleMouseUp = () => setDragState(null);
    if (dragState) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragState, state.duration, onTrim, onUpdateClipFade]);

  const TrackHeader = ({ icon: Icon, label }: { icon: any, label: string }) => (
    <div className="absolute left-2 top-1/2 -translate-y-1/2 flex items-center gap-1.5 z-10 pointer-events-none opacity-40 bg-black/80 px-1.5 py-0.5 rounded border border-[#1a1a1a]">
      <Icon className="w-2.5 h-2.5 text-slate-400" />
      <span className="text-[7px] font-mono text-slate-400 tracking-tighter uppercase">{label}</span>
    </div>
  );

  const renderClip = (item: any, trackName: keyof VideoState, className: string, children?: React.ReactNode) => {
    const left = (item.startTime / state.duration) * 100;
    const width = (item.duration / state.duration) * 100;
    const isClipSelected = (trackName === 'videoClips' && state.selectedClipId === item.id) || 
                          (trackName === 'textTrack' && state.selectedTextId === item.id);
    const isHoveredActive = state.currentTime >= item.startTime && state.currentTime <= item.startTime + item.duration;

    return (
      <div 
        key={item.id}
        onClick={(e) => { e.stopPropagation(); trackName === 'videoClips' && onSelectClip?.(item.id); }}
        className={`absolute top-1 bottom-1 rounded border overflow-hidden cursor-pointer group transition-all bg-[#121212] border-[#222] ${isClipSelected ? 'ring-2 ring-blue-500 z-30 bg-[#1a1a1a]' : isHoveredActive ? 'bg-[#1a1a1a] border-white/20' : 'hover:bg-[#151515]'} ${className}`}
        style={{ left: `${left}%`, width: `${width}%` }}
      >
        <div 
          className="trim-handle timeline-item-handle absolute left-0 top-0 bottom-0 w-1 bg-white/10 hover:bg-white/30 cursor-ew-resize opacity-0 group-hover:opacity-100 transition-opacity z-10"
          onMouseDown={(e) => onStartTrim(e, trackName, item.id, 'start', item.startTime, item.duration)}
        />

        {/* Transition Fade Handles for Media Clips */}
        {trackName === 'videoClips' && (
          <>
            <div 
              className="timeline-item-handle absolute left-0 top-0 w-3 h-3 bg-white/10 hover:bg-white/40 cursor-ew-resize z-20 rounded-br-full border-b border-r border-white/20"
              title="Fade In"
              onMouseDown={(e) => onStartFadeDrag(e, item.id, 'fade-in', item.fadeInDuration || 0)}
            />
            <div 
              className="timeline-item-handle absolute right-0 top-0 w-3 h-3 bg-white/10 hover:bg-white/40 cursor-ew-resize z-20 rounded-bl-full border-b border-l border-white/20"
              title="Fade Out"
              onMouseDown={(e) => onStartFadeDrag(e, item.id, 'fade-out', item.fadeOutDuration || 0)}
            />
            {/* Visual Fade indicators */}
            {item.fadeInDuration > 0 && (
                <div className="absolute top-0 bottom-0 left-0 bg-gradient-to-r from-black/50 to-transparent pointer-events-none" style={{ width: `${(item.fadeInDuration / item.duration) * 100}%` }} />
            )}
            {item.fadeOutDuration > 0 && (
                <div className="absolute top-0 bottom-0 right-0 bg-gradient-to-l from-black/50 to-transparent pointer-events-none" style={{ width: `${(item.fadeOutDuration / item.duration) * 100}%` }} />
            )}
          </>
        )}

        <div className="flex items-center h-full px-2 overflow-hidden pointer-events-none">
            {children}
        </div>
        <div 
          className="trim-handle timeline-item-handle absolute right-0 top-0 bottom-0 w-1 bg-white/10 hover:bg-white/30 cursor-ew-resize opacity-0 group-hover:opacity-100 transition-opacity z-10"
          onMouseDown={(e) => onStartTrim(e, trackName, item.id, 'end', item.startTime, item.duration)}
        />
      </div>
    );
  };

  return (
    <div className="w-full h-full flex flex-col bg-black border-t border-[#1a1a1a] select-none">
      <div className="h-10 border-b border-[#1a1a1a] bg-black flex items-center justify-between px-4">
         <div className="flex items-center gap-1">
            <button onClick={onSplit} className="p-2 hover:bg-[#0a0a0a] rounded text-slate-500 hover:text-white transition-all flex items-center gap-2 px-3 border border-transparent hover:border-[#1a1a1a]"><Scissors className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Split</span></button>
            <button onClick={onDelete} className="p-2 hover:bg-[#0a0a0a] rounded text-slate-500 hover:text-red-500 transition-all flex items-center gap-2 px-3 border border-transparent hover:border-[#1a1a1a]"><Trash2 className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Delete</span></button>
            <div className="w-[1px] h-4 bg-[#1a1a1a] mx-2"></div>
            <button className="p-2 text-white/50 hover:text-white"><Magnet className="w-3.5 h-3.5" /></button>
         </div>
         <div className="flex items-center gap-4">
            <div className="text-[9px] font-mono text-white bg-[#0a0a0a] px-2 py-0.5 rounded border border-[#1a1a1a] tracking-widest">
                {new Date(state.currentTime * 1000).toISOString().substr(14, 9)} / {new Date(state.duration * 1000).toISOString().substr(14, 5)}
            </div>
            <div className="flex items-center gap-2">
                <ZoomOut className="w-3 h-3 text-slate-700" />
                <div className="w-16 h-[1px] bg-[#1a1a1a]"><div className="w-1/3 h-full bg-slate-400"></div></div>
                <ZoomIn className="w-3 h-3 text-slate-700" />
            </div>
         </div>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar relative bg-[#050505]">
        <div className="relative min-h-[400px] p-2" ref={timelineRef} onClick={handleTimelineClick}>
            <div className="absolute top-0 bottom-0 w-[1px] bg-white z-50 pointer-events-none" style={{ left: `${percentage}%` }}>
                <div className="absolute -top-1 -left-[3px] w-1.5 h-4 bg-white rounded-sm shadow-[0_0_10px_white]"></div>
            </div>

            {/* Keyframe Track */}
            <div className="mb-1 relative h-6 w-full bg-black rounded-sm border border-[#1a1a1a]">
                 <TrackHeader icon={Zap} label="Keys" />
                 {Object.entries(state.transform.keyframes).map(([prop, keys]) => (
                     (keys as Keyframe[]).map(k => (
                         <div key={k.id} className="absolute top-1/2 -translate-y-1/2 w-1.5 h-1.5 bg-blue-500 rotate-45 z-40 border border-white/50" style={{ left: `${(k.time / state.duration) * 100}%` }} />
                     ))
                 ))}
            </div>

            {/* Main Video Track */}
            <div className="mb-1 relative h-12 w-full bg-black rounded-sm border border-[#1a1a1a]">
                 <TrackHeader icon={FolderOpen} label="Media" />
                 {state.videoClips.map(clip => renderClip(clip, 'videoClips', 'border-l-blue-500 border-l-2', 
                    <div className="flex items-center gap-2 w-full h-full">
                        <img src={clip.thumbnail} className="h-full w-10 object-cover rounded-sm opacity-50" />
                        <span className="truncate text-[7px] font-bold uppercase tracking-wider text-slate-400">{clip.name}</span>
                    </div>
                 ))}
            </div>

            {/* FX Track */}
            <div className="mb-1 relative h-10 w-full bg-black rounded-sm border border-[#1a1a1a]">
                 <TrackHeader icon={Sparkles} label="VFX" />
                 {state.effectTrack.map(fx => renderClip(fx, 'effectTrack', 'border-l-orange-500 border-l-2 bg-orange-500/5', 
                    <span className="truncate text-[7px] uppercase tracking-widest text-orange-400 font-bold">{fx.type}</span>
                 ))}
            </div>

             <div className="relative h-10 w-full mb-1 bg-black rounded-sm border border-[#1a1a1a]">
                <TrackHeader icon={Subtitles} label="Subs" />
                {state.subtitleTrack.map(sub => renderClip(sub, 'subtitleTrack', 'border-l-yellow-500 border-l-2 bg-yellow-500/5', 
                    <span className="truncate text-[7px] uppercase tracking-widest text-slate-400 italic">{sub.text}</span>
                ))}
            </div>

            <div className="relative h-10 w-full mb-1 bg-black rounded-sm border border-[#1a1a1a]">
                <TrackHeader icon={Type} label="Text" />
                {state.textTrack.map(txt => renderClip(txt, 'textTrack', 'border-l-purple-500 border-l-2 bg-purple-500/5', 
                    <span className="truncate text-[7px] uppercase tracking-widest text-slate-400 font-bold">{txt.text}</span>
                ))}
            </div>

            <div className="relative h-10 w-full mb-1 bg-black rounded-sm border border-[#1a1a1a]">
                <TrackHeader icon={Music} label="Audio" />
                {state.audioTrack.map(aud => renderClip(aud, 'audioTrack', 'border-l-green-500 border-l-2 bg-green-500/5', 
                    <div className="flex items-center gap-2">
                         <span className="truncate text-[7px] uppercase tracking-widest text-slate-500 font-mono">{aud.name}</span>
                         {aud.voiceEffect && aud.voiceEffect !== 'none' && <span className="text-[6px] bg-green-500/20 text-green-400 px-1 rounded uppercase">{aud.voiceEffect}</span>}
                    </div>
                ))}
            </div>
        </div>
      </div>
    </div>
  );
};

export default Timeline;

import React from 'react';
import { VideoState, VideoTransform, VideoAdjustment, ChromaKey, TextBlock, VideoClip } from '../types';
import { Maximize, Diamond, Palette, Scissors, Type, AlignLeft, AlignCenter, AlignRight, Bold, Play } from 'lucide-react';

interface PropertiesPanelProps {
  state: VideoState;
  onChangeTransform: (transform: VideoTransform) => void;
  onUpdateTransformProperty: (prop: keyof VideoTransform, value: number) => void;
  onChangeAdjustment: (adj: VideoAdjustment) => void;
  onToggleKeyframe: (prop: string) => void;
  onChangeChromaKey: (chroma: ChromaKey) => void;
  onUpdateText: (id: string, updates: Partial<TextBlock> | { style: Partial<TextBlock['style']> }) => void;
  onUpdateClip: (id: string, updates: Partial<VideoClip>) => void;
}

const FONTS = ['Inter', 'Orbitron', 'JetBrains Mono', 'Impact', 'Arial', 'Times New Roman'];

const PropertiesPanel: React.FC<PropertiesPanelProps> = ({ 
  state, 
  onUpdateTransformProperty, 
  onChangeAdjustment, 
  onToggleKeyframe, 
  onChangeChromaKey,
  onUpdateText,
  onUpdateClip
}) => {

  const selectedText = state.textTrack.find(t => t.id === state.selectedTextId);
  const selectedClip = state.videoClips.find(c => c.id === state.selectedClipId);

  const KeyframeButton = ({ prop }: { prop: string }) => {
      const hasKeyAtCurrent = state.transform.keyframes[prop]?.some(k => Math.abs(k.time - state.currentTime) < 0.1);
      return (
          <button 
            onClick={() => onToggleKeyframe(prop)}
            className={`transition-all p-1 rounded ${hasKeyAtCurrent ? 'text-white' : 'text-slate-800 hover:text-slate-600'}`} 
            title={hasKeyAtCurrent ? "Remove Keyframe" : "Add Keyframe"}
          >
              <Diamond className={`w-2.5 h-2.5 ${hasKeyAtCurrent ? 'fill-current' : ''}`} />
          </button>
      );
  };

  const Section = ({ icon: Icon, title, children }: { icon: any, title: string, children?: React.ReactNode }) => (
      <div className="space-y-4">
          <h3 className="text-[9px] font-black text-slate-600 uppercase tracking-[0.3em] flex items-center gap-2">
              <Icon className="w-3 h-3" /> {title}
          </h3>
          <div className="space-y-4 bg-black p-3 rounded border border-[#1a1a1a]">
              {children}
          </div>
      </div>
  );

  return (
    <div className="h-full bg-black flex flex-col custom-scrollbar overflow-y-auto">
        <div className="p-4 space-y-8 pb-20">

            {selectedClip && (
                <Section icon={Play} title="Transition">
                    <div className="space-y-4">
                        <div className="space-y-1.5">
                            <div className="flex justify-between items-center">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Fade In (s)</label>
                                <span className="text-[9px] text-white font-mono">{selectedClip.fadeInDuration?.toFixed(2)}s</span>
                            </div>
                            <input 
                                type="range" min="0" max={selectedClip.duration / 2} step="0.1"
                                value={selectedClip.fadeInDuration || 0}
                                onChange={(e) => onUpdateClip(selectedClip.id, { fadeInDuration: parseFloat(e.target.value) })}
                                className="w-full"
                            />
                        </div>
                        <div className="space-y-1.5">
                            <div className="flex justify-between items-center">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Fade Out (s)</label>
                                <span className="text-[9px] text-white font-mono">{selectedClip.fadeOutDuration?.toFixed(2)}s</span>
                            </div>
                            <input 
                                type="range" min="0" max={selectedClip.duration / 2} step="0.1"
                                value={selectedClip.fadeOutDuration || 0}
                                onChange={(e) => onUpdateClip(selectedClip.id, { fadeOutDuration: parseFloat(e.target.value) })}
                                className="w-full"
                            />
                        </div>
                        <div className="pt-2 border-t border-white/5">
                            <p className="text-[7px] text-slate-600 font-mono italic">Adjust the start and end opacity ramp of the media node.</p>
                        </div>
                    </div>
                </Section>
            )}

            {selectedText && (
                <Section icon={Type} title="Typography">
                    <div className="space-y-4">
                        <div className="space-y-1.5">
                            <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Content</label>
                            <textarea 
                                value={selectedText.text}
                                onChange={(e) => onUpdateText(selectedText.id, { text: e.target.value })}
                                className="w-full bg-[#0a0a0a] border border-[#1a1a1a] rounded p-2 text-[10px] text-white focus:border-white focus:outline-none h-16 resize-none"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                            <div className="space-y-1.5">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Font Face</label>
                                <select 
                                    value={selectedText.style.fontFamily}
                                    onChange={(e) => onUpdateText(selectedText.id, { style: { fontFamily: e.target.value } })}
                                    className="w-full bg-[#0a0a0a] border border-[#1a1a1a] rounded p-1.5 text-[10px] text-white focus:border-white outline-none"
                                >
                                    {FONTS.map(f => <option key={f} value={f}>{f}</option>)}
                                </select>
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Size</label>
                                <input 
                                    type="number"
                                    value={selectedText.style.fontSize}
                                    onChange={(e) => onUpdateText(selectedText.id, { style: { fontSize: parseInt(e.target.value) || 1 } })}
                                    className="w-full bg-[#0a0a0a] border border-[#1a1a1a] rounded p-1.5 text-[10px] text-white focus:border-white outline-none"
                                />
                            </div>
                        </div>

                        <div className="flex items-center gap-2">
                            <div className="flex-1 space-y-1.5">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Color</label>
                                <div className="flex items-center gap-2 bg-[#0a0a0a] border border-[#1a1a1a] rounded p-1">
                                    <input 
                                        type="color"
                                        value={selectedText.style.color}
                                        onChange={(e) => onUpdateText(selectedText.id, { style: { color: e.target.value } })}
                                        className="w-6 h-6 rounded border-none bg-transparent cursor-pointer"
                                    />
                                    <span className="text-[9px] font-mono text-white uppercase">{selectedText.style.color}</span>
                                </div>
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Weight</label>
                                <button 
                                    onClick={() => onUpdateText(selectedText.id, { style: { fontWeight: selectedText.style.fontWeight === '700' ? '400' : '700' } })}
                                    className={`p-2 rounded border transition-all ${selectedText.style.fontWeight === '700' ? 'bg-white text-black border-white' : 'border-[#1a1a1a] text-slate-500'}`}
                                >
                                    <Bold className="w-3 h-3" />
                                </button>
                            </div>
                        </div>

                        <div className="space-y-1.5">
                            <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Alignment</label>
                            <div className="flex bg-[#0a0a0a] border border-[#1a1a1a] rounded overflow-hidden">
                                {(['left', 'center', 'right'] as const).map(align => (
                                    <button 
                                        key={align}
                                        onClick={() => onUpdateText(selectedText.id, { style: { textAlign: align } })}
                                        className={`flex-1 flex items-center justify-center p-2 hover:bg-white/5 transition-all ${selectedText.style.textAlign === align ? 'bg-white/10 text-white border-x border-white/10' : 'text-slate-600'}`}
                                    >
                                        {align === 'left' && <AlignLeft className="w-3.5 h-3.5" />}
                                        {align === 'center' && <AlignCenter className="w-3.5 h-3.5" />}
                                        {align === 'right' && <AlignRight className="w-3.5 h-3.5" />}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                             <div className="space-y-1.5">
                                <div className="flex justify-between items-center">
                                    <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Pos X %</label>
                                    <span className="text-[9px] text-white">{selectedText.style.x}%</span>
                                </div>
                                <input 
                                    type="range" min="0" max="100"
                                    value={selectedText.style.x}
                                    onChange={(e) => onUpdateText(selectedText.id, { style: { x: parseInt(e.target.value) } })}
                                    className="w-full"
                                />
                            </div>
                            <div className="space-y-1.5">
                                <div className="flex justify-between items-center">
                                    <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Pos Y %</label>
                                    <span className="text-[9px] text-white">{selectedText.style.y}%</span>
                                </div>
                                <input 
                                    type="range" min="0" max="100"
                                    value={selectedText.style.y}
                                    onChange={(e) => onUpdateText(selectedText.id, { style: { y: parseInt(e.target.value) } })}
                                    className="w-full"
                                />
                            </div>
                        </div>
                    </div>
                </Section>
            )}

            <Section icon={Maximize} title="Spatial">
                {[
                    { label: 'Scale', prop: 'scale', min: 0.1, max: 2, step: 0.01 },
                    { label: 'Rotate', prop: 'rotation', min: -180, max: 180, step: 1 },
                    { label: 'Opac', prop: 'opacity', min: 0, max: 100, step: 1 },
                    { label: 'X_Pos', prop: 'positionX', min: -500, max: 500, step: 1 },
                ].map(item => {
                    const value = state.transform[item.prop as keyof VideoTransform] as number;
                    return (
                        <div key={item.prop} className="space-y-1.5">
                            <div className="flex justify-between items-center">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">{item.label}</label>
                                <div className="flex items-center gap-2">
                                    <span className="text-[9px] font-mono text-white">
                                        {typeof value === 'number' ? value.toFixed(2) : value}
                                    </span>
                                    <KeyframeButton prop={item.prop} />
                                </div>
                            </div>
                            <input 
                                type="range" 
                                min={item.min} 
                                max={item.max} 
                                step={item.step}
                                value={value}
                                onChange={(e) => onUpdateTransformProperty(item.prop as keyof VideoTransform, parseFloat(e.target.value))}
                                className="w-full"
                            />
                        </div>
                    );
                })}
            </Section>

            <Section icon={Palette} title="Correction">
                <div className="space-y-4">
                    <div className="flex justify-between items-center">
                        <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Intensity</label>
