import React, { useState, useEffect } from 'react';
import { useVideoEditor } from './hooks/useVideoEditor';
import { useAIController } from './hooks/useAIController';
import VideoPlayer from './components/VideoPlayer';
import Timeline from './components/Timeline';
import AIChat from './components/AIChat';
import EditorSidebar from './components/EditorSidebar';
import PropertiesPanel from './components/PropertiesPanel';
import Header from './components/Header';
import { RightPanelTab, SubtitleBlock, EffectBlock, EffectType } from './types';
import { Settings2, MessageSquare } from 'lucide-react';

const App: React.FC = () => {
  const { 
    state, 
    setState, 
    handleTimeUpdate, 
    togglePlay, 
    handleSplit, 
    handleTrim, 
    handleDelete, 
    handleAddText, 
    handleUpdateTextProperty,
    handleUpdateClipProperty,
    handleUpdateAudioProperty,
    handleSelectClip,
    handleAddAudio,
    handleToggleKeyframe,
    handleUpdateTransform
  } = useVideoEditor();

  const { messages, isProcessing, handleSendMessage } = useAIController(state, setState);
  const [rightPanel, setRightPanel] = useState<RightPanelTab>('chat');

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (e.key.toLowerCase() === 'b') handleSplit();
      if (e.key === 'Delete' || e.key === 'Backspace') handleDelete();
      if (e.key === ' ') {
        e.preventDefault();
        togglePlay();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleSplit, handleDelete, togglePlay]);

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-black text-slate-400 selection:bg-white/20">
      <EditorSidebar 
        state={state}
        onSetMode={(mode) => setState(prev => ({ ...prev, activeMode: mode, selectedTextId: undefined, selectedClipId: undefined }))}
        onAddText={handleAddText} 
        onAddAudio={handleAddAudio}
        onUpdateAudio={handleUpdateAudioProperty}
        onSetFilter={(f) => setState(prev => ({ ...prev, activeFilter: f }))}
        onAddSubtitle={() => {
            const newSub: SubtitleBlock = {
                id: Math.random().toString(36),
                text: "NEURAL CAPTION GENERATED",
                startTime: state.currentTime,
                duration: 3
            };
            setState(prev => ({ ...prev, subtitleTrack: [...prev.subtitleTrack, newSub] }));
        }}
        onAddClip={() => {}}
        onAddEffect={(type) => {
            const newFx: EffectBlock = {
                id: Math.random().toString(36),
                type: type as EffectType,
                startTime: state.currentTime,
                duration: 5,
                intensity: 50
            };
            setState(prev => ({ ...prev, effectTrack: [...prev.effectTrack, newFx] }));
        }}
      />

      <div className="flex-1 flex flex-col min-w-0 relative" onClick={() => setState(prev => ({ ...prev, selectedTextId: undefined, selectedClipId: undefined }))}>
        <Header simulationMode={'native'} onSetSimulationMode={() => {}} />

        <div className="flex-1 flex justify-center items-center bg-[#050505] overflow-hidden relative">
          <VideoPlayer 
            state={state} 
            onTimeUpdate={handleTimeUpdate} 
            onDurationChange={(d) => setState(prev => ({...prev, duration: d}))} 
            onTogglePlay={togglePlay}
            onSelectText={(id) => {
                setState(prev => ({ ...prev, selectedTextId: id, selectedClipId: undefined }));
                setRightPanel('properties');
            }}
          />
        </div>

        <div className="h-64 border-t border-[#1a1a1a] bg-black z-20" onClick={(e) => e.stopPropagation()}>
          <Timeline 
            state={state} 
            onSeek={handleTimeUpdate} 
            onSplit={handleSplit} 
            onDelete={handleDelete} 
            onTrim={handleTrim} 
            onSelectClip={(id) => {
                handleSelectClip(id);
                setRightPanel('properties');
            }}
            onUpdateClipFade={(id, updates) => handleUpdateClipProperty(id, updates)}
          />
        </div>
      </div>

      <div className="w-80 border-l border-[#1a1a1a] bg-black flex flex-col z-30" onClick={(e) => e.stopPropagation()}>
         <div className="flex border-b border-[#1a1a1a]">
           <button onClick={() => setRightPanel('properties')} className={`flex-1 py-4 text-[9px] font-black tracking-[0.2em] flex items-center justify-center gap-2 transition-all ${rightPanel === 'properties' ? 'text-white border-b border-white bg-[#0a0a0a]' : 'text-slate-600 hover:bg-[#0a0a0a]'}`}><Settings2 className="w-4 h-4" /> INSPECTOR</button>
           <button onClick={() => setRightPanel('chat')} className={`flex-1 py-4 text-[9px] font-black tracking-[0.2em] flex items-center justify-center gap-2 transition-all ${rightPanel === 'chat' ? 'text-white border-b border-white bg-[#0a0a0a]' : 'text-slate-600 hover:bg-[#0a0a0a]'}`}><MessageSquare className="w-4 h-4" /> NEURAL_LINK</button>
         </div>
         <div className="flex-1 overflow-hidden">
           {rightPanel === 'chat' ? (
            <AIChat messages={messages} onSendMessage={handleSendMessage} isProcessing={isProcessing} />
           ) : (
            <PropertiesPanel 
              state={state}
              onChangeTransform={(t) => setState(prev => ({...prev, transform: t}))}
              onUpdateTransformProperty={handleUpdateTransform}
              onChangeAdjustment={(a) => setState(prev => ({...prev, adjustment: a}))}
              onToggleKeyframe={handleToggleKeyframe}
              onChangeChromaKey={(c) => setState(prev => ({...prev, chromaKey: c}))}
              onUpdateText={handleUpdateTextProperty}
              onUpdateClip={handleUpdateClipProperty}
            />
           )}
         </div>
      </div>
    </div>
  );
};

export default App;

