import React, { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { createGeminiSession } from '../services/geminiService';
import { ChatMessage, ToolNames, ToolArgs, VideoState, SubtitleBlock, FilterPreset, AudioBlock, VideoClip, DirectorialLogEntry } from '../types';
import { Chat } from '@google/genai';
import { INITIAL_CHAT_MESSAGE } from '../constants';

export const useAIController = (videoState: VideoState, setVideoState: React.Dispatch<React.SetStateAction<VideoState>>) => {
  const [messages, setMessages] = useState<ChatMessage[]>([{ id: 'init', role: 'model', content: INITIAL_CHAT_MESSAGE }]);
  const [isProcessing, setIsProcessing] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);

  useEffect(() => {
    chatSessionRef.current = createGeminiSession();
  }, []);

  const addLog = useCallback((action: string, type: 'ai' | 'user' = 'ai') => {
    const entry: DirectorialLogEntry = {
        id: Math.random().toString(36),
        timestamp: Date.now(),
        action,
        type
    };
    setVideoState(prev => ({ ...prev, directorialLog: [entry, ...prev.directorialLog].slice(0, 10) }));
  }, [setVideoState]);

  const handleSendMessage = useCallback(async (userMessage: string) => {
    if (!chatSessionRef.current) return;
    setIsProcessing(true);
    setMessages(prev => [...prev, { id: Date.now().toString(), role: 'user', content: userMessage }]);
    addLog(userMessage, 'user');

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMessage });
      const functionCalls = result.functionCalls;

      if (functionCalls && functionCalls.length > 0) {
        const responses: any[] = [];
        for (const call of functionCalls) {
          const toolName = call.name;
          const args = call.args as ToolArgs;
          let responseResult = { result: "Operation Successful" };

          setVideoState(prev => ({ ...prev, isAnalyzing: true }));

          switch (toolName) {
            case ToolNames.GENERATE_IMAGE:
              setVideoState(prev => ({ ...prev, isGenerating: true, generationProgress: 30 }));
              const imgResponse = await ai.models.generateContent({
                model: 'gemini-2.5-flash-image',
                contents: { parts: [{ text: args.prompt }] },
                config: { imageConfig: { aspectRatio: args.aspectRatio || "16:9" } }
              });

              const imgPart = imgResponse.candidates[0].content.parts.find(p => p.inlineData);
              if (imgPart) {
                const newClip: VideoClip = {
                  id: Math.random().toString(36),
                  url: `data:image/png;base64,${imgPart.inlineData.data}`,
                  thumbnail: `data:image/png;base64,${imgPart.inlineData.data}`,
                  startTime: videoState.duration,
                  duration: 5,
                  name: `AI_Synth_Frame_${Math.floor(Math.random()*1000)}`
                };
                setVideoState(prev => ({ 
                  ...prev, 
                  videoClips: [...prev.videoClips, newClip],
                  duration: prev.duration + 5,
                  isGenerating: false 
                }));
                addLog(`Injected AI Frame: ${args.prompt}`);
              }
              break;

            case ToolNames.GENERATE_VIDEO:
              // Veo requires API key selection
              // @ts-ignore
              if (!await window.aistudio.hasSelectedApiKey()) {
                // @ts-ignore
                await window.aistudio.openSelectKey();
              }
              setVideoState(prev => ({ ...prev, isGenerating: true, generationProgress: 10 }));

              let operation = await ai.models.generateVideos({
                model: 'veo-3.1-fast-generate-preview',
                prompt: args.prompt,
                config: { numberOfVideos: 1, resolution: '720p', aspectRatio: '16:9' }
              });

              while (!operation.done) {
                await new Promise(r => setTimeout(r, 5000));
                setVideoState(prev => ({ ...prev, generationProgress: Math.min(prev.generationProgress + 5, 95) }));
                operation = await ai.operations.getVideosOperation({ operation: operation });
              }

              const vidUri = operation.response?.generatedVideos?.[0]?.video?.uri;
              if (vidUri) {
                const fetchRes = await fetch(`${vidUri}&key=${process.env.API_KEY}`);
                const blob = await fetchRes.blob();
                const localUrl = URL.createObjectURL(blob);
                const newVidClip: VideoClip = {
                  id: Math.random().toString(36),
                  url: localUrl,
                  thumbnail: 'https://images.unsplash.com/photo-1485846234645-a62644f84728?w=100',
                  startTime: videoState.duration,
                  duration: 5,
                  name: `VEO_Scene_${Math.floor(Math.random()*1000)}`
                };
                setVideoState(prev => ({ 
                  ...prev, 
                  videoClips: [...prev.videoClips, newVidClip],
                  duration: prev.duration + 5,
                  isGenerating: false 
                }));
                addLog(`Injected VEO Sequence: ${args.prompt}`);
              }
              break;

            case ToolNames.ADD_SUBTITLE:
              const newSub: SubtitleBlock = {
                id: Math.random().toString(36),
                text: args.text,
                startTime: args.startTime ?? videoState.currentTime,
                duration: args.duration ?? 3
              };
              setVideoState(prev => ({ ...prev, subtitleTrack: [...prev.subtitleTrack, newSub] }));
              break;

            case ToolNames.SET_FILTER:
              setVideoState(prev => ({ ...prev, activeFilter: args.filter as FilterPreset }));
              addLog(`Grade shift: ${args.filter}`);
              break;
          }
          responses.push({ name: toolName, response: responseResult, id: call.id });
        }

        const finalResponse = await chatSessionRef.current.sendToolResponse({ functionResponses: responses });
        if (finalResponse.text) setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: finalResponse.text }]);
      } else if (result.text) {
        setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: result.text }]);
      }
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: "Neural sync error. Rebooting fabricator." }]);
    } finally {
      setIsProcessing(false);
      setVideoState(prev => ({ ...prev, isAnalyzing: false, isGenerating: false }));
    }
  }, [setVideoState, videoState.currentTime, videoState.duration, addLog]);

  return { messages, isProcessing, handleSendMessage };
};

import React, { useRef, useEffect, useState, useMemo } from 'react';
import { VideoState, FilterPreset, EffectType, VideoClip } from '../types';
import { Play, Pause, Activity, Zap, Cpu, Target, ShieldCheck, Sparkles, Loader2 } from 'lucide-react';

interface VideoPlayerProps {
  state: VideoState;
  onTimeUpdate: (time: number) => void;
  onDurationChange: (duration: number) => void;
  onTogglePlay: () => void;
  onSelectText: (id: string) => void;
}

const getFilterCSS = (preset: FilterPreset): string => {
    switch (preset) {
        case 'vibrant': return 'saturate(1.5) contrast(1.1)';
        case 'cinema': return 'sepia(0.2) contrast(1.2) brightness(0.9) saturate(0.8)';
        case 'vintage': return 'sepia(0.5) contrast(0.8) brightness(1.1)';
        case 'bw': return 'grayscale(1)';
        case 'cyber': return 'hue-rotate(180deg) saturate(2) brightness(1.2) contrast(1.1)';
        case 'horror': return 'grayscale(0.5) contrast(1.5) brightness(0.7) hue-rotate(-20deg)';
        case 'gold': return 'sepia(1) saturate(2) brightness(1.1) contrast(1.1)';
        case 'neon': return 'saturate(3) contrast(1.3) hue-rotate(-10deg) brightness(1.1)';
        default: return 'none';
    }
};

const VideoPlayer: React.FC<VideoPlayerProps> = ({ state, onTimeUpdate, onDurationChange, onTogglePlay, onSelectText }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [randomVal, setRandomVal] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => setRandomVal(Math.floor(Math.random() * 9999)), 200);
    return () => clearInterval(interval);
  }, []);

  const activeClip = useMemo(() => {
    return state.videoClips.find(c => state.currentTime >= c.startTime && state.currentTime <= c.startTime + c.duration) || state.videoClips[0];
  }, [state.videoClips, state.currentTime]);

  useEffect(() => {
    if (videoRef.current) {
      if (state.isPlaying && videoRef.current.paused) {
        videoRef.current.play().catch(() => {});
      } else if (!state.isPlaying && !videoRef.current.paused) {
        videoRef.current.pause();
      }
    }
  }, [state.isPlaying]);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.volume = state.volume;
      videoRef.current.playbackRate = state.playbackSpeed;
    }
  }, [state.volume, state.playbackSpeed]);

  useEffect(() => {
    if (videoRef.current && Math.abs(videoRef.current.currentTime - state.currentTime) > 0.5) {
      videoRef.current.currentTime = state.currentTime;
    }
  }, [state.currentTime]);

  const activeSub = state.subtitleTrack.find(s => state.currentTime >= s.startTime && state.currentTime <= s.startTime + s.duration);
  const activeTextOverlays = state.textTrack.filter(t => state.currentTime >= t.startTime && state.currentTime <= t.startTime + t.duration);
  const activeEffects = state.effectTrack.filter(e => state.currentTime >= e.startTime && state.currentTime <= e.startTime + e.duration);

  const transitionOpacity = useMemo(() => {
    if (!activeClip) return 1;
    const { startTime, duration, fadeInDuration = 0, fadeOutDuration = 0 } = activeClip;
    const clipTime = state.currentTime - startTime;

    if (clipTime < fadeInDuration) {
      return Math.max(0, clipTime / fadeInDuration);
    }
    if (clipTime > duration - fadeOutDuration) {
      return Math.max(0, (duration - clipTime) / fadeOutDuration);
    }
    return 1;
  }, [activeClip, state.currentTime]);

  const baseFilter = `
    brightness(${state.adjustment.brightness}%)
    contrast(${state.adjustment.contrast}%)
    saturate(${state.adjustment.saturation}%)
    blur(${state.adjustment.blur}px)
    hue-rotate(${state.adjustment.hue}deg)
    ${getFilterCSS(state.activeFilter)}
  `;

  return (
    <div className="relative w-full h-full flex flex-col items-center justify-center p-4">
      {/* HUD HEADER */}
      <div className="w-full flex justify-between px-4 py-2 mb-2 font-mono text-[7px] text-slate-500 uppercase tracking-[0.4em]">
          <div className="flex items-center gap-4">
              <span className="flex items-center gap-1"><Cpu className="w-2.5 h-2.5" /> Core_Sentry_Active</span>
              <span className="text-white">ID_{randomVal}</span>
          </div>
          <div className="flex items-center gap-4">
              <span>Bitrate: 48.2MB/S</span>
              <span className="flex items-center gap-1 text-green-500/50"><ShieldCheck className="w-2.5 h-2.5" /> Neural_Encrypted</span>
          </div>
      </div>

      <div className={`relative overflow-hidden bg-black aspect-video max-h-[75vh] w-full transition-all duration-700 shadow-[0_0_50px_rgba(0,0,0,1)] border ${state.isAnalyzing || state.isGenerating ? 'border-blue-500/50 active-glow' : 'border-[#1a1a1a]'}`}>

         {/* Generation Overlay */}
         {state.isGenerating && (
             <div className="absolute inset-0 z-[60] bg-black/80 flex flex-col items-center justify-center backdrop-blur-md">
                 <div className="relative mb-6">
                    <Sparkles className="w-12 h-12 text-blue-500 animate-pulse" />
                    <Loader2 className="w-12 h-12 text-blue-400 absolute inset-0 animate-spin opacity-40" />
                 </div>
                 <h2 className="text-[10px] font-black text-white tracking-[0.5em] uppercase mb-2">Neural Fabrication in Progress</h2>
                 <div className="w-64 h-1 bg-white/5 rounded-full overflow-hidden mb-4">
                     <div 
                        className="h-full bg-blue-500 transition-all duration-1000 ease-out" 
                        style={{ width: `${state.generationProgress}%` }}
                     />
                 </div>
                 <p className="text-[8px] font-mono text-slate-500 tracking-widest uppercase">Syncing Reality Layer_{state.generationProgress}%</p>
             </div>
         )}

         {/* Diagnostic Overlay */}
         <div className="absolute inset-0 z-50 pointer-events-none border border-white/5">
             <div className="absolute top-1/2 left-0 w-full h-[1px] bg-white/5"></div>
             <div className="absolute top-0 left-1/2 w-[1px] h-full bg-white/5"></div>
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2">
                 <Target className="w-12 h-12 text-white/5 stroke-[0.5]" />
             </div>
         </div>

         {/* AI HUD Scanline */}
         {state.isAnalyzing && !state.isGenerating && (
            <div className="absolute inset-0 z-50 pointer-events-none bg-white/5">
                <div className="absolute top-0 left-0 w-full h-[1px] bg-white/40 animate-[scan_1.5s_linear_infinite]"></div>
                <div className="absolute bottom-12 left-4 flex items-center gap-2">
                    <Activity className="w-3 h-3 text-white animate-pulse" />
                    <span className="text-[8px] font-mono text-white uppercase tracking-widest">Neural Link Processing...</span>
                </div>
            </div>
         )}

         {/* Cinematic VFX Overlays */}
         <div className="absolute inset-0 z-30 pointer-events-none overflow-hidden">
             {activeEffects.map(fx => (
                 <div key={fx.id} className="absolute inset-0">
                     {fx.type === 'vhs' && (
                         <div className="absolute inset-0 opacity-40 mix-blend-screen animate-pulse bg-[url('https://media.giphy.com/media/oEI9uWUPr9m80/giphy.gif')] bg-cover"></div>
                     )}
                     {fx.type === 'glitch' && (
                         <div className="absolute inset-0 opacity-30 animate-[glitch_0.2s_steps(2)_infinite] bg-cyan-500/10 shadow-[5px_0_red,-5px_0_blue]"></div>
                     )}
                     {fx.type === 'scanline' && (
                         <div className="absolute inset-0 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_2px,3px_100%]"></div>
                     )}
                     {fx.type === 'data_stream' && (
                         <div className="absolute inset-0 opacity-20 flex flex-col font-mono text-[8px] text-green-500 overflow-hidden leading-tight animate-[stream_20s_linear_infinite]">
                             {Array.from({length: 40}).map((_, i) => (
                                 <div key={i} className="whitespace-nowrap opacity-40">
                                     {Array.from({length: 10}).map(() => Math.random().toString(36).substring(7)).join(' ')}
                                 </div>
                             ))}
                         </div>
                     )}
                 </div>
             ))}
         </div>

         <video
            ref={videoRef}
            key={activeClip?.url}
            className={`w-full h-full object-contain transition-all duration-500 ${activeEffects.some(e => e.type === 'glitch') ? 'animate-[glitch_0.1s_infinite]' : ''}`}
            style={{ 
                filter: baseFilter,
                transform: `scale(${state.transform.scale}) translate(${state.transform.positionX}px, ${state.transform.positionY}px) rotate(${state.transform.rotation}deg)`,
                opacity: (state.transform.opacity / 100) * transitionOpacity
            }}
            src={activeClip?.url}
            loop
            playsInline
            onTimeUpdate={(e) => onTimeUpdate(e.currentTarget.currentTime)}
            onLoadedMetadata={(e) => onDurationChange(e.currentTarget.duration)}
         />

         <div className="absolute inset-0 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity bg-black/10 cursor-pointer z-10" onClick={onTogglePlay}>
            <div className="p-4 bg-white/5 backdrop-blur-xl rounded-full border border-white/20 shadow-2xl">
                {state.isPlaying ? <Pause className="w-8 h-8 text-white" /> : <Play className="w-8 h-8 text-white ml-1" />}
            </div>
         </div>
      </div>

      <style>{`
        @keyframes scan {
          0% { top: 0%; }
          100% { top: 100%; }
        }
        @keyframes glitch {
          0% { transform: translate(0); }
          20% { transform: translate(-2px, 2px); }
          40% { transform: translate(-2px, -2px); }
          60% { transform: translate(2px, 2px); }
          80% { transform: translate(2px, -2px); }
          100% { transform: translate(0); }
        }
        @keyframes stream {
            0% { transform: translateY(0); }
            100% { transform: translateY(-50%); }
        }
      `}</style>
    </div>
  );
};

