                            <button className="mt-2 w-full flex items-center justify-between p-2 bg-[#0a0a0a] border border-[#1a1a1a] rounded hover:border-purple-500/50 transition-all">
                                <span className="text-[8px] font-bold text-white uppercase">Enhance Voice AI</span>
