                            </button>
                        </div>
                        {/* Mixer remains below */}
                        <div className="space-y-4 pt-4 border-t border-[#1a1a1a]">
                            <p className="text-[8px] font-mono text-slate-600 uppercase mb-2 flex items-center gap-2"><Activity className="w-2.5 h-2.5" /> Neural_Mixer</p>
                            {state.audioTrack.map(track => (
                                <div key={track.id} className="p-2 border border-[#1a1a1a] rounded">
                                    <span className="text-[8px] uppercase font-bold text-slate-500">{track.name}</span>
                                    <input 
                                        type="range" min="0" max="1" step="0.01" 
                                        value={track.volume} 
                                        onChange={(e) => onUpdateAudio(track.id, { volume: parseFloat(e.target.value) })}
