                id: Math.random().toString(36),
                text: "NEURAL CAPTION GENERATED",
                startTime: state.currentTime,
                duration: 3
            };
            setState(prev => ({ ...prev, subtitleTrack: [...prev.subtitleTrack, newSub] }));
        }}
        onAddClip={() => {}}
        onAddEffect={(type) => {
            const newFx: EffectBlock = {
                id: Math.random().toString(36),
                type: type as EffectType,
                startTime: state.currentTime,
                duration: 5,
                intensity: 50
            };
            setState(prev => ({ ...prev, effectTrack: [...prev.effectTrack, newFx] }));
        }}
        onFabricate={(prompt, type) => {
            const command = type === 'video' ? `Synthesize a cinematic video scene: ${prompt}` : `Fabricate a high-fidelity image: ${prompt}`;
            handleSendMessage(command);
        }}
