import React, { useState, useRef, useEffect } from 'react';
import { VideoState, Keyframe } from '../types';
import { Scissors, Trash2, Magnet, ZoomIn, ZoomOut, Type, Music, FolderOpen, Zap, Diamond, Subtitles, Sparkles } from 'lucide-react';

interface TimelineProps {
  state: VideoState;
  onSeek: (time: number) => void;
  onSplit: () => void;
  onDelete: () => void;
  onTrim: (trackName: keyof VideoState, id: string, startTime: number, duration: number) => void;
  onSelectClip?: (id: string) => void;
  onUpdateClipFade?: (id: string, updates: { fadeInDuration?: number, fadeOutDuration?: number }) => void;
}

const Timeline: React.FC<TimelineProps> = ({ state, onSeek, onSplit, onDelete, onTrim, onSelectClip, onUpdateClipFade }) => {
  const percentage = (state.currentTime / state.duration) * 100;
  const timelineRef = useRef<HTMLDivElement>(null);

  const [dragState, setDragState] = useState<{
    trackName: keyof VideoState;
    id: string;
    type: 'trim' | 'fade-in' | 'fade-out';
    edge?: 'start' | 'end';
    initialMouseX: number;
    initialStartTime: number;
    initialDuration: number;
    initialFadeIn?: number;
    initialFadeOut?: number;
  } | null>(null);

  const handleTimelineClick = (e: React.MouseEvent<HTMLDivElement>) => {
    if ((e.target as HTMLElement).closest('.timeline-item-handle')) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const clickPercentage = x / rect.width;
    const newTime = Math.max(0, Math.min(state.duration, clickPercentage * state.duration));
    onSeek(newTime);
  };

  const onStartTrim = (e: React.MouseEvent, trackName: keyof VideoState, id: string, edge: 'start' | 'end', startTime: number, duration: number) => {
    e.stopPropagation();
    setDragState({ trackName, id, type: 'trim', edge, initialMouseX: e.clientX, initialStartTime: startTime, initialDuration: duration });
  };

  const onStartFadeDrag = (e: React.MouseEvent, id: string, type: 'fade-in' | 'fade-out', initialFade: number) => {
    e.stopPropagation();
    const clip = state.videoClips.find(c => c.id === id);
    if (!clip) return;
    setDragState({ trackName: 'videoClips', id, type, initialMouseX: e.clientX, initialStartTime: clip.startTime, initialDuration: clip.duration, initialFadeIn: clip.fadeInDuration, initialFadeOut: clip.fadeOutDuration });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragState || !timelineRef.current) return;
      const timelineWidth = timelineRef.current.getBoundingClientRect().width;
      const dx = ((e.clientX - dragState.initialMouseX) / timelineWidth) * state.duration;

      if (dragState.type === 'trim') {
        let newStartTime = dragState.initialStartTime;
        let newDuration = dragState.initialDuration;
        if (dragState.edge === 'start') {
          newStartTime = Math.max(0, dragState.initialStartTime + dx);
          newDuration = Math.max(0.1, dragState.initialDuration - (newStartTime - dragState.initialStartTime));
        } else {
          newDuration = Math.max(0.1, dragState.initialDuration + dx);
        }
        onTrim(dragState.trackName, dragState.id, newStartTime, newDuration);
      } else if (dragState.type === 'fade-in' && onUpdateClipFade) {
        const newFade = Math.max(0, Math.min(dragState.initialDuration / 2, (dragState.initialFadeIn || 0) + dx));
        onUpdateClipFade(dragState.id, { fadeInDuration: newFade });
      } else if (dragState.type === 'fade-out' && onUpdateClipFade) {
        const newFade = Math.max(0, Math.min(dragState.initialDuration / 2, (dragState.initialFadeOut || 0) - dx));
        onUpdateClipFade(dragState.id, { fadeOutDuration: newFade });
      }
    };
    const handleMouseUp = () => setDragState(null);
    if (dragState) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragState, state.duration, onTrim, onUpdateClipFade]);

  const TrackHeader = ({ icon: Icon, label }: { icon: any, label: string }) => (
    <div className="absolute left-2 top-1/2 -translate-y-1/2 flex items-center gap-1.5 z-10 pointer-events-none opacity-40 bg-black/80 px-1.5 py-0.5 rounded border border-[#1a1a1a]">
      <Icon className="w-2.5 h-2.5 text-slate-400" />
      <span className="text-[7px] font-mono text-slate-400 tracking-tighter uppercase">{label}</span>
    </div>
  );

  const renderClip = (item: any, trackName: keyof VideoState, className: string, children?: React.ReactNode) => {
    const left = (item.startTime / state.duration) * 100;
    const width = (item.duration / state.duration) * 100;
    const isClipSelected = (trackName === 'videoClips' && state.selectedClipId === item.id) || (trackName === 'textTrack' && state.selectedTextId === item.id);
    const isHoveredActive = state.currentTime >= item.startTime && state.currentTime <= item.startTime + item.duration;

    return (
      <div 
        key={item.id}
        onClick={(e) => { e.stopPropagation(); trackName === 'videoClips' && onSelectClip?.(item.id); }}
        className={`absolute top-1 bottom-1 rounded border overflow-hidden cursor-pointer group transition-all bg-[#121212] border-[#222] ${isClipSelected ? 'ring-2 ring-blue-500 z-30 bg-[#1a1a1a]' : isHoveredActive ? 'bg-[#1a1a1a] border-white/20' : 'hover:bg-[#151515]'} ${className}`}
        style={{ left: `${left}%`, width: `${width}%` }}
      >
        <div className="trim-handle timeline-item-handle absolute left-0 top-0 bottom-0 w-1 bg-white/10 hover:bg-white/30 cursor-ew-resize opacity-0 group-hover:opacity-100 transition-opacity z-10" onMouseDown={(e) => onStartTrim(e, trackName, item.id, 'start', item.startTime, item.duration)} />
        {trackName === 'videoClips' && (
          <>
            <div className="timeline-item-handle absolute left-0 top-0 w-3 h-3 bg-white/10 hover:bg-white/40 cursor-ew-resize z-20 rounded-br-full border-b border-r border-white/20" onMouseDown={(e) => onStartFadeDrag(e, item.id, 'fade-in', item.fadeInDuration || 0)} />
            <div className="timeline-item-handle absolute right-0 top-0 w-3 h-3 bg-white/10 hover:bg-white/40 cursor-ew-resize z-20 rounded-bl-full border-b border-l border-white/20" onMouseDown={(e) => onStartFadeDrag(e, item.id, 'fade-out', item.fadeOutDuration || 0)} />
            {item.isEnhanced && <div className="absolute top-1 right-1 z-20"><Sparkles className="w-2.5 h-2.5 text-cyan-400 animate-pulse" /></div>}
          </>
        )}
        <div className="flex items-center h-full px-2 overflow-hidden pointer-events-none">{children}</div>
        <div className="trim-handle timeline-item-handle absolute right-0 top-0 bottom-0 w-1 bg-white/10 hover:bg-white/30 cursor-ew-resize opacity-0 group-hover:opacity-100 transition-opacity z-10" onMouseDown={(e) => onStartTrim(e, trackName, item.id, 'end', item.startTime, item.duration)} />
      </div>
    );
  };

  return (
    <div className="w-full h-full flex flex-col bg-black border-t border-[#1a1a1a] select-none">
      <div className="h-10 border-b border-[#1a1a1a] bg-black flex items-center justify-between px-4">
         <div className="flex items-center gap-1">
            <button onClick={onSplit} className="p-2 hover:bg-[#0a0a0a] rounded text-slate-500 hover:text-white transition-all flex items-center gap-2 px-3 border border-transparent hover:border-[#1a1a1a]"><Scissors className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Split</span></button>
            <button onClick={onDelete} className="p-2 hover:bg-[#0a0a0a] rounded text-slate-500 hover:text-red-500 transition-all flex items-center gap-2 px-3 border border-transparent hover:border-[#1a1a1a]"><Trash2 className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Delete</span></button>
         </div>
         <div className="flex items-center gap-4">
            <div className="text-[9px] font-mono text-white bg-[#0a0a0a] px-2 py-0.5 rounded border border-[#1a1a1a] tracking-widest">
                {new Date(state.currentTime * 1000).toISOString().substr(14, 9)} / {new Date(state.duration * 1000).toISOString().substr(14, 5)}
            </div>
         </div>
      </div>
      <div className="flex-1 overflow-y-auto custom-scrollbar relative bg-[#050505]">
        <div className="relative min-h-[400px] p-2" ref={timelineRef} onClick={handleTimelineClick}>
            <div className="absolute top-0 bottom-0 w-[1px] bg-white z-50 pointer-events-none" style={{ left: `${percentage}%` }}><div className="absolute -top-1 -left-[3px] w-1.5 h-4 bg-white rounded-sm shadow-[0_0_10px_white]"></div></div>
            <div className="mb-1 relative h-6 w-full bg-black rounded-sm border border-[#1a1a1a]">
                 <TrackHeader icon={Zap} label="Keys" />
                 {Object.entries(state.transform.keyframes).map(([prop, keys]) => (keys as Keyframe[]).map(k => <div key={k.id} className="absolute top-1/2 -translate-y-1/2 w-1.5 h-1.5 bg-blue-500 rotate-45 z-40 border border-white/50" style={{ left: `${(k.time / state.duration) * 100}%` }} />))}
            </div>
            <div className="mb-1 relative h-12 w-full bg-black rounded-sm border border-[#1a1a1a]">
                 <TrackHeader icon={FolderOpen} label="Media" />
                 {state.videoClips.map(clip => renderClip(clip, 'videoClips', 'border-l-blue-500 border-l-2', 
                    <div className="flex items-center gap-2 w-full h-full">
                        <img src={clip.thumbnail} className="h-full w-10 object-cover rounded-sm opacity-50" />
                        <span className="truncate text-[7px] font-bold uppercase tracking-wider text-slate-400">{clip.name}</span>
                    </div>
                 ))}
            </div>
            <div className="mb-1 relative h-10 w-full bg-black rounded-sm border border-[#1a1a1a]">
                 <TrackHeader icon={Sparkles} label="VFX" />
                 {state.effectTrack.map(fx => renderClip(fx, 'effectTrack', 'border-l-orange-500 border-l-2 bg-orange-500/5', <span className="truncate text-[7px] uppercase tracking-widest text-orange-400 font-bold">{fx.type}</span>))}
            </div>
        </div>
      </div>
    </div>
  );
};

