interface VideoPlayerProps {
  state: VideoState;
  onTimeUpdate: (time: number) => void;
  onDurationChange: (duration: number) => void;
  onTogglePlay: () => void;
  onSelectText: (id: string) => void;
}

const getFilterCSS = (preset: FilterPreset): string => {
    switch (preset) {
        case 'vibrant': return 'saturate(1.5) contrast(1.1)';
        case 'cinema': return 'sepia(0.2) contrast(1.2) brightness(0.9) saturate(0.8)';
        case 'vintage': return 'sepia(0.5) contrast(0.8) brightness(1.1)';
        case 'bw': return 'grayscale(1)';
        case 'cyber': return 'hue-rotate(180deg) saturate(2) brightness(1.2) contrast(1.1)';
        case 'horror': return 'grayscale(0.5) contrast(1.5) brightness(0.7) hue-rotate(-20deg)';
        case 'gold': return 'sepia(1) saturate(2) brightness(1.1) contrast(1.1)';
        case 'neon': return 'saturate(3) contrast(1.3) hue-rotate(-10deg) brightness(1.1)';
        default: return 'none';
    }
};

const hexToRgb = (hex: string) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result ? {
        r: parseInt(result[1], 16),
        g: parseInt(result[2], 16),
        b: parseInt(result[3], 16)
    } : { r: 0, g: 255, b: 0 };
};

const VideoPlayer: React.FC<VideoPlayerProps> = ({ state, onTimeUpdate, onDurationChange, onTogglePlay, onSelectText }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [randomVal, setRandomVal] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => setRandomVal(Math.floor(Math.random() * 9999)), 200);
    return () => clearInterval(interval);
  }, []);

  const activeClip = useMemo(() => {
    return state.videoClips.find(c => state.currentTime >= c.startTime && state.currentTime <= c.startTime + c.duration) || state.videoClips[0];
  }, [state.videoClips, state.currentTime]);

  const activeTexts = useMemo(() => {
    return state.textTrack.filter(t => state.currentTime >= t.startTime && state.currentTime <= t.startTime + t.duration);
  }, [state.textTrack, state.currentTime]);

  useEffect(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return;

    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    let requestRef: number;

    const processFrame = () => {
        if (video.paused || video.ended) return;

        canvas.width = video.videoWidth || 1280;
        canvas.height = video.videoHeight || 720;

        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        if (state.chromaKey.enabled) {
            const frame = ctx.getImageData(0, 0, canvas.width, canvas.height);
            const l = frame.data.length / 4;
            const target = hexToRgb(state.chromaKey.color);
            const tol = state.chromaKey.intensity * 2.5;
            const feather = state.chromaKey.shadow;

            for (let i = 0; i < l; i++) {
                const r = frame.data[i * 4 + 0];
                const g = frame.data[i * 4 + 1];
                const b = frame.data[i * 4 + 2];
                const dist = Math.sqrt(Math.pow(r - target.r, 2) + Math.pow(g - target.g, 2) + Math.pow(b - target.b, 2));
                if (dist < tol) frame.data[i * 4 + 3] = 0;
                else if (dist < tol + feather) frame.data[i * 4 + 3] = ((dist - tol) / feather) * 255;
            }
            ctx.putImageData(frame, 0, 0);
        }
        requestRef = requestAnimationFrame(processFrame);
    };

    if (!state.isPlaying) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    } else {
        requestRef = requestAnimationFrame(processFrame);
    }
    return () => cancelAnimationFrame(requestRef);
  }, [state.isPlaying, state.chromaKey.enabled, state.chromaKey.color, state.chromaKey.intensity, state.chromaKey.shadow, state.currentTime]);

  useEffect(() => {
    if (videoRef.current) {
      if (state.isPlaying && videoRef.current.paused) videoRef.current.play().catch(() => {});
      else if (!state.isPlaying && !videoRef.current.paused) videoRef.current.pause();
    }
  }, [state.isPlaying]);

  const activeEffects = state.effectTrack.filter(e => state.currentTime >= e.startTime && state.currentTime <= e.startTime + e.duration);

  const transitionOpacity = useMemo(() => {
    if (!activeClip) return 1;
    const { startTime, duration, fadeInDuration = 0, fadeOutDuration = 0 } = activeClip;
    const clipTime = state.currentTime - startTime;
    if (clipTime < fadeInDuration) return Math.max(0, clipTime / fadeInDuration);
    if (clipTime > duration - fadeOutDuration) return Math.max(0, (duration - clipTime) / fadeOutDuration);
    return 1;
  }, [activeClip, state.currentTime]);

  const stabScale = activeClip?.isStabilized ? 1.05 : 1;

  // Layering adjustments: Clip adjustments override global if they differ from defaults
  const effectiveAdjustment: VideoAdjustment = activeClip?.adjustment || state.adjustment;

  const baseFilter = `
    brightness(${effectiveAdjustment.brightness}%)
    contrast(${effectiveAdjustment.contrast}%)
    saturate(${effectiveAdjustment.saturation}%)
    blur(${effectiveAdjustment.blur}px)
    hue-rotate(${effectiveAdjustment.hue}deg)
    ${getFilterCSS(state.activeFilter)}
    ${activeClip?.isEnhanced ? 'contrast(1.1) brightness(1.02) saturate(1.05)' : ''}
  `;

  return (
    <div className="relative w-full h-full flex flex-col items-center justify-center p-4">
      <div className="w-full flex justify-between px-4 py-2 mb-2 font-mono text-[7px] text-slate-500 uppercase tracking-[0.4em]">
          <div className="flex items-center gap-4">
              <span className="flex items-center gap-1"><Cpu className="w-2.5 h-2.5" /> Core_Sentry_Active</span>
              <span className="text-white">ID_{randomVal}</span>
          </div>
          <div className="flex items-center gap-4">
              {activeClip?.isEnhanced && <span className="flex items-center gap-1 text-cyan-400 font-black"><Sparkles className="w-2 h-2" /> NUE_ACTIVE</span>}
              {activeClip?.isStabilized && <span className="flex items-center gap-1 text-emerald-400 font-black"><Shield className="w-2 h-2" /> INERTIAL_DAMPENING_ON</span>}
              <span>Bitrate: 48.2MB/S</span>
              <span className="flex items-center gap-1 text-green-500/50"><ShieldCheck className="w-2.5 h-2.5" /> Neural_Encrypted</span>
          </div>
      </div>

      <div className={`relative overflow-hidden bg-black aspect-video max-h-[75vh] w-full transition-all duration-700 shadow-[0_0_50px_rgba(0,0,0,1)] border ${state.isAnalyzing || state.isGenerating || state.isEnhancing || state.isStabilizing ? 'border-blue-500/50 active-glow' : 'border-[#1a1a1a]'}`}>

         {state.chromaKey.enabled && state.environmentUrl && (
             <div className="absolute inset-0 z-0">
                 <img src={state.environmentUrl} className="w-full h-full object-cover opacity-80" alt="Environment" />
                 <div className="absolute inset-0 bg-black/20 backdrop-blur-[2px]"></div>
             </div>
         )}

         <video ref={videoRef} key={activeClip?.url} className="hidden" src={activeClip?.url} loop playsInline onTimeUpdate={(e) => onTimeUpdate(e.currentTarget.currentTime)} onLoadedMetadata={(e) => onDurationChange(e.currentTarget.duration)} />

         <canvas
            ref={canvasRef}
            className={`relative w-full h-full object-contain transition-all duration-500 z-10 ${activeEffects.some(e => e.type === 'glitch') ? 'animate-[glitch_0.1s_infinite]' : ''}`}
            style={{ 
                filter: baseFilter,
                transform: `scale(${state.transform.scale * stabScale}) translate(${state.transform.positionX}px, ${state.transform.positionY}px) rotate(${state.transform.rotation}deg)`,
                opacity: (state.transform.opacity / 100) * transitionOpacity
            }}
         />

         {/* Text Overlay Layer */}
         <div className="absolute inset-0 z-20 pointer-events-none">
            {activeTexts.map((text) => (
                <div 
                    key={text.id} 
                    className={`absolute pointer-events-auto cursor-pointer transition-opacity duration-300 ${state.selectedTextId === text.id ? 'ring-1 ring-white/50 ring-offset-2 ring-offset-black/50' : ''}`}
                    onClick={(e) => { e.stopPropagation(); onSelectText(text.id); }}
                    style={{
                        left: `${text.style.x}%`,
                        top: `${text.style.y}%`,
                        transform: 'translate(-50%, -50%)',
                        fontFamily: text.style.fontFamily,
                        fontSize: `${text.style.fontSize}px`,
                        color: text.style.color,
                        opacity: text.style.opacity,
                        textShadow: text.style.shadow,
                        fontWeight: text.style.fontWeight || 'normal',
                        textAlign: text.style.textAlign || 'center',
                    }}
                >
                    <div style={{
                        backgroundColor: text.style.backgroundColor || 'transparent',
                        padding: `${text.style.padding || 0}px`,
                        borderRadius: `${text.style.borderRadius || 0}px`,
                        display: 'inline-block',
                        opacity: text.style.backgroundOpacity ?? 1,
                    }}>
                        {text.text}
                    </div>
                </div>
            ))}
         </div>

         {(state.isGenerating || state.isEnhancing || state.isStabilizing) && (
             <div className="absolute inset-0 z-[60] bg-black/80 flex flex-col items-center justify-center backdrop-blur-md">
                 <div className="relative mb-6">
                    {state.isStabilizing ? <Shield className="w-12 h-12 text-emerald-500 animate-pulse" /> : <Sparkles className="w-12 h-12 text-blue-500 animate-pulse" />}
                    <Loader2 className="w-12 h-12 text-blue-400 absolute inset-0 animate-spin opacity-40" />
                 </div>
                 <h2 className="text-[10px] font-black text-white tracking-[0.5em] uppercase mb-2">
                    {state.isStabilizing ? 'Motion Stabilizing Algorithm' : state.isEnhancing ? 'Neural Upscaling Sequence' : 'Neural Fabrication'}
                 </h2>
                 <div className="w-64 h-1 bg-white/5 rounded-full overflow-hidden mb-4">
                     <div className="h-full bg-blue-500 transition-all duration-200" style={{ width: `${state.generationProgress}%` }} />
                 </div>
                 <p className="text-[7px] font-mono text-slate-500 tracking-widest uppercase">Processing Layer_{state.generationProgress}%</p>
             </div>
         )}

         <div className="absolute inset-0 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity bg-black/10 cursor-pointer z-[40]" onClick={onTogglePlay}>
            <div className="p-4 bg-white/5 backdrop-blur-xl rounded-full border border-white/20 shadow-2xl">
                {state.isPlaying ? <Pause className="w-8 h-8 text-white" /> : <Play className="w-8 h-8 text-white ml-1" />}
            </div>
         </div>
      </div>
    </div>
  );
};

