interface VideoPlayerProps {
  state: VideoState;
  onTimeUpdate: (time: number) => void;
  onDurationChange: (duration: number) => void;
  onTogglePlay: () => void;
  onSelectText: (id: string) => void;
}

const getFilterCSS = (preset: FilterPreset): string => {
    switch (preset) {
        case 'vibrant': return 'saturate(1.5) contrast(1.1)';
        case 'cinema': return 'sepia(0.2) contrast(1.2) brightness(0.9) saturate(0.8)';
        case 'vintage': return 'sepia(0.5) contrast(0.8) brightness(1.1)';
        case 'bw': return 'grayscale(1)';
        case 'cyber': return 'hue-rotate(180deg) saturate(2) brightness(1.2) contrast(1.1)';
        case 'horror': return 'grayscale(0.5) contrast(1.5) brightness(0.7) hue-rotate(-20deg)';
        case 'gold': return 'sepia(1) saturate(2) brightness(1.1) contrast(1.1)';
        case 'neon': return 'saturate(3) contrast(1.3) hue-rotate(-10deg) brightness(1.1)';
        default: return 'none';
    }
};

const hexToRgb = (hex: string) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result ? {
        r: parseInt(result[1], 16),
        g: parseInt(result[2], 16),
        b: parseInt(result[3], 16)
    } : { r: 0, g: 255, b: 0 };
};

const VideoPlayer: React.FC<VideoPlayerProps> = ({ state, onTimeUpdate, onDurationChange, onTogglePlay, onSelectText }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [randomVal, setRandomVal] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => setRandomVal(Math.floor(Math.random() * 9999)), 200);
    return () => clearInterval(interval);
  }, []);

  const activeClip = useMemo(() => {
    return state.videoClips.find(c => state.currentTime >= c.startTime && state.currentTime <= c.startTime + c.duration) || state.videoClips[0];
  }, [state.videoClips, state.currentTime]);

  const activeTexts = useMemo(() => {
    return state.textTrack.filter(t => state.currentTime >= t.startTime && state.currentTime <= t.startTime + t.duration);
  }, [state.textTrack, state.currentTime]);

  useEffect(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return;

    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    let requestRef: number;

    const processFrame = () => {
        if (video.paused || video.ended) return;

        canvas.width = video.videoWidth || 1280;
        canvas.height = video.videoHeight || 720;

        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        if (state.chromaKey.enabled) {
            const frame = ctx.getImageData(0, 0, canvas.width, canvas.height);
            const l = frame.data.length / 4;
            const target = hexToRgb(state.chromaKey.color);
            const tol = state.chromaKey.intensity * 2.5;
            const feather = state.chromaKey.shadow;

            for (let i = 0; i < l; i++) {
                const r = frame.data[i * 4 + 0];
                const g = frame.data[i * 4 + 1];
                const b = frame.data[i * 4 + 2];
                const dist = Math.sqrt(Math.pow(r - target.r, 2) + Math.pow(g - target.g, 2) + Math.pow(b - target.b, 2));
                if (dist < tol) frame.data[i * 4 + 3] = 0;
                else if (dist < tol + feather) frame.data[i * 4 + 3] = ((dist - tol) / feather) * 255;
            }
            ctx.putImageData(frame, 0, 0);
        }
        requestRef = requestAnimationFrame(processFrame);
    };

    if (!state.isPlaying) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    } else {
        requestRef = requestAnimationFrame(processFrame);
    }
    return () => cancelAnimationFrame(requestRef);
  }, [state.isPlaying, state.chromaKey.enabled, state.chromaKey.color, state.chromaKey.intensity, state.chromaKey.shadow, state.currentTime]);

  useEffect(() => {
    if (videoRef.current) {
      if (state.isPlaying && videoRef.current.paused) videoRef.current.play().catch(() => {});
      else if (!state.isPlaying && !videoRef.current.paused) videoRef.current.pause();
    }
  }, [state.isPlaying]);

  const activeEffects = state.effectTrack.filter(e => state.currentTime >= e.startTime && state.currentTime <= e.startTime + e.duration);

  const transitionOpacity = useMemo(() => {
    if (!activeClip) return 1;
    const { startTime, duration, fadeInDuration = 0, fadeOutDuration = 0 } = activeClip;
    const clipTime = state.currentTime - startTime;
    if (clipTime < fadeInDuration) return Math.max(0, clipTime / fadeInDuration);
    if (clipTime > duration - fadeOutDuration) return Math.max(0, (duration - clipTime) / fadeOutDuration);
    return 1;
  }, [activeClip, state.currentTime]);

  const stabScale = activeClip?.isStabilized ? 1.05 : 1;

  // Layering adjustments: Clip adjustments override global if they differ from defaults
  const effectiveAdjustment: VideoAdjustment = activeClip?.adjustment || state.adjustment;

  const baseFilter = `
    brightness(${effectiveAdjustment.brightness}%)
    contrast(${effectiveAdjustment.contrast}%)
    saturate(${effectiveAdjustment.saturation}%)
    blur(${effectiveAdjustment.blur}px)
    hue-rotate(${effectiveAdjustment.hue}deg)
    ${getFilterCSS(state.activeFilter)}
    ${activeClip?.isEnhanced ? 'contrast(1.1) brightness(1.02) saturate(1.05)' : ''}
  `;

  const vignetteStyle = useMemo(() => {
    const intensity = effectiveAdjustment.vignetteIntensity / 100;
    const size = effectiveAdjustment.vignetteSize;
    return {
      background: `radial-gradient(circle, transparent ${size}%, rgba(0,0,0,${intensity}) 100%)`,
    };
  }, [effectiveAdjustment.vignetteIntensity, effectiveAdjustment.vignetteSize]);

  return (
    <div className="relative w-full h-full flex flex-col items-center justify-center p-4">
      <div className="w-full flex justify-between px-4 py-2 mb-2 font-mono text-[7px] text-slate-500 uppercase tracking-[0.4em]">
          <div className="flex items-center gap-4">
              <span className="flex items-center gap-1"><Cpu className="w-2.5 h-2.5" /> Core_Sentry_Active</span>
              <span className="text-white">ID_{randomVal}</span>
          </div>
          <div className="flex items-center gap-4">
              {activeClip?.isEnhanced && <span className="flex items-center gap-1 text-cyan-400 font-black"><Sparkles className="w-2 h-2" /> NUE_ACTIVE</span>}
              {activeClip?.isStabilized && <span className="flex items-center gap-1 text-emerald-400 font-black"><Shield className="w-2 h-2" /> INERTIAL_DAMPENING_ON</span>}
              <span>Bitrate: 48.2MB/S</span>
              <span className="flex items-center gap-1 text-green-500/50"><ShieldCheck className="w-2.5 h-2.5" /> Neural_Encrypted</span>
          </div>
      </div>

      <div className={`relative overflow-hidden bg-black aspect-video max-h-[75vh] w-full transition-all duration-700 shadow-[0_0_50px_rgba(0,0,0,1)] border ${state.isAnalyzing || state.isGenerating || state.isEnhancing || state.isStabilizing ? 'border-blue-500/50 active-glow' : 'border-[#1a1a1a]'}`}>

         {state.chromaKey.enabled && state.environmentUrl && (
             <div className="absolute inset-0 z-0">
                 <img src={state.environmentUrl} className="w-full h-full object-cover opacity-80" alt="Environment" />
                 <div className="absolute inset-0 bg-black/20 backdrop-blur-[2px]"></div>
             </div>
         )}

         <video ref={videoRef} key={activeClip?.url} className="hidden" src={activeClip?.url} loop playsInline onTimeUpdate={(e) => onTimeUpdate(e.currentTarget.currentTime)} onLoadedMetadata={(e) => onDurationChange(e.currentTarget.duration)} />

         <canvas
            ref={canvasRef}
            className={`relative w-full h-full object-contain transition-all duration-500 z-10 ${activeEffects.some(e => e.type === 'glitch') ? 'animate-[glitch_0.1s_infinite]' : ''}`}
            style={{ 
                filter: baseFilter,
                transform: `scale(${state.transform.scale * stabScale}) translate(${state.transform.positionX}px, ${state.transform.positionY}px) rotate(${state.transform.rotation}deg)`,
                opacity: (state.transform.opacity / 100) * transitionOpacity
            }}
         />

         {/* Vignette Overlay Layer */}
         <div className="absolute inset-0 z-[15] pointer-events-none transition-all duration-300" style={vignetteStyle}></div>

         {/* Text Overlay Layer */}
         <div className="absolute inset-0 z-20 pointer-events-none">
            {activeTexts.map((text) => (
                <div 
                    key={text.id} 
                    className={`absolute pointer-events-auto cursor-pointer transition-opacity duration-300 ${state.selectedTextId === text.id ? 'ring-1 ring-white/50 ring-offset-2 ring-offset-black/50' : ''}`}
                    onClick={(e) => { e.stopPropagation(); onSelectText(text.id); }}
                    style={{
                        left: `${text.style.x}%`,
                        top: `${text.style.y}%`,
                        transform: 'translate(-50%, -50%)',
                        fontFamily: text.style.fontFamily,
                        fontSize: `${text.style.fontSize}px`,
                        color: text.style.color,
                        opacity: text.style.opacity,
                        textShadow: text.style.shadow,
                        fontWeight: text.style.fontWeight || 'normal',
                        textAlign: text.style.textAlign || 'center',
                    }}
                >
                    <div style={{
                        backgroundColor: text.style.backgroundColor || 'transparent',
                        padding: `${text.style.padding || 0}px`,
                        borderRadius: `${text.style.borderRadius || 0}px`,
                        display: 'inline-block',
                        opacity: text.style.backgroundOpacity ?? 1,
                    }}>
                        {text.text}
                    </div>
                </div>
            ))}
         </div>

         {(state.isGenerating || state.isEnhancing || state.isStabilizing) && (
             <div className="absolute inset-0 z-[60] bg-black/80 flex flex-col items-center justify-center backdrop-blur-md">
                 <div className="relative mb-6">
                    {state.isStabilizing ? <Shield className="w-12 h-12 text-emerald-500 animate-pulse" /> : <Sparkles className="w-12 h-12 text-blue-500 animate-pulse" />}
                    <Loader2 className="w-12 h-12 text-blue-400 absolute inset-0 animate-spin opacity-40" />
                 </div>
                 <h2 className="text-[10px] font-black text-white tracking-[0.5em] uppercase mb-2">
                    {state.isStabilizing ? 'Motion Stabilizing Algorithm' : state.isEnhancing ? 'Neural Upscaling Sequence' : 'Neural Fabrication'}
                 </h2>
                 <div className="w-64 h-1 bg-white/5 rounded-full overflow-hidden mb-4">
                     <div className="h-full bg-blue-500 transition-all duration-200" style={{ width: `${state.generationProgress}%` }} />
                 </div>
                 <p className="text-[7px] font-mono text-slate-500 tracking-widest uppercase">Processing Layer_{state.generationProgress}%</p>
             </div>
         )}

         <div className="absolute inset-0 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity bg-black/10 cursor-pointer z-[40]" onClick={onTogglePlay}>
            <div className="p-4 bg-white/5 backdrop-blur-xl rounded-full border border-white/20 shadow-2xl">
                {state.isPlaying ? <Pause className="w-8 h-8 text-white" /> : <Play className="w-8 h-8 text-white ml-1" />}
            </div>
         </div>
      </div>
    </div>
  );
};

export default VideoPlayer;

import React from 'react';
import { VideoState, VideoTransform, VideoAdjustment, ChromaKey, TextBlock, VideoClip } from '../types';
import { Maximize, Diamond, Palette, Scissors, Type, AlignLeft, AlignCenter, AlignRight, Bold, Play, Image as ImageIcon, Wind, Sparkles, Activity, Sliders, Shield, Layers, Focus } from 'lucide-react';

interface PropertiesPanelProps {
  state: VideoState;
  onChangeTransform: (transform: VideoTransform) => void;
  onUpdateTransformProperty: (prop: keyof VideoTransform, value: number) => void;
  onChangeAdjustment: (adj: VideoAdjustment) => void;
  onToggleKeyframe: (prop: string) => void;
  onChangeChromaKey: (chroma: ChromaKey) => void;
  onUpdateText: (id: string, updates: Partial<TextBlock> | { style: Partial<TextBlock['style']> }) => void;
  onUpdateClip: (id: string, updates: Partial<VideoClip>) => void;
}

const PropertiesPanel: React.FC<PropertiesPanelProps> = ({ 
  state, 
  onUpdateTransformProperty, 
  onChangeAdjustment, 
  onToggleKeyframe, 
  onChangeChromaKey,
  onUpdateText,
  onUpdateClip
}) => {

  const selectedText = state.textTrack.find(t => t.id === state.selectedTextId);
  const selectedClip = state.videoClips.find(c => c.id === state.selectedClipId);

  const Section = ({ icon: Icon, title, children }: { icon: any, title: string, children?: React.ReactNode }) => (
      <div className="space-y-4">
          <h3 className="text-[9px] font-black text-slate-600 uppercase tracking-[0.3em] flex items-center gap-2">
              <Icon className="w-3 h-3" /> {title}
          </h3>
          <div className="space-y-4 bg-black p-3 rounded border border-[#1a1a1a]">
              {children}
          </div>
      </div>
  );

  const handleAdjustmentChange = (prop: keyof VideoAdjustment, value: number) => {
    if (selectedClip) {
      // Update per-clip adjustment
      const currentAdj = selectedClip.adjustment || state.adjustment;
      onUpdateClip(selectedClip.id, {
        adjustment: { ...currentAdj, [prop]: value }
      });
    } else {
      // Update global adjustment
      onChangeAdjustment({
        ...state.adjustment,
        [prop]: value
      });
    }
  };

  const activeAdjustment = selectedClip?.adjustment || state.adjustment;

  return (
    <div className="h-full bg-black flex flex-col custom-scrollbar overflow-y-auto">
        <div className="p-4 space-y-8 pb-20">

            {selectedText && (
                <>
                    <Section icon={Type} title="Typography">
                        <div className="space-y-4">
                            <div className="space-y-1">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Raw Text</label>
                                <textarea 
                                    value={selectedText.text}
                                    onChange={(e) => onUpdateText(selectedText.id, { text: e.target.value })}
                                    className="w-full bg-[#0a0a0a] border border-[#1a1a1a] rounded p-2 text-[10px] text-white h-16 resize-none focus:border-blue-500 outline-none transition-all"
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-1">
                                    <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Font Size</label>
                                    <input 
                                        type="number" 
                                        value={selectedText.style.fontSize} 
                                        onChange={(e) => onUpdateText(selectedText.id, { style: { fontSize: parseInt(e.target.value) } })}
                                        className="w-full bg-[#0a0a0a] border border-[#1a1a1a] rounded px-2 py-1 text-[10px] text-white"
                                    />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Color</label>
                                    <input 
                                        type="color" 
                                        value={selectedText.style.color} 
                                        onChange={(e) => onUpdateText(selectedText.id, { style: { color: e.target.value } })}
                                        className="w-full h-8 bg-transparent border-none cursor-pointer"
                                    />
                                </div>
                            </div>
                        </div>
                    </Section>

                    <Section icon={Layers} title="Neural Backdrop">
                        <div className="space-y-4">
                            <div className="space-y-2">
                                <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Shape Color</label>
                                <div className="flex items-center gap-2">
                                    <input 
                                        type="color" 
                                        value={selectedText.style.backgroundColor || '#000000'} 
                                        onChange={(e) => onUpdateText(selectedText.id, { style: { backgroundColor: e.target.value } })}
                                        className="w-8 h-8 bg-transparent border-none cursor-pointer"
                                    />
                                    <span className="text-[8px] font-mono text-slate-400 uppercase">{selectedText.style.backgroundColor || 'Transparent'}</span>
                                </div>
                            </div>

                            <div className="space-y-2">
                                <div className="flex justify-between items-center">
                                    <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Opacity</label>
                                    <span className="text-[9px] font-mono text-white">{Math.round((selectedText.style.backgroundOpacity ?? 0) * 100)}%</span>
                                </div>
                                <input 
                                    type="range" min="0" max="1" step="0.01"
                                    value={selectedText.style.backgroundOpacity ?? 0}
                                    onChange={(e) => onUpdateText(selectedText.id, { style: { backgroundOpacity: parseFloat(e.target.value) } })}
                                    className="w-full accent-blue-500"
                                />
                            </div>

                            <div className="space-y-2">
                                <div className="flex justify-between items-center">
                                    <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Padding</label>
                                    <span className="text-[9px] font-mono text-white">{selectedText.style.padding ?? 0}px</span>
                                </div>
                                <input 
                                    type="range" min="0" max="50" step="1"
                                    value={selectedText.style.padding ?? 0}
                                    onChange={(e) => onUpdateText(selectedText.id, { style: { padding: parseInt(e.target.value) } })}
                                    className="w-full accent-white"
                                />
                            </div>

                            <div className="space-y-2">
                                <div className="flex justify-between items-center">
                                    <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Border Radius</label>
                                    <span className="text-[9px] font-mono text-white">{selectedText.style.borderRadius ?? 0}px</span>
                                </div>
                                <input 
                                    type="range" min="0" max="100" step="1"
                                    value={selectedText.style.borderRadius ?? 0}
                                    onChange={(e) => onUpdateText(selectedText.id, { style: { borderRadius: parseInt(e.target.value) } })}
                                    className="w-full accent-white"
                                />
                            </div>
                        </div>
                    </Section>
                </>
            )}

            {selectedClip && (
              <>
                <Section icon={Sparkles} title="Neural Enhancement">
                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                            <span className="text-[9px] text-slate-400 uppercase tracking-widest font-bold">NUE Status</span>
                            {selectedClip.isEnhanced ? (
                                <span className="text-[7px] px-1.5 py-0.5 bg-cyan-500/20 text-cyan-400 rounded-sm font-black animate-pulse">OPTIMIZED</span>
                            ) : (
                                <span className="text-[7px] text-slate-600 uppercase font-black">RAW_SIGNAL</span>
                            )}
                        </div>

                        {!selectedClip.isEnhanced && (
                            <button 
                                onClick={() => {/* App handler would trigger AI for this */}}
                                className="w-full py-2 bg-blue-600 hover:bg-blue-500 text-white text-[8px] font-black uppercase rounded tracking-widest flex items-center justify-center gap-2 transition-all"
                            >
                                <Activity className="w-3 h-3" /> Initiate NUE Reconstruction
                            </button>
                        )}
                    </div>
                </Section>

                <Section icon={Shield} title="Inertial Dampening">
                  <div className="space-y-4">
                    <div className="flex items-center justify-between">
                        <span className="text-[9px] text-slate-400 uppercase tracking-widest font-bold">Stabilization</span>
                        {selectedClip.isStabilized ? (
                            <span className="text-[7px] px-1.5 py-0.5 bg-emerald-500/20 text-emerald-400 rounded-sm font-black">ACTIVE</span>
                        ) : (
                            <span className="text-[7px] text-slate-600 uppercase font-black">SHAKY_SIGNAL</span>
                        )}
                    </div>

                    {!selectedClip.isStabilized && (
                        <button 
                            className="w-full py-2 bg-[#1a1a1a] hover:bg-[#222] border border-[#333] text-white text-[8px] font-black uppercase rounded tracking-widest flex items-center justify-center gap-2 transition-all"
                        >
                            <Shield className="w-3 h-3" /> Fix Motion Jitter
                        </button>
                    )}
                  </div>
                </Section>
              </>
            )}

            <Section icon={Sliders} title={selectedClip ? "Clip Calibration" : "Neural Calibration"}>
                <div className="space-y-4">
                    <div className="space-y-2">
                        <div className="flex justify-between items-center">
                            <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Hue Shift</label>
                            <span className="text-[9px] font-mono text-white">{activeAdjustment.hue}°</span>
                        </div>
                        <input 
                            type="range" min="-180" max="180" step="1"
                            value={activeAdjustment.hue}
                            onChange={(e) => handleAdjustmentChange('hue', parseFloat(e.target.value))}
                            className="w-full accent-purple-500"
                        />
                    </div>
                    <div className="space-y-2">
                        <div className="flex justify-between items-center">
                            <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Luminance</label>
                            <span className="text-[9px] font-mono text-white">{activeAdjustment.brightness}%</span>
                        </div>
                        <input 
                            type="range" min="0" max="200" step="1"
                            value={activeAdjustment.brightness}
                            onChange={(e) => handleAdjustmentChange('brightness', parseFloat(e.target.value))}
                            className="w-full accent-white"
                        />
                    </div>
                    <div className="space-y-2">
                        <div className="flex justify-between items-center">
                            <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Contrast</label>
                            <span className="text-[9px] font-mono text-white">{activeAdjustment.contrast}%</span>
                        </div>
                        <input 
                            type="range" min="0" max="200" step="1"
                            value={activeAdjustment.contrast}
                            onChange={(e) => handleAdjustmentChange('contrast', parseFloat(e.target.value))}
                            className="w-full accent-white"
                        />
                    </div>
                    <div className="space-y-2">
                        <div className="flex justify-between items-center">
                            <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Saturation</label>
                            <span className="text-[9px] font-mono text-white">{activeAdjustment.saturation}%</span>
                        </div>
                        <input 
                            type="range" min="0" max="200" step="1"
                            value={activeAdjustment.saturation}
                            onChange={(e) => handleAdjustmentChange('saturation', parseFloat(e.target.value))}
                            className="w-full accent-white"
                        />
                    </div>
                </div>
            </Section>

            <Section icon={Focus} title="Neural Focus (Vignette)">
                <div className="space-y-4">
                    <div className="space-y-2">
                        <div className="flex justify-between items-center">
                            <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Intensity</label>
                            <span className="text-[9px] font-mono text-white">{activeAdjustment.vignetteIntensity}%</span>
                        </div>
                        <input 
                            type="range" min="0" max="100" step="1"
                            value={activeAdjustment.vignetteIntensity}
                            onChange={(e) => handleAdjustmentChange('vignetteIntensity', parseFloat(e.target.value))}
                            className="w-full accent-slate-400"
                        />
                    </div>
                    <div className="space-y-2">
                        <div className="flex justify-between items-center">
                            <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Softness (Size)</label>
                            <span className="text-[9px] font-mono text-white">{activeAdjustment.vignetteSize}%</span>
                        </div>
                        <input 
                            type="range" min="0" max="100" step="1"
                            value={activeAdjustment.vignetteSize}
                            onChange={(e) => handleAdjustmentChange('vignetteSize', parseFloat(e.target.value))}
                            className="w-full accent-slate-400"
                        />
                    </div>
                </div>
            </Section>

            <Section icon={Scissors} title="Extraction (Chroma)">
                <div className="space-y-4">
                    <div className="flex items-center justify-between">
                        <span className="text-[9px] text-slate-400 uppercase tracking-widest font-bold">Neural Keying</span>
                        <input type="checkbox" checked={state.chromaKey.enabled} onChange={(e) => onChangeChromaKey({ ...state.chromaKey, enabled: e.target.checked })} className="accent-blue-500 w-3 h-3 cursor-pointer" />
                    </div>
                    {state.chromaKey.enabled && (
                        <div className="space-y-2">
                            <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">Target Color</label>
                            <input type="color" value={state.chromaKey.color} onChange={(e) => onChangeChromaKey({ ...state.chromaKey, color: e.target.value })} className="w-full h-8 rounded border-none bg-transparent cursor-pointer" />
                        </div>
                    )}
                </div>
            </Section>

            <Section icon={Maximize} title="Spatial Controls">
                {[
                    { label: 'Scale', prop: 'scale', min: 0.1, max: 2, step: 0.01 },
                    { label: 'Rotate', prop: 'rotation', min: -180, max: 180, step: 1 },
                ].map(item => (
                    <div key={item.prop} className="space-y-1.5">
                        <div className="flex justify-between items-center">
                            <label className="text-[7px] text-slate-500 uppercase font-mono tracking-widest">{item.label}</label>
                            <span className="text-[9px] font-mono text-white">{(state.transform[item.prop as keyof VideoTransform] as number).toFixed(2)}</span>
                        </div>
                        <input type="range" min={item.min} max={item.max} step={item.step} value={state.transform[item.prop as keyof VideoTransform] as number} onChange={(e) => onUpdateTransformProperty(item.prop as keyof VideoTransform, parseFloat(e.target.value))} className="w-full" />
                    </div>
                ))}
            </Section>
        </div>
    </div>
  );
};

